def _scan_factor_is_missing(value) -> bool:
    if value is None:
        return True
    if isinstance(value, (list, tuple, set, dict)):
        return len(value) == 0
    if isinstance(value, str):
        return value.strip().lower() in {"", "nan", "none", "nat", "null"}
    try:
        missing = pd.isna(value)
    except (TypeError, ValueError):
        return False
    if isinstance(missing, (list, tuple)):
        return False
    try:
        return bool(missing)
    except (TypeError, ValueError):
        return False


def _scan_factor_text(value) -> str:
    if _scan_factor_is_missing(value):
        return ""
    if isinstance(value, bool):
        return "true" if value else "false"
    text = str(value).strip()
    return "" if text.lower() in {"nan", "none", "nat", "null"} else text


def _scan_factor_bool(value) -> bool | None:
    if _scan_factor_is_missing(value):
        return None
    if isinstance(value, bool):
        return value
    if isinstance(value, (int, float)) and not isinstance(value, bool):
        try:
            return float(value) != 0.0
        except (TypeError, ValueError):
            return None
    text = str(value).strip().lower()
    if text in {"true", "t", "yes", "y", "1"}:
        return True
    if text in {"false", "f", "no", "n", "0"}:
        return False
    return None


def _scan_factor_number(value) -> float | None:
    if _scan_factor_is_missing(value):
        return None
    return _coerce_float(value)


def _format_scan_factor_boundary(value: float) -> str:
    numeric = float(value)
    if numeric.is_integer():
        return str(int(numeric))
    return f"{numeric:g}"


def _scan_factor_numeric_bucket(value, boundaries: tuple[float, ...]) -> str:
    numeric = _scan_factor_number(value)
    if numeric is None:
        return ""
    sorted_boundaries = [float(item) for item in boundaries]
    previous = None
    for boundary in sorted_boundaries:
        if numeric < boundary:
            if previous is None:
                return f"< {_format_scan_factor_boundary(boundary)}"
            return f"{_format_scan_factor_boundary(previous)} to < {_format_scan_factor_boundary(boundary)}"
        previous = boundary
    if previous is None:
        return ""
    return f">= {_format_scan_factor_boundary(previous)}"


def _scan_factor_list_values(value) -> list[str]:
    if _scan_factor_is_missing(value):
        return []
    parsed = value
    if isinstance(value, str):
        text = value.strip()
        if text.startswith("[") and text.endswith("]"):
            try:
                parsed = ast.literal_eval(text)
            except (SyntaxError, ValueError):
                parsed = text
        if isinstance(parsed, str):
            separator = ";" if ";" in parsed else ","
            parts = parsed.split(separator) if separator in parsed else [parsed]
        else:
            parts = list(parsed) if isinstance(parsed, (list, tuple, set)) else [parsed]
    elif isinstance(value, (list, tuple, set)):
        parts = list(value)
    else:
        parts = [value]

    normalized = []
    for part in parts:
        text = _scan_factor_text(part)
        if text:
            normalized.append(text)
    return sorted(set(normalized))


def _scan_factor_items_from_row(row: dict) -> list[dict]:
    if not isinstance(row, dict):
        return []
    factors = []
    seen = set()

    def add(key: str, group: str, label: str, kind: str, value_label: str) -> None:
        value_text = _scan_factor_text(value_label)
        if not value_text:
            return
        dedupe_key = (key, value_text)
        if dedupe_key in seen:
            return
        seen.add(dedupe_key)
        factors.append(
            {
                "factor_key": key,
                "factor_group": group,
                "factor_label": label,
                "value_kind": kind,
                "value_label": value_text,
            }
        )

    for key, (group, label) in SCAN_FACTOR_CATEGORICAL_FIELDS.items():
        add(key, group, label, "category", row.get(key))

    for key, (group, label) in SCAN_FACTOR_BOOL_FIELDS.items():
        value = _scan_factor_bool(row.get(key))
        if value is not None:
            add(key, group, label, "bool", "true" if value else "false")

    for key, (group, label) in SCAN_FACTOR_LIST_FIELDS.items():
        for value in _scan_factor_list_values(row.get(key)):
            add(key, group, label, "list_item", value)

    for key, (group, label, boundaries) in SCAN_FACTOR_NUMERIC_FIELDS.items():
        bucket = _scan_factor_numeric_bucket(row.get(key), boundaries)
        if bucket:
            add(key, group, label, "number_bucket", bucket)

    return factors


def _scan_factor_mean(values) -> float | None:
    numeric_values = [
        float(value)
        for value in values
        if _scan_factor_number(value) is not None
    ]
    return mean(numeric_values) if numeric_values else None


def _scan_factor_median(values) -> float | None:
    numeric_values = [
        float(value)
        for value in values
        if _scan_factor_number(value) is not None
    ]
    return median(numeric_values) if numeric_values else None


def _scan_factor_win_rate(values) -> float | None:
    bool_values = [
        1.0 if value else 0.0
        for value in (_scan_factor_bool(item) for item in values)
        if value is not None
    ]
    return mean(bool_values) if bool_values else None


def _scan_factor_row_id(row: pd.Series | dict) -> str:
    getter = row.get if hasattr(row, "get") else lambda key, default=None: default
    symbol = str(getter("_symbol", getter("symbol", "")) or "").strip().upper()
    scan_date = str(getter("_scan_date_text", getter("last_trade_date", "")) or "").strip()
    run_id = str(getter("_run_id_text", getter("run_id", "")) or "").strip()
    run_timestamp = str(getter("_run_timestamp_text", getter("run_timestamp", "")) or "").strip()
    suffix = run_id or run_timestamp
    return f"{symbol}:{scan_date}:{suffix}".rstrip(":")


def _prepare_scan_factor_history_frame(history_df: pd.DataFrame | None) -> pd.DataFrame:
    if history_df is None or not isinstance(history_df, pd.DataFrame) or history_df.empty:
        return pd.DataFrame()
    required_columns = {"symbol", "last_close"}
    if not required_columns.issubset(set(history_df.columns)):
        return pd.DataFrame()
    if "last_trade_date" not in history_df.columns and "run_date" not in history_df.columns:
        return pd.DataFrame()

    frame = history_df.copy()
    frame["_input_order"] = range(len(frame))
    frame["_symbol"] = frame["symbol"].apply(lambda value: _scan_factor_text(value).upper())
    date_source = frame["last_trade_date"] if "last_trade_date" in frame.columns else frame["run_date"]
    frame["_scan_date_dt"] = pd.to_datetime(date_source, errors="coerce")
    frame["_scan_date_text"] = frame["_scan_date_dt"].dt.strftime("%Y-%m-%d")
    frame["_entry_close"] = pd.to_numeric(frame["last_close"], errors="coerce")
    if "side" in frame.columns:
        frame["_side"] = frame["side"].apply(normalize_side)
    else:
        frame["_side"] = "LONG"
    frame["_run_id_text"] = frame["run_id"].fillna("").astype(str) if "run_id" in frame.columns else ""
    frame["_run_timestamp_text"] = (
        frame["run_timestamp"].fillna("").astype(str)
        if "run_timestamp" in frame.columns
        else ""
    )

    frame = frame[
        (frame["_symbol"] != "")
        & frame["_scan_date_dt"].notna()
        & frame["_entry_close"].notna()
        & (frame["_entry_close"] > 0)
    ].copy()
    if frame.empty:
        return frame
    frame.sort_values(
        ["_symbol", "_scan_date_dt", "_run_timestamp_text", "_run_id_text", "_input_order"],
        inplace=True,
    )
    frame.drop_duplicates(["_symbol", "_scan_date_text"], keep="last", inplace=True)
    frame["_scan_row_id"] = frame.apply(_scan_factor_row_id, axis=1)
    return frame


def build_scan_factor_observation_rows(
    history_df: pd.DataFrame | None,
    *,
    horizons: tuple[int, ...] = SCAN_FACTOR_HORIZONS,
) -> list[dict]:
    frame = _prepare_scan_factor_history_frame(history_df)
    if frame.empty:
        return []

    benchmark_closes: dict[str, float] = {}
    spy_rows = frame[frame["_symbol"] == "SPY"].sort_values("_scan_date_dt")
    for _, spy_row in spy_rows.iterrows():
        close_value = _scan_factor_number(spy_row.get("_entry_close"))
        if close_value is not None and close_value > 0:
            benchmark_closes[str(spy_row.get("_scan_date_text") or "")] = float(close_value)

    normalized_horizons = tuple(sorted({int(horizon) for horizon in horizons if int(horizon) > 0}))
    rows = []
    for symbol, symbol_frame in frame.groupby("_symbol", sort=True):
        symbol_frame = symbol_frame.sort_values("_scan_date_dt").reset_index(drop=True)
        records = symbol_frame.to_dict("records")
        for idx, entry in enumerate(records):
            entry_close = _scan_factor_number(entry.get("_entry_close"))
            if entry_close is None or entry_close <= 0:
                continue
            side = normalize_side(entry.get("_side") or entry.get("side") or "")
            side_multiplier = -1.0 if side == "SHORT" else 1.0
            for horizon in normalized_horizons:
                future_idx = idx + horizon
                if future_idx >= len(records):
                    continue
                future = records[future_idx]
                future_close = _scan_factor_number(future.get("_entry_close"))
                if future_close is None or future_close <= 0:
                    continue
                raw_return_pct = ((float(future_close) / float(entry_close)) - 1.0) * 100.0
                side_return_pct = raw_return_pct * side_multiplier
                scan_date = str(entry.get("_scan_date_text") or "")
                future_scan_date = str(future.get("_scan_date_text") or "")
                spy_forward_return_pct = None
                spy_relative_side_return_pct = None
                spy_entry_close = benchmark_closes.get(scan_date)
                spy_future_close = benchmark_closes.get(future_scan_date)
                if spy_entry_close and spy_entry_close > 0 and spy_future_close and spy_future_close > 0:
                    spy_forward_return_pct = ((float(spy_future_close) / float(spy_entry_close)) - 1.0) * 100.0
                    spy_relative_side_return_pct = side_multiplier * (raw_return_pct - spy_forward_return_pct)

                scan_row_id = str(entry.get("_scan_row_id") or _scan_factor_row_id(entry))
                rows.append(
                    {
                        "observation_id": f"{scan_row_id}:{horizon}",
                        "scan_row_id": scan_row_id,
                        "run_id": _scan_factor_text(entry.get("run_id")),
                        "run_timestamp": _scan_factor_text(entry.get("run_timestamp")),
                        "run_date": _scan_factor_text(entry.get("run_date")) or scan_date,
                        "watchlist_label": _scan_factor_text(entry.get("watchlist_label")),
                        "symbol": symbol,
                        "side": side,
                        "scan_date": scan_date,
                        "entry_close": float(entry_close),
                        "future_scan_date": future_scan_date,
                        "future_close": float(future_close),
                        "horizon_sessions": int(horizon),
                        "raw_return_pct": raw_return_pct,
                        "side_return_pct": side_return_pct,
                        "win": side_return_pct > 0,
                        "spy_forward_return_pct": spy_forward_return_pct,
                        "spy_relative_side_return_pct": spy_relative_side_return_pct,
                    }
                )

    rows.sort(
        key=lambda item: (
            str(item.get("scan_date") or ""),
            str(item.get("symbol") or ""),
            int(item.get("horizon_sessions", 0) or 0),
        )
    )
    return rows


def _scan_factor_baseline_summary(obs_df: pd.DataFrame) -> dict:
    side_values = pd.to_numeric(obs_df.get("side_return_pct"), errors="coerce").dropna()
    spy_relative_values = pd.to_numeric(obs_df.get("spy_relative_side_return_pct"), errors="coerce").dropna()
    return {
        "observation_count": int(obs_df["observation_id"].nunique()) if "observation_id" in obs_df.columns else len(obs_df),
        "win_rate": _scan_factor_win_rate(obs_df.get("win", [])),
        "avg_side_return_pct": float(side_values.mean()) if not side_values.empty else None,
        "avg_spy_relative_side_return_pct": (
            float(spy_relative_values.mean()) if not spy_relative_values.empty else None
        ),
    }


def build_scan_factor_leaderboard_rows(
    history_df: pd.DataFrame | None,
    observation_rows: list[dict] | None = None,
    *,
    lookback_days: int = SCAN_FACTOR_LOOKBACK_DAYS,
    min_observations: int = SCAN_FACTOR_MIN_OBSERVATIONS,
    reference_date: date | datetime | str | None = None,
) -> list[dict]:
    observations = observation_rows if observation_rows is not None else build_scan_factor_observation_rows(history_df)
    if not observations:
        return []
    frame = _prepare_scan_factor_history_frame(history_df)
    if frame.empty:
        return []

    obs_df = pd.DataFrame(observations)
    if obs_df.empty or "scan_row_id" not in obs_df.columns:
        return []
    obs_df["_scan_date_dt"] = pd.to_datetime(obs_df["scan_date"], errors="coerce")
    obs_df = obs_df[obs_df["_scan_date_dt"].notna()].copy()
    if obs_df.empty:
        return []

    if reference_date is None:
        window_end_ts = obs_df["_scan_date_dt"].max()
    else:
        window_end_ts = pd.to_datetime(reference_date, errors="coerce")
        if pd.isna(window_end_ts):
            window_end_ts = obs_df["_scan_date_dt"].max()
    lookback_days = max(1, int(lookback_days or SCAN_FACTOR_LOOKBACK_DAYS))
    window_start_ts = window_end_ts - pd.Timedelta(days=lookback_days)
    recent_obs = obs_df[
        (obs_df["_scan_date_dt"] >= window_start_ts)
        & (obs_df["_scan_date_dt"] <= window_end_ts)
    ].copy()
    if recent_obs.empty:
        return []

    source_rows = {
        str(row.get("_scan_row_id") or ""): row
        for row in frame.to_dict("records")
        if str(row.get("_scan_row_id") or "")
    }
    baseline_map = {
        (int(group_key[0]), str(group_key[1])): _scan_factor_baseline_summary(group_df)
        for group_key, group_df in recent_obs.groupby(["horizon_sessions", "side"], dropna=False)
    }

    factor_observations = []
    for obs in recent_obs.to_dict("records"):
        source_row = source_rows.get(str(obs.get("scan_row_id") or ""))
        if not source_row:
            continue
        for factor in _scan_factor_items_from_row(source_row):
            merged = dict(obs)
            merged.update(factor)
            factor_observations.append(merged)
    if not factor_observations:
        return []

    factor_df = pd.DataFrame(factor_observations)
    generated_at = datetime.now().isoformat(timespec="seconds")
    window_start = window_start_ts.strftime("%Y-%m-%d")
    window_end = window_end_ts.strftime("%Y-%m-%d")
    rows = []
    group_cols = [
        "horizon_sessions",
        "side",
        "factor_key",
        "factor_group",
        "factor_label",
        "value_kind",
        "value_label",
    ]
    for group_key, group_df in factor_df.groupby(group_cols, dropna=False):
        unique_df = group_df.drop_duplicates(subset=["observation_id"])
        observation_count = int(unique_df["observation_id"].nunique())
        if observation_count < int(min_observations or 1):
            continue
        side_values = pd.to_numeric(unique_df["side_return_pct"], errors="coerce").dropna()
        raw_values = pd.to_numeric(unique_df["raw_return_pct"], errors="coerce").dropna()
        spy_relative_values = pd.to_numeric(unique_df["spy_relative_side_return_pct"], errors="coerce").dropna()
        avg_side_return_pct = float(side_values.mean()) if not side_values.empty else None
        median_side_return_pct = float(side_values.median()) if not side_values.empty else None
        avg_raw_return_pct = float(raw_values.mean()) if not raw_values.empty else None
        avg_spy_relative_side_return_pct = (
            float(spy_relative_values.mean()) if not spy_relative_values.empty else None
        )
        win_rate = _scan_factor_win_rate(unique_df.get("win", []))
        baseline = baseline_map.get((int(group_key[0]), str(group_key[1])), {})
        baseline_avg_side_return_pct = _scan_factor_number(baseline.get("avg_side_return_pct"))
        baseline_avg_spy_relative_side_return_pct = _scan_factor_number(
            baseline.get("avg_spy_relative_side_return_pct")
        )
        baseline_win_rate = _scan_factor_number(baseline.get("win_rate"))
        side_return_edge_pct = (
            avg_side_return_pct - baseline_avg_side_return_pct
            if avg_side_return_pct is not None and baseline_avg_side_return_pct is not None
            else None
        )
        win_rate_edge = (
            win_rate - baseline_win_rate
            if win_rate is not None and baseline_win_rate is not None
            else None
        )
        spy_relative_edge_pct = (
            avg_spy_relative_side_return_pct - baseline_avg_spy_relative_side_return_pct
            if avg_spy_relative_side_return_pct is not None
            and baseline_avg_spy_relative_side_return_pct is not None
            else None
        )
        success_score = (side_return_edge_pct or 0.0) + ((win_rate_edge or 0.0) * 10.0)
        impact_score = (
            abs(side_return_edge_pct or 0.0)
            + abs((win_rate_edge or 0.0) * 10.0)
            + abs(spy_relative_edge_pct or 0.0)
        ) * math.log1p(max(1, observation_count))

        sample_rows = unique_df.to_dict("records")
        sample_rows.sort(
            key=lambda item: (
                str(item.get("scan_date") or ""),
                _scan_factor_number(item.get("side_return_pct")) or -9999.0,
                str(item.get("symbol") or ""),
            ),
            reverse=True,
        )
        samples = []
        for item in sample_rows:
            side_return = _scan_factor_number(item.get("side_return_pct"))
            sample = f"{item.get('symbol')} {item.get('scan_date')}->{item.get('future_scan_date')}"
            if side_return is not None:
                sample += f" ({side_return:+.2f}%)"
            samples.append(sample)
            if len(samples) >= 8:
                break

        rows.append(
            {
                "generated_at": generated_at,
                "lookback_days": lookback_days,
                "window_start": window_start,
                "window_end": window_end,
                "horizon_sessions": int(group_key[0]),
                "side": str(group_key[1]),
                "factor_key": str(group_key[2]),
                "factor_group": str(group_key[3]),
                "factor_label": str(group_key[4]),
                "value_kind": str(group_key[5]),
                "value_label": str(group_key[6]),
                "observation_count": observation_count,
                "symbol_count": int(unique_df["symbol"].nunique()),
                "win_rate": win_rate,
                "avg_side_return_pct": avg_side_return_pct,
                "median_side_return_pct": median_side_return_pct,
                "avg_raw_return_pct": avg_raw_return_pct,
                "avg_spy_relative_side_return_pct": avg_spy_relative_side_return_pct,
                "baseline_observation_count": int(baseline.get("observation_count", 0) or 0),
                "baseline_win_rate": baseline_win_rate,
                "baseline_avg_side_return_pct": baseline_avg_side_return_pct,
                "baseline_avg_spy_relative_side_return_pct": baseline_avg_spy_relative_side_return_pct,
                "side_return_edge_pct": side_return_edge_pct,
                "win_rate_edge": win_rate_edge,
                "spy_relative_edge_pct": spy_relative_edge_pct,
                "success_score": success_score,
                "impact_score": impact_score,
                "sample_observations": "; ".join(samples),
            }
        )

    rows.sort(
        key=lambda item: (
            -(_scan_factor_number(item.get("success_score")) or 0.0),
            -(_scan_factor_number(item.get("impact_score")) or 0.0),
            -int(item.get("observation_count", 0) or 0),
            int(item.get("horizon_sessions", 0) or 0),
            str(item.get("factor_label") or ""),
            str(item.get("value_label") or ""),
        )
    )
    return rows


def _write_scan_factor_csv(path: Path, rows: list[dict], columns: list[str]) -> None:
    path.parent.mkdir(parents=True, exist_ok=True)
    pd.DataFrame(rows, columns=columns).to_csv(path, index=False)


def export_scan_factor_views(
    history_path: Path | None = None,
    observations_path: Path | None = None,
    leaderboard_path: Path | None = None,
    *,
    lookback_days: int = SCAN_FACTOR_LOOKBACK_DAYS,
    min_observations: int = SCAN_FACTOR_MIN_OBSERVATIONS,
) -> dict:
    history_path = Path(history_path or D1_FEATURE_HISTORY_FILE)
    observations_path = Path(observations_path or SCAN_FACTOR_OBSERVATIONS_FILE)
    leaderboard_path = Path(leaderboard_path or SCAN_FACTOR_LEADERBOARD_FILE)

    if not history_path.exists() or history_path.stat().st_size == 0:
        _write_scan_factor_csv(observations_path, [], SCAN_FACTOR_OBSERVATION_COLUMNS)
        _write_scan_factor_csv(leaderboard_path, [], SCAN_FACTOR_LEADERBOARD_COLUMNS)
        return {"observation_count": 0, "leaderboard_count": 0}

    history_df = pd.read_csv(history_path, low_memory=False)
    observation_rows = build_scan_factor_observation_rows(history_df)
    leaderboard_rows = build_scan_factor_leaderboard_rows(
        history_df,
        observation_rows,
        lookback_days=lookback_days,
        min_observations=min_observations,
    )
    _write_scan_factor_csv(observations_path, observation_rows, SCAN_FACTOR_OBSERVATION_COLUMNS)
    _write_scan_factor_csv(leaderboard_path, leaderboard_rows, SCAN_FACTOR_LEADERBOARD_COLUMNS)
    return {
        "observation_count": len(observation_rows),
        "leaderboard_count": len(leaderboard_rows),
        "observations_path": str(observations_path),
        "leaderboard_path": str(leaderboard_path),
    }


def load_scan_factor_leaderboard_rows(path: Path | None = None) -> list[dict]:
    path = Path(path or SCAN_FACTOR_LEADERBOARD_FILE)
    if not path.exists() or path.stat().st_size == 0:
        return []
    try:
        frame = pd.read_csv(path, low_memory=False)
    except Exception:
        logging.exception("Failed to load scan factor leaderboard from %s", path)
        return []
    if frame.empty:
        return []
    frame = frame.where(pd.notna(frame), None)
    return frame.to_dict("records")


def _tier_for_priority_bucket(priority_bucket: str | None) -> str:
    bucket = str(priority_bucket or "").strip().lower()
    if bucket == "favorite_setup":
        return "S"
    if bucket == "near_favorite_zone":
        return "A"
    return ""


def _tier_rank_value(tier: str | None) -> int:
    return {"S": 0, "A": 1, "S/A": 2}.get(str(tier or "").strip().upper(), 9)


def _positive_scan_factor_groups(
    leaderboard_rows: list[dict] | None,
    *,
    top_per_side_horizon: int = TIER_CATCH_TOP_SCAN_FACTORS_PER_SIDE_HORIZON,
) -> dict[tuple[int, str], list[dict]]:
    grouped: dict[tuple[int, str], list[dict]] = {}
    for row in leaderboard_rows or []:
        if not isinstance(row, dict):
            continue
        success_score = _scan_factor_number(row.get("success_score"))
        if success_score is None or success_score <= 0:
            continue
        horizon = int(row.get("horizon_sessions", 0) or 0)
        side = normalize_side(row.get("side"))
        factor_key = str(row.get("factor_key") or "").strip()
        value_label = str(row.get("value_label") or "").strip()
        if horizon <= 0 or not factor_key or not value_label:
            continue
        grouped.setdefault((horizon, side), []).append(row)

    limited: dict[tuple[int, str], list[dict]] = {}
    for key, rows in grouped.items():
        ranked = sorted(
            rows,
            key=lambda item: (
                -(_scan_factor_number(item.get("success_score")) or 0.0),
                -(_scan_factor_number(item.get("impact_score")) or 0.0),
                -int(item.get("observation_count", 0) or 0),
                str(item.get("factor_label") or ""),
                str(item.get("value_label") or ""),
            ),
        )
        limited[key] = ranked[: max(1, int(top_per_side_horizon or 1))]
    return limited


def _positive_scan_factor_matches_for_source_row(
    source_row: dict,
    *,
    horizon: int | None = None,
    side: str | None = None,
    positive_factor_groups: dict[tuple[int, str], list[dict]] | None = None,
) -> list[dict]:
    groups = positive_factor_groups or {}
    if not groups or not isinstance(source_row, dict):
        return []

    factor_keys = {
        (str(item.get("factor_key") or ""), str(item.get("value_label") or ""))
        for item in _scan_factor_items_from_row(source_row)
    }
    if not factor_keys:
        return []

    normalized_side = normalize_side(side or source_row.get("_side") or source_row.get("side"))
    horizons = [int(horizon)] if horizon else sorted({key[0] for key in groups.keys()})
    matches = []
    seen = set()
    for horizon_value in horizons:
        for row in groups.get((int(horizon_value), normalized_side), []):
            match_key = (str(row.get("factor_key") or ""), str(row.get("value_label") or ""))
            if match_key not in factor_keys:
                continue
            dedupe_key = (int(horizon_value), match_key[0], match_key[1])
            if dedupe_key in seen:
                continue
            seen.add(dedupe_key)
            matches.append(row)
    matches.sort(
        key=lambda item: (
            int(item.get("horizon_sessions", 0) or 0),
            -(_scan_factor_number(item.get("success_score")) or 0.0),
            str(item.get("factor_label") or ""),
        )
    )
    return matches


def _format_positive_scan_factor_matches(matches: list[dict], *, limit: int = 8) -> str:
    labels = []
    for row in matches[: max(1, int(limit or 1))]:
        success_score = _scan_factor_number(row.get("success_score"))
        score_text = f" {success_score:+.2f}" if success_score is not None else ""
        labels.append(
            f"{int(row.get('horizon_sessions', 0) or 0)}d "
            f"{row.get('factor_label')}={row.get('value_label')}{score_text}"
        )
    if len(matches) > len(labels):
        labels.append(f"+{len(matches) - len(labels)} more")
    return "; ".join(labels)


def build_bot_tier_pick_rows(
    history_df: pd.DataFrame | None,
    leaderboard_rows: list[dict] | None = None,
) -> list[dict]:
    frame = _prepare_scan_factor_history_frame(history_df)
    if frame.empty:
        return []
    latest_scan_date = frame["_scan_date_dt"].max()
    latest_frame = frame[frame["_scan_date_dt"] == latest_scan_date].copy()
    positive_factor_groups = _positive_scan_factor_groups(leaderboard_rows)
    generated_at = datetime.now().isoformat(timespec="seconds")
    rows = []
    for source_row in latest_frame.to_dict("records"):
        tier = _tier_for_priority_bucket(source_row.get("priority_bucket"))
        if not tier:
            continue
        matches = _positive_scan_factor_matches_for_source_row(
            source_row,
            positive_factor_groups=positive_factor_groups,
        )
        rows.append(
            {
                "generated_at": generated_at,
                "run_date": _scan_factor_text(source_row.get("run_date")) or source_row.get("_scan_date_text"),
                "scan_date": source_row.get("_scan_date_text"),
                "scan_row_id": source_row.get("_scan_row_id"),
                "tier": tier,
                "symbol": source_row.get("_symbol"),
                "side": normalize_side(source_row.get("_side") or source_row.get("side")),
                "priority_bucket": _scan_factor_text(source_row.get("priority_bucket")),
                "priority_score": _scan_factor_number(source_row.get("priority_score")),
                "setup_family": _scan_factor_text(source_row.get("setup_family")),
                "favorite_zone": _scan_factor_text(source_row.get("favorite_zone")),
                "current_band_zone": _scan_factor_text(source_row.get("current_band_zone")),
                "trend_20d": _scan_factor_text(source_row.get("trend_20d")),
                "last_close": _scan_factor_number(source_row.get("_entry_close")),
                "scan_factor_match_count": len(matches),
                "scan_factor_matches": _format_positive_scan_factor_matches(matches),
            }
        )

    rows.sort(
        key=lambda item: (
            _tier_rank_value(item.get("tier")),
            -(_scan_factor_number(item.get("priority_score")) or 0.0),
            str(item.get("symbol") or ""),
        )
    )
    return rows


def build_bot_tier_outcome_rows(
    history_df: pd.DataFrame | None,
    observation_rows: list[dict] | None = None,
    leaderboard_rows: list[dict] | None = None,
) -> list[dict]:
    frame = _prepare_scan_factor_history_frame(history_df)
    if frame.empty:
        return []
    observations = observation_rows if observation_rows is not None else build_scan_factor_observation_rows(history_df)
    if not observations:
        return []
    source_rows = {
        str(row.get("_scan_row_id") or ""): row
        for row in frame.to_dict("records")
        if str(row.get("_scan_row_id") or "")
    }
    positive_factor_groups = _positive_scan_factor_groups(leaderboard_rows)
    rows = []
    for obs in observations:
        if not isinstance(obs, dict):
            continue
        source_row = source_rows.get(str(obs.get("scan_row_id") or ""))
        if not source_row:
            continue
        tier = _tier_for_priority_bucket(source_row.get("priority_bucket"))
        if not tier:
            continue
        horizon = int(obs.get("horizon_sessions", 0) or 0)
        side = normalize_side(obs.get("side"))
        matches = _positive_scan_factor_matches_for_source_row(
            source_row,
            horizon=horizon,
            side=side,
            positive_factor_groups=positive_factor_groups,
        )
        rows.append(
            {
                "observation_id": obs.get("observation_id"),
                "scan_row_id": obs.get("scan_row_id"),
                "run_id": obs.get("run_id"),
                "run_timestamp": obs.get("run_timestamp"),
                "run_date": obs.get("run_date"),
                "watchlist_label": obs.get("watchlist_label"),
                "scan_date": obs.get("scan_date"),
                "future_scan_date": obs.get("future_scan_date"),
                "horizon_sessions": horizon,
                "tier": tier,
                "symbol": obs.get("symbol"),
                "side": side,
                "priority_bucket": _scan_factor_text(source_row.get("priority_bucket")),
                "priority_score": _scan_factor_number(source_row.get("priority_score")),
                "setup_family": _scan_factor_text(source_row.get("setup_family")),
                "favorite_zone": _scan_factor_text(source_row.get("favorite_zone")),
                "entry_close": obs.get("entry_close"),
                "future_close": obs.get("future_close"),
                "raw_return_pct": obs.get("raw_return_pct"),
                "side_return_pct": obs.get("side_return_pct"),
                "win": bool(obs.get("win")),
                "spy_forward_return_pct": obs.get("spy_forward_return_pct"),
                "spy_relative_side_return_pct": obs.get("spy_relative_side_return_pct"),
                "positive_scan_factor_match_count": len(matches),
                "positive_scan_factor_matches": _format_positive_scan_factor_matches(matches),
            }
        )

    rows.sort(
        key=lambda item: (
            str(item.get("scan_date") or ""),
            _tier_rank_value(item.get("tier")),
            str(item.get("symbol") or ""),
            int(item.get("horizon_sessions", 0) or 0),
        )
    )
    return rows


def _tier_performance_summary_row(
    group_df: pd.DataFrame,
    baseline_df: pd.DataFrame,
    *,
    generated_at: str,
    lookback_days: int,
    window_start: str,
    window_end: str,
    horizon,
    tier: str,
    side: str,
) -> dict:
    side_values = pd.to_numeric(group_df.get("side_return_pct"), errors="coerce").dropna()
    spy_relative_values = pd.to_numeric(group_df.get("spy_relative_side_return_pct"), errors="coerce").dropna()
    baseline_side_values = pd.to_numeric(baseline_df.get("side_return_pct"), errors="coerce").dropna()
    baseline_spy_values = pd.to_numeric(baseline_df.get("spy_relative_side_return_pct"), errors="coerce").dropna()
    win_rate = _scan_factor_win_rate(group_df.get("win", []))
    baseline_win_rate = _scan_factor_win_rate(baseline_df.get("win", []))
    avg_side_return_pct = float(side_values.mean()) if not side_values.empty else None
    baseline_avg_side_return_pct = float(baseline_side_values.mean()) if not baseline_side_values.empty else None
    avg_spy_relative_side_return_pct = (
        float(spy_relative_values.mean()) if not spy_relative_values.empty else None
    )
    baseline_avg_spy_relative_side_return_pct = (
        float(baseline_spy_values.mean()) if not baseline_spy_values.empty else None
    )
    match_counts = pd.to_numeric(group_df.get("positive_scan_factor_match_count"), errors="coerce").fillna(0)
    sample_rows = group_df.to_dict("records")
    sample_rows.sort(
        key=lambda item: (
            str(item.get("scan_date") or ""),
            _scan_factor_number(item.get("side_return_pct")) or -9999.0,
            str(item.get("symbol") or ""),
        ),
        reverse=True,
    )
    samples = []
    for item in sample_rows[:8]:
        side_return = _scan_factor_number(item.get("side_return_pct"))
        sample = f"{item.get('symbol')} {item.get('scan_date')}->{item.get('future_scan_date')}"
        if side_return is not None:
            sample += f" ({side_return:+.2f}%)"
        samples.append(sample)
    return {
        "generated_at": generated_at,
        "lookback_days": lookback_days,
        "window_start": window_start,
        "window_end": window_end,
        "horizon_sessions": horizon,
        "tier": tier,
        "side": side,
        "observation_count": int(group_df["observation_id"].nunique()) if "observation_id" in group_df.columns else len(group_df),
        "symbol_count": int(group_df["symbol"].nunique()) if "symbol" in group_df.columns else 0,
        "win_rate": win_rate,
        "avg_side_return_pct": avg_side_return_pct,
        "median_side_return_pct": float(side_values.median()) if not side_values.empty else None,
        "avg_spy_relative_side_return_pct": avg_spy_relative_side_return_pct,
        "baseline_observation_count": int(baseline_df["observation_id"].nunique()) if "observation_id" in baseline_df.columns else len(baseline_df),
        "baseline_win_rate": baseline_win_rate,
        "baseline_avg_side_return_pct": baseline_avg_side_return_pct,
        "baseline_avg_spy_relative_side_return_pct": baseline_avg_spy_relative_side_return_pct,
        "side_return_edge_pct": (
            avg_side_return_pct - baseline_avg_side_return_pct
            if avg_side_return_pct is not None and baseline_avg_side_return_pct is not None
            else None
        ),
        "win_rate_edge": (
            win_rate - baseline_win_rate
            if win_rate is not None and baseline_win_rate is not None
            else None
        ),
        "spy_relative_edge_pct": (
            avg_spy_relative_side_return_pct - baseline_avg_spy_relative_side_return_pct
            if avg_spy_relative_side_return_pct is not None
            and baseline_avg_spy_relative_side_return_pct is not None
            else None
        ),
        "positive_scan_factor_match_rate": float((match_counts > 0).mean()) if len(match_counts) else None,
        "sample_observations": "; ".join(samples),
    }


def build_bot_tier_performance_rows(
    tier_outcome_rows: list[dict] | None,
    observation_rows: list[dict] | None,
    *,
    lookback_days: int = SCAN_FACTOR_LOOKBACK_DAYS,
    reference_date: date | datetime | str | None = None,
) -> list[dict]:
    if not tier_outcome_rows:
        return []
    tier_df = pd.DataFrame(tier_outcome_rows)
    all_obs_df = pd.DataFrame(observation_rows or [])
    if tier_df.empty or all_obs_df.empty:
        return []
    tier_df["_scan_date_dt"] = pd.to_datetime(tier_df["scan_date"], errors="coerce")
    all_obs_df["_scan_date_dt"] = pd.to_datetime(all_obs_df["scan_date"], errors="coerce")
    tier_df = tier_df[tier_df["_scan_date_dt"].notna()].copy()
    all_obs_df = all_obs_df[all_obs_df["_scan_date_dt"].notna()].copy()
    if tier_df.empty or all_obs_df.empty:
        return []
    if reference_date is None:
        window_end_ts = tier_df["_scan_date_dt"].max()
    else:
        window_end_ts = pd.to_datetime(reference_date, errors="coerce")
        if pd.isna(window_end_ts):
            window_end_ts = tier_df["_scan_date_dt"].max()
    lookback_days = max(1, int(lookback_days or SCAN_FACTOR_LOOKBACK_DAYS))
    window_start_ts = window_end_ts - pd.Timedelta(days=lookback_days)
    tier_recent = tier_df[
        (tier_df["_scan_date_dt"] >= window_start_ts)
        & (tier_df["_scan_date_dt"] <= window_end_ts)
    ].copy()
    obs_recent = all_obs_df[
        (all_obs_df["_scan_date_dt"] >= window_start_ts)
        & (all_obs_df["_scan_date_dt"] <= window_end_ts)
    ].copy()
    if tier_recent.empty or obs_recent.empty:
        return []

    generated_at = datetime.now().isoformat(timespec="seconds")
    window_start = window_start_ts.strftime("%Y-%m-%d")
    window_end = window_end_ts.strftime("%Y-%m-%d")
    rows = []

    def add_row(horizon, tier: str, side: str, group_df: pd.DataFrame) -> None:
        if group_df.empty:
            return
        baseline = obs_recent[obs_recent["horizon_sessions"] == horizon]
        if side != "ALL":
            baseline = baseline[baseline["side"].apply(normalize_side) == side]
        if baseline.empty:
            return
        rows.append(
            _tier_performance_summary_row(
                group_df,
                baseline,
                generated_at=generated_at,
                lookback_days=lookback_days,
                window_start=window_start,
                window_end=window_end,
                horizon=horizon,
                tier=tier,
                side=side,
            )
        )

    for horizon in sorted({int(value) for value in tier_recent["horizon_sessions"].dropna().unique()}):
        horizon_df = tier_recent[tier_recent["horizon_sessions"] == horizon]
        for tier in ("S", "A"):
            tier_df_for_horizon = horizon_df[horizon_df["tier"] == tier]
            for side in ("LONG", "SHORT"):
                add_row(horizon, tier, side, tier_df_for_horizon[tier_df_for_horizon["side"].apply(normalize_side) == side])
            add_row(horizon, tier, "ALL", tier_df_for_horizon)
        for side in ("LONG", "SHORT"):
            add_row(horizon, "S/A", side, horizon_df[horizon_df["side"].apply(normalize_side) == side])
        add_row(horizon, "S/A", "ALL", horizon_df)

    rows.sort(
        key=lambda item: (
            int(item.get("horizon_sessions", 0) or 0),
            _tier_rank_value(item.get("tier")),
            str(item.get("side") or ""),
        )
    )
    return rows


def _build_tier_catch_summary_row(
    opportunity_rows: list[dict],
    *,
    generated_at: str,
    lookback_days: int,
    window_start: str,
    window_end: str,
    horizon,
    side: str,
    top_factor_count: int,
) -> dict:
    winners = [row for row in opportunity_rows if (_scan_factor_number(row.get("side_return_pct")) or 0.0) > 0]
    caught = [row for row in opportunity_rows if _tier_for_priority_bucket(row.get("priority_bucket"))]
    caught_winners = [row for row in winners if _tier_for_priority_bucket(row.get("priority_bucket"))]
    caught_s = [row for row in caught if _tier_for_priority_bucket(row.get("priority_bucket")) == "S"]
    caught_a = [row for row in caught if _tier_for_priority_bucket(row.get("priority_bucket")) == "A"]
    missed_winners = [row for row in winners if not _tier_for_priority_bucket(row.get("priority_bucket"))]

    def _sample(rows: list[dict]) -> str:
        ranked = sorted(
            rows,
            key=lambda item: (
                _scan_factor_number(item.get("side_return_pct")) or -9999.0,
                str(item.get("scan_date") or ""),
                str(item.get("symbol") or ""),
            ),
            reverse=True,
        )
        samples = []
        for item in ranked[:8]:
            side_return = _scan_factor_number(item.get("side_return_pct"))
            text = f"{item.get('symbol')} {item.get('scan_date')}->{item.get('future_scan_date')}"
            if side_return is not None:
                text += f" ({side_return:+.2f}%)"
            tier = _tier_for_priority_bucket(item.get("priority_bucket"))
            if tier:
                text += f" tier={tier}"
            samples.append(text)
        return "; ".join(samples)

    return {
        "generated_at": generated_at,
        "lookback_days": lookback_days,
        "window_start": window_start,
        "window_end": window_end,
        "horizon_sessions": horizon,
        "side": side,
        "factor_opportunity_count": len(opportunity_rows),
        "factor_winner_count": len(winners),
        "caught_opportunity_count": len(caught),
        "caught_winner_count": len(caught_winners),
        "caught_s_count": len(caught_s),
        "caught_a_count": len(caught_a),
        "caught_opportunity_rate": (len(caught) / len(opportunity_rows)) if opportunity_rows else None,
        "caught_winner_rate": (len(caught_winners) / len(winners)) if winners else None,
        "missed_winner_count": len(missed_winners),
        "top_factor_count": top_factor_count,
        "sample_caught_winners": _sample(caught_winners),
        "sample_missed_winners": _sample(missed_winners),
    }


def build_bot_tier_catch_rate_rows(
    history_df: pd.DataFrame | None,
    observation_rows: list[dict] | None,
    leaderboard_rows: list[dict] | None,
    *,
    lookback_days: int = SCAN_FACTOR_LOOKBACK_DAYS,
    reference_date: date | datetime | str | None = None,
) -> list[dict]:
    frame = _prepare_scan_factor_history_frame(history_df)
    observations = observation_rows or []
    positive_groups = _positive_scan_factor_groups(leaderboard_rows)
    if frame.empty or not observations or not positive_groups:
        return []

    obs_df = pd.DataFrame(observations)
    obs_df["_scan_date_dt"] = pd.to_datetime(obs_df["scan_date"], errors="coerce")
    obs_df = obs_df[obs_df["_scan_date_dt"].notna()].copy()
    if obs_df.empty:
        return []
    if reference_date is None:
        window_end_ts = obs_df["_scan_date_dt"].max()
    else:
        window_end_ts = pd.to_datetime(reference_date, errors="coerce")
        if pd.isna(window_end_ts):
            window_end_ts = obs_df["_scan_date_dt"].max()
    lookback_days = max(1, int(lookback_days or SCAN_FACTOR_LOOKBACK_DAYS))
    window_start_ts = window_end_ts - pd.Timedelta(days=lookback_days)
    obs_df = obs_df[
        (obs_df["_scan_date_dt"] >= window_start_ts)
        & (obs_df["_scan_date_dt"] <= window_end_ts)
    ].copy()
    if obs_df.empty:
        return []

    source_rows = {
        str(row.get("_scan_row_id") or ""): row
        for row in frame.to_dict("records")
        if str(row.get("_scan_row_id") or "")
    }
    opportunities = []
    for obs in obs_df.to_dict("records"):
        source_row = source_rows.get(str(obs.get("scan_row_id") or ""))
        if not source_row:
            continue
        horizon = int(obs.get("horizon_sessions", 0) or 0)
        side = normalize_side(obs.get("side"))
        matches = _positive_scan_factor_matches_for_source_row(
            source_row,
            horizon=horizon,
            side=side,
            positive_factor_groups=positive_groups,
        )
        if not matches:
            continue
        item = dict(obs)
        item["priority_bucket"] = _scan_factor_text(source_row.get("priority_bucket"))
        item["tier"] = _tier_for_priority_bucket(source_row.get("priority_bucket"))
        item["positive_scan_factor_match_count"] = len(matches)
        item["positive_scan_factor_matches"] = _format_positive_scan_factor_matches(matches)
        opportunities.append(item)
    if not opportunities:
        return []

    generated_at = datetime.now().isoformat(timespec="seconds")
    window_start = window_start_ts.strftime("%Y-%m-%d")
    window_end = window_end_ts.strftime("%Y-%m-%d")
    rows = []

    for horizon in sorted({int(row.get("horizon_sessions", 0) or 0) for row in opportunities}):
        horizon_rows = [row for row in opportunities if int(row.get("horizon_sessions", 0) or 0) == horizon]
        for side in ("LONG", "SHORT"):
            side_rows = [row for row in horizon_rows if normalize_side(row.get("side")) == side]
            if not side_rows:
                continue
            rows.append(
                _build_tier_catch_summary_row(
                    side_rows,
                    generated_at=generated_at,
                    lookback_days=lookback_days,
                    window_start=window_start,
                    window_end=window_end,
                    horizon=horizon,
                    side=side,
                    top_factor_count=len(positive_groups.get((horizon, side), [])),
                )
            )
        rows.append(
            _build_tier_catch_summary_row(
                horizon_rows,
                generated_at=generated_at,
                lookback_days=lookback_days,
                window_start=window_start,
                window_end=window_end,
                horizon=horizon,
                side="ALL",
                top_factor_count=sum(len(positive_groups.get((horizon, side), [])) for side in ("LONG", "SHORT")),
            )
        )

    rows.sort(
        key=lambda item: (
            int(item.get("horizon_sessions", 0) or 0),
            str(item.get("side") or ""),
        )
    )
    return rows


def export_bot_tier_tracker_views(
    history_path: Path | None = None,
    tier_list_path: Path | None = None,
    tier_outcomes_path: Path | None = None,
    tier_performance_path: Path | None = None,
    tier_catch_rate_path: Path | None = None,
    *,
    lookback_days: int = SCAN_FACTOR_LOOKBACK_DAYS,
    min_observations: int = SCAN_FACTOR_MIN_OBSERVATIONS,
) -> dict:
    history_path = Path(history_path or D1_FEATURE_HISTORY_FILE)
    tier_list_path = Path(tier_list_path or TIER_LIST_FILE)
    tier_outcomes_path = Path(tier_outcomes_path or TIER_OUTCOMES_FILE)
    tier_performance_path = Path(tier_performance_path or TIER_PERFORMANCE_FILE)
    tier_catch_rate_path = Path(tier_catch_rate_path or TIER_CATCH_RATE_FILE)

    if not history_path.exists() or history_path.stat().st_size == 0:
        _write_scan_factor_csv(tier_list_path, [], TIER_LIST_COLUMNS)
        _write_scan_factor_csv(tier_outcomes_path, [], TIER_OUTCOME_COLUMNS)
        _write_scan_factor_csv(tier_performance_path, [], TIER_PERFORMANCE_COLUMNS)
        _write_scan_factor_csv(tier_catch_rate_path, [], TIER_CATCH_RATE_COLUMNS)
        return {"tier_pick_count": 0, "tier_outcome_count": 0, "tier_performance_count": 0, "tier_catch_rate_count": 0}

    history_df = pd.read_csv(history_path, low_memory=False)
    observation_rows = build_scan_factor_observation_rows(history_df)
    leaderboard_rows = build_scan_factor_leaderboard_rows(
        history_df,
        observation_rows,
        lookback_days=lookback_days,
        min_observations=min_observations,
    )
    tier_pick_rows = build_bot_tier_pick_rows(history_df, leaderboard_rows)
    tier_outcome_rows = build_bot_tier_outcome_rows(history_df, observation_rows, leaderboard_rows)
    tier_performance_rows = build_bot_tier_performance_rows(
        tier_outcome_rows,
        observation_rows,
        lookback_days=lookback_days,
    )
    tier_catch_rate_rows = build_bot_tier_catch_rate_rows(
        history_df,
        observation_rows,
        leaderboard_rows,
        lookback_days=lookback_days,
    )
    _write_scan_factor_csv(tier_list_path, tier_pick_rows, TIER_LIST_COLUMNS)
    _write_scan_factor_csv(tier_outcomes_path, tier_outcome_rows, TIER_OUTCOME_COLUMNS)
    _write_scan_factor_csv(tier_performance_path, tier_performance_rows, TIER_PERFORMANCE_COLUMNS)
    _write_scan_factor_csv(tier_catch_rate_path, tier_catch_rate_rows, TIER_CATCH_RATE_COLUMNS)
    return {
        "tier_pick_count": len(tier_pick_rows),
        "tier_outcome_count": len(tier_outcome_rows),
        "tier_performance_count": len(tier_performance_rows),
        "tier_catch_rate_count": len(tier_catch_rate_rows),
        "tier_list_path": str(tier_list_path),
        "tier_outcomes_path": str(tier_outcomes_path),
        "tier_performance_path": str(tier_performance_path),
        "tier_catch_rate_path": str(tier_catch_rate_path),
    }


def _load_csv_dict_rows(path: Path | str | None) -> list[dict]:
    if not path:
        return []
    path = Path(path)
    if not path.exists() or path.stat().st_size == 0:
        return []
    try:
        frame = pd.read_csv(path, low_memory=False)
    except Exception:
        logging.exception("Failed to load CSV rows from %s", path)
        return []
    if frame.empty:
        return []
    frame = frame.where(pd.notna(frame), None)
    return frame.to_dict("records")


def load_bot_tier_list_rows(path: Path | str | None = None) -> list[dict]:
    return _load_csv_dict_rows(path or TIER_LIST_FILE)


def load_bot_tier_performance_rows(path: Path | str | None = None) -> list[dict]:
    return _load_csv_dict_rows(path or TIER_PERFORMANCE_FILE)


def load_bot_tier_catch_rate_rows(path: Path | str | None = None) -> list[dict]:
    return _load_csv_dict_rows(path or TIER_CATCH_RATE_FILE)


def build_tracker_factor_view_rows(attribute_leaderboard_rows: list[dict]) -> list[dict]:
    if not attribute_leaderboard_rows:
        return []

    excluded_keys = {
        "setup.symbol",
        "setup.side",
        "setup.priority_bucket",
        "setup.priority_score",
        "levels.previous_day_high",
        "levels.previous_day_low",
    }
    rows = []
    for row in attribute_leaderboard_rows:
        if not isinstance(row, dict):
            continue
        attribute_key = str(row.get("attribute_key") or "").strip()
        if not attribute_key or attribute_key in excluded_keys or attribute_key.endswith("_note"):
            continue
        if int(row.get("setup_count", 0) or 0) < 6:
            continue
        if int(row.get("closed_tradeable_setup_count", 0) or 0) < 4:
            continue
        avg_closed_r_edge = _coerce_float(row.get("avg_closed_r_edge")) or 0.0
        target_hit_rate_edge = _coerce_float(row.get("target_hit_rate_edge")) or 0.0
        stop_rate_edge = _coerce_float(row.get("stop_rate_edge")) or 0.0
        impact_score = (
            abs(avg_closed_r_edge)
            + (abs(target_hit_rate_edge) * 1.5)
            + (abs(stop_rate_edge) * 1.5)
        ) * math.log1p(max(1, int(row.get("closed_tradeable_setup_count", 0) or 0)))
        if impact_score <= 0:
            continue
        item = dict(row)
        item["success_edge"] = (
            avg_closed_r_edge
            + (target_hit_rate_edge * 1.5)
            - (stop_rate_edge * 1.5)
        )
        item["impact_score"] = impact_score
        rows.append(item)

    rows.sort(
        key=lambda item: (
            -(float(item.get("success_edge", 0.0) or 0.0)),
            -(float(item.get("impact_score", 0.0) or 0.0)),
            -int(item.get("closed_tradeable_setup_count", 0) or 0),
            str(item.get("attribute_label") or ""),
            str(item.get("value_label") or ""),
        )
    )
    return rows


def export_setup_tracker_views(payload: dict) -> None:
    setups = payload.get("setups", {}) if isinstance(payload, dict) else {}
    attribute_registry = payload.get("attribute_registry", {}) if isinstance(payload, dict) else {}
    scenario_rows = _flatten_tracker_scenarios(setups)
    daily_rows = _flatten_tracker_daily_marks(setups)
    attribute_rows = _flatten_tracker_attributes(setups, attribute_registry)
    attribute_leaderboard_rows = _build_tracker_attribute_leaderboard_rows(attribute_rows)
    stats_rows = build_tracker_stats_rows(scenario_rows)
    setup_type_rows = build_tracker_setup_type_rows(setups)
    playbook_rows = build_tracker_playbook_rows(setups)
    payload["stats"] = stats_rows
    payload["setup_type_stats"] = setup_type_rows

    SETUP_SCENARIOS_FILE.parent.mkdir(parents=True, exist_ok=True)
    pd.DataFrame(scenario_rows).to_csv(SETUP_SCENARIOS_FILE, index=False)
    pd.DataFrame(daily_rows).to_csv(SETUP_DAILY_FILE, index=False)
    pd.DataFrame(stats_rows).to_csv(SETUP_STATS_FILE, index=False)
    pd.DataFrame(setup_type_rows).to_csv(SETUP_TYPE_STATS_FILE, index=False)
    pd.DataFrame(playbook_rows).to_csv(SETUP_PLAYBOOKS_FILE, index=False)
    pd.DataFrame(attribute_rows).to_csv(SETUP_ATTRIBUTES_FILE, index=False)
    pd.DataFrame(attribute_leaderboard_rows).to_csv(SETUP_ATTRIBUTE_LEADERBOARD_FILE, index=False)


def _infer_tracker_scan_date(
    tracked_rows: list[dict],
    symbol_map: dict,
    requested_scan_date: str | None = None,
) -> str:
    requested = str(requested_scan_date or "").strip()
    if requested:
        return requested

    candidate_dates = []
    tracked_symbols = [
        str(row.get("symbol", "")).strip().upper()
        for row in tracked_rows
        if isinstance(row, dict) and str(row.get("symbol", "")).strip()
    ]
    if tracked_symbols:
        for symbol in tracked_symbols:
            symbol_entry = symbol_map.get(symbol, {}) if isinstance(symbol_map, dict) else {}
            trade_date = str(symbol_entry.get("last_trade_date") or "").strip()
            if trade_date:
                candidate_dates.append(trade_date)
    elif isinstance(symbol_map, dict):
        for symbol_entry in symbol_map.values():
            if not isinstance(symbol_entry, dict):
                continue
            trade_date = str(symbol_entry.get("last_trade_date") or "").strip()
            if trade_date:
                candidate_dates.append(trade_date)

    if not candidate_dates:
        return datetime.now().date().isoformat()
    if len(set(candidate_dates)) == 1:
        return candidate_dates[0]
    return max(set(candidate_dates), key=lambda value: (candidate_dates.count(value), value))


def _indicator_row_for_scan_date(df: pd.DataFrame | None, scan_date: str) -> pd.Series | None:
    if df is None or not isinstance(df, pd.DataFrame) or df.empty or not scan_date:
        return None
    indicator_frame = compute_indicator_frame(df)
    if indicator_frame.empty or "trade_date" not in indicator_frame.columns:
        return None
    eligible_indicator_rows = indicator_frame[indicator_frame["trade_date"] <= scan_date]
    if eligible_indicator_rows.empty:
        return None
    return eligible_indicator_rows.iloc[-1]


def update_setup_tracker_from_scan(
    tracked_rows: list[dict],
    ai_state: dict,
    feature_rows_by_symbol: dict[str, dict],
    daily_frames_by_symbol: dict[str, pd.DataFrame],
    ib: IBApi | None,
    scan_date: str | None = None,
    auto_tune: bool = True,
    control_rows: list[dict] | None = None,
    study_rows: list[dict] | None = None,
) -> None:
    tracker = load_setup_tracker_payload()
    symbol_map = ai_state.get("symbols", {}) if isinstance(ai_state, dict) else {}
    now_iso = datetime.now().isoformat(timespec="seconds")
    target_scan_date = _infer_tracker_scan_date(tracked_rows, symbol_map, requested_scan_date=scan_date)
    scan_regime_label = (
        str((ai_state.get("market_regime") or {}).get("label") or "").strip().lower()
        if isinstance(ai_state, dict)
        else ""
    )

    existing_today_ids = [
        setup_id
        for setup_id, setup in list((tracker.get("setups") or {}).items())
        if isinstance(setup, dict) and str(setup.get("scan_date")) == target_scan_date
    ]
    for setup_id in existing_today_ids:
        tracker["setups"].pop(setup_id, None)

    current_setup_ids = []
    skipped_symbols = []
    for row in tracked_rows:
        symbol = str(row.get("symbol", "")).strip().upper()
        symbol_entry = symbol_map.get(symbol)
        if not isinstance(symbol_entry, dict):
            continue
        symbol_scan_date = str(symbol_entry.get("last_trade_date") or "").strip()
        if symbol_scan_date != target_scan_date:
            skipped_symbols.append(f"{symbol} ({symbol_scan_date or 'missing trade date'})")
            continue
        if not str(row.get("market_regime_label") or "").strip():
            row["market_regime_label"] = scan_regime_label
        df = daily_frames_by_symbol.get(symbol)
        indicator_row = _indicator_row_for_scan_date(df, target_scan_date)
        setup = build_tracker_setup_record(
            row,
            symbol_entry,
            feature_rows_by_symbol.get(symbol),
            now_iso,
            indicator_row,
            scan_date=target_scan_date,
            attribute_registry=tracker.setdefault("attribute_registry", {}),
        )
        if not setup:
            continue
        tracker["setups"][setup["setup_id"]] = setup
        current_setup_ids.append(setup["setup_id"])

    tracker["daily_watchlists"][target_scan_date] = {
        "updated_at": now_iso,
        "setup_ids": current_setup_ids,
        "symbols": sorted(
            {
                setup.get("symbol")
                for setup in tracker["setups"].values()
                if setup.get("setup_id") in current_setup_ids
            }
        ),
    }
    if skipped_symbols:
        logging.warning(
            "Setup tracker skipped %s symbol(s) whose daily data did not match scan date %s: %s",
            len(skipped_symbols),
            target_scan_date,
            ", ".join(skipped_symbols[:12]) + (f" (+{len(skipped_symbols) - 12} more)" if len(skipped_symbols) > 12 else ""),
        )

    # Control / holdout records live in a separate namespace so none of the
    # favorite-path aggregations (Expected-R, calibration, playbooks, stats) can
    # ever see them; they exist purely for gate measurement and edge discovery.
    control_setups = tracker.setdefault("control_setups", {})
    existing_control_today = [
        setup_id
        for setup_id, setup in list(control_setups.items())
        if isinstance(setup, dict) and str(setup.get("scan_date")) == target_scan_date
    ]
    for setup_id in existing_control_today:
        control_setups.pop(setup_id, None)
    control_added = 0
    for row in control_rows or []:
        symbol = str(row.get("symbol", "")).strip().upper()
        symbol_entry = symbol_map.get(symbol)
        if not isinstance(symbol_entry, dict):
            continue
        if str(symbol_entry.get("last_trade_date") or "").strip() != target_scan_date:
            continue
        if not str(row.get("market_regime_label") or "").strip():
            row["market_regime_label"] = scan_regime_label
        df = daily_frames_by_symbol.get(symbol)
        indicator_row = _indicator_row_for_scan_date(df, target_scan_date)
        setup = build_tracker_setup_record(
            row,
            symbol_entry,
            feature_rows_by_symbol.get(symbol),
            now_iso,
            indicator_row,
            scan_date=target_scan_date,
            attribute_registry=tracker.setdefault("attribute_registry", {}),
        )
        if not setup:
            continue
        setup["is_control"] = True
        setup["control_reason"] = str(row.get("control_reason") or "random")
        setup["setup_id"] = f"control:{setup['setup_id']}"
        control_setups[setup["setup_id"]] = setup
        control_added += 1
    _prune_control_setups(control_setups, reference_scan_date=target_scan_date)
    if control_added:
        logging.info(
            "Setup tracker recorded %s control/holdout setup(s) for %s (%s total tracked).",
            control_added,
            target_scan_date,
            len(control_setups),
        )

    # Study records (B4): new setup ideas under evaluation. Same isolated-namespace
    # treatment as control — never visible to Expected-R / calibration / live
    # ranking / stats; recorded purely so their hit-rate and realized R can be
    # measured before they are allowed to affect scoring.
    study_setups = tracker.setdefault("study_setups", {})
    existing_study_today = [
        setup_id
        for setup_id, setup in list(study_setups.items())
        if isinstance(setup, dict) and str(setup.get("scan_date")) == target_scan_date
    ]
    for setup_id in existing_study_today:
        study_setups.pop(setup_id, None)
    study_added = 0
    for row in study_rows or []:
        symbol = str(row.get("symbol", "")).strip().upper()
        symbol_entry = symbol_map.get(symbol)
        if not isinstance(symbol_entry, dict):
            continue
        if str(symbol_entry.get("last_trade_date") or "").strip() != target_scan_date:
            continue
        if not str(row.get("market_regime_label") or "").strip():
            row["market_regime_label"] = scan_regime_label
        df = daily_frames_by_symbol.get(symbol)
        indicator_row = _indicator_row_for_scan_date(df, target_scan_date)
        setup = build_tracker_setup_record(
            row,
            symbol_entry,
            feature_rows_by_symbol.get(symbol),
            now_iso,
            indicator_row,
            scan_date=target_scan_date,
            attribute_registry=tracker.setdefault("attribute_registry", {}),
        )
        if not setup:
            continue
        setup["is_study"] = True
        setup["study_kind"] = str(row.get("study_kind") or row.get("setup_family") or "study")
        setup["setup_id"] = f"study:{setup['setup_id']}"
        study_setups[setup["setup_id"]] = setup
        study_added += 1
    _prune_study_setups(study_setups, reference_scan_date=target_scan_date)
    if study_added:
        logging.info(
            "Setup tracker recorded %s study setup(s) for %s (%s total tracked).",
            study_added,
            target_scan_date,
            len(study_setups),
        )

    recompute_cache = {}

    def _recompute_namespace(namespace: dict) -> None:
        for setup_id, setup in list((namespace or {}).items()):
            if not isinstance(setup, dict):
                continue
            symbol = str(setup.get("symbol", "")).strip().upper()
            if symbol in recompute_cache:
                df = recompute_cache[symbol]
            else:
                df = daily_frames_by_symbol.get(symbol)
                if df is None or df.empty:
                    anchor_date = str(setup.get("anchor_date") or setup.get("entry_trade_date") or target_scan_date)
                    days_needed = ATR_LENGTH + 220
                    try:
                        anchor_date_obj = datetime.fromisoformat(anchor_date).date()
                        days_needed = max(days_needed, (datetime.now().date() - anchor_date_obj).days + 20)
                    except ValueError:
                        pass
                    df = fetch_daily_bars(ib, symbol, days_needed)
                recompute_cache[symbol] = df
            if df is None or df.empty:
                continue
            namespace[setup_id] = recompute_tracker_setup_record(setup, df)

    _recompute_namespace(tracker.get("setups"))
    _recompute_namespace(tracker.get("control_setups"))
    _recompute_namespace(tracker.get("study_setups"))

    export_setup_tracker_views(tracker)
    try:
        write_control_discovery_report(CONTROL_DISCOVERY_FILE, tracker)
    except Exception as exc:
        logging.warning("Could not write control discovery report (%s).", exc)
    try:
        write_master_avwap_study_report(MASTER_AVWAP_STUDY_FILE, tracker)
    except Exception as exc:
        logging.warning("Could not write study report (%s).", exc)
    save_setup_tracker_payload(tracker)
    if auto_tune:
        tuner_output = run_priority_scoring_tuner(
            apply_changes=True,
            min_setups=8,
            suppress_failures=True,
        )
        if tuner_output:
            logging.info("Priority scoring tuner: %s", tuner_output.splitlines()[0])


# ---------------------------------------------------------------------------
# Control / holdout discovery
# ---------------------------------------------------------------------------
def select_tracker_control_rows(
    priority_rows: list[dict],
    tracked_rows: list[dict],
    *,
    scan_date: str | None = None,
    max_rows: int = CONTROL_SAMPLE_MAX_PER_SCAN,
) -> list[dict]:
    """Pick a capped sample of real setups the bot saw but did NOT promote.

    Two strata: ``near_miss`` (scored just below the favorite gate — measures
    whether the gate is well-calibrated) and ``random`` (a deterministic sample
    of the rest — surfaces edges in configurations the bot ignores). Rows are
    flagged in place with ``is_control`` and ``control_reason``."""

    if not TRACKER_CONTROL_SAMPLING_ENABLED or max_rows <= 0:
        return []

    tracked_keys = {
        (str(row.get("symbol") or "").strip().upper(), normalize_side(row.get("side")))
        for row in tracked_rows or []
    }
    candidates = []
    for row in priority_rows or []:
        symbol = str(row.get("symbol") or "").strip().upper()
        if not symbol:
            continue
        if (symbol, normalize_side(row.get("side"))) in tracked_keys:
            continue
        if str(row.get("priority_bucket") or "") in {"favorite_setup", "near_favorite_zone"}:
            continue
        if row.get("ranking_blocked") or _is_priority_recommendation_blocked(row):
            continue
        # Only track genuine setups that simply weren't promoted, not non-setups.
        if not row.get("has_favorite_signal"):
            continue
        candidates.append(row)

    if not candidates:
        return []

    gate = float(PRIORITY_FAVORITE_SETUP_MIN_SCORE)
    near_miss = [row for row in candidates if _priority_row_score(row) >= gate - CONTROL_NEAR_MISS_SCORE_BAND]
    near_miss_ids = {id(row) for row in near_miss}
    others = [row for row in candidates if id(row) not in near_miss_ids]

    near_miss.sort(key=lambda row: -_priority_row_score(row))
    rng = random.Random(str(scan_date or ""))
    rng.shuffle(others)

    selected = []
    for row in near_miss:
        if len(selected) >= max_rows:
            break
        row["is_control"] = True
        row["control_reason"] = "near_miss"
        selected.append(row)
    for row in others:
        if len(selected) >= max_rows:
            break
        row["is_control"] = True
        row["control_reason"] = "random"
        selected.append(row)
    return selected


def _prune_control_setups(control_setups: dict, *, reference_scan_date: str | None = None) -> None:
    """Bound the control namespace by age and hard count so it stays cheap to
    recompute every scan."""

    if not isinstance(control_setups, dict) or not control_setups:
        return
    reference = _parse_iso_date_or_none(reference_scan_date) or datetime.now().date()
    for setup_id, setup in list(control_setups.items()):
        scan_day = _parse_iso_date_or_none(isinstance(setup, dict) and setup.get("scan_date") or None)
        if scan_day is None or (reference - scan_day).days > CONTROL_SETUP_KEEP_DAYS:
            control_setups.pop(setup_id, None)
    if len(control_setups) > CONTROL_SETUP_MAX_RECORDS:
        ordered = sorted(
            control_setups.items(),
            key=lambda item: str(item[1].get("scan_date") or "") if isinstance(item[1], dict) else "",
        )
        for setup_id, _setup in ordered[: len(control_setups) - CONTROL_SETUP_MAX_RECORDS]:
            control_setups.pop(setup_id, None)


def _collect_control_episode_observations(setups: dict, *, default_reason: str = "random") -> list[dict]:
    """Episode-deduped closed observations (one per setup episode) from a setups
    namespace, each carrying side/family/reason and representative closed R."""

    by_episode: dict[tuple, dict] = {}
    for setup in (setups or {}).values():
        if not isinstance(setup, dict):
            continue
        outcome = _summarize_tracker_setup_outcome(setup)
        if int(outcome.get("closed_tradeable_scenario_count", 0) or 0) <= 0:
            continue
        realized = _coerce_float(outcome.get("representative_closed_r"))
        if realized is None:
            realized = _coerce_float(outcome.get("avg_closed_r"))
        if realized is None:
            continue
        key = _tracker_episode_key(setup)
        scan_date = str(setup.get("scan_date") or "")
        existing = by_episode.get(key)
        if existing is not None and existing["scan_date"] <= scan_date:
            continue
        by_episode[key] = {
            "side": normalize_side(setup.get("side")),
            "setup_family": _canonical_tracker_setup_family(setup),
            "reason": str(setup.get("control_reason") or default_reason),
            "closed_r": float(realized),
            "scan_date": scan_date,
        }
    return list(by_episode.values())


def _summarize_control_observation_group(observations: list[dict]) -> dict:
    closed_rs = [float(obs["closed_r"]) for obs in observations if obs.get("closed_r") is not None]
    n = len(closed_rs)
    return {
        "closed_episodes": n,
        "avg_closed_r": (sum(closed_rs) / n) if n else None,
        "win_rate": (sum(1.0 for value in closed_rs if value > 0) / n) if n else None,
    }


def _prune_study_setups(study_setups: dict, *, reference_scan_date: str | None = None) -> None:
    """Bound the study namespace by age and hard count (mirrors
    ``_prune_control_setups`` with study limits)."""

    if not isinstance(study_setups, dict) or not study_setups:
        return
    reference = _parse_iso_date_or_none(reference_scan_date) or datetime.now().date()
    for setup_id, setup in list(study_setups.items()):
        scan_day = _parse_iso_date_or_none(isinstance(setup, dict) and setup.get("scan_date") or None)
        if scan_day is None or (reference - scan_day).days > STUDY_SETUP_KEEP_DAYS:
            study_setups.pop(setup_id, None)
    if len(study_setups) > STUDY_SETUP_MAX_RECORDS:
        ordered = sorted(
            study_setups.items(),
            key=lambda item: str(item[1].get("scan_date") or "") if isinstance(item[1], dict) else "",
        )
        for setup_id, _setup in ordered[: len(study_setups) - STUDY_SETUP_MAX_RECORDS]:
            study_setups.pop(setup_id, None)


def build_study_discovery_rows(tracker: dict | None = None) -> dict:
    """Rank study-namespace setup ideas by realized edge (episode-deduped, closed R).

    Read-only over ``tracker["study_setups"]`` — never reads or writes
    ``setups``/``control_setups``, so Expected-R, calibration, and live ranking are
    unaffected. This is the measurement surface for new ideas (1h/4h trend,
    HV-level break, compression break, ...) before any of them touch scoring.
    """

    tracker = tracker if isinstance(tracker, dict) else load_setup_tracker_payload()
    observations = _collect_control_episode_observations(
        tracker.get("study_setups", {}), default_reason="study"
    )
    family_groups: dict[tuple[str, str], list[dict]] = {}
    for obs in observations:
        family_groups.setdefault((obs["side"], obs["setup_family"]), []).append(obs)
    family_rows = []
    for (side, family), obs_list in family_groups.items():
        summary = _summarize_control_observation_group(obs_list)
        avg_r = summary["avg_closed_r"]
        summary.update(
            {
                "side": side,
                "setup_family": family,
                "promising": bool(
                    summary["closed_episodes"] >= STUDY_DISCOVERY_MIN_CLOSED_EPISODES
                    and avg_r is not None
                    and avg_r >= CONTROL_DISCOVERY_MIN_AVG_R
                ),
            }
        )
        family_rows.append(summary)
    family_rows.sort(
        key=lambda row: (
            -(row["avg_closed_r"] if row["avg_closed_r"] is not None else -9999.0),
            -int(row["closed_episodes"]),
        )
    )
    return {"families": family_rows}


def write_master_avwap_study_report(path: Path, tracker: dict | None = None) -> None:
    discovery = build_study_discovery_rows(tracker)
    lines = [
        "Master AVWAP study namespace (B4)",
        f"Generated at {datetime.now().strftime('%Y-%m-%d %H:%M:%S')}",
        "",
        "Study-only setup ideas, measured for edge BEFORE they affect scoring.",
        "Isolated from Expected-R / calibration / live ranking. Episode-deduped,",
        "representative-stop, net-of-cost closed R.",
        "",
        f"{'side':<6}{'study kind':<34}{'episodes':>10}{'avg R':>9}{'win':>7}  flag",
        "-" * 74,
    ]
    if discovery["families"]:
        for row in discovery["families"]:
            avg_r = row["avg_closed_r"]
            win = row["win_rate"]
            flag = "  <-- PROMISING" if row.get("promising") else ""
            lines.append(
                f"{row['side']:<6}{row['setup_family'][:33]:<34}{row['closed_episodes']:>10}"
                f"{(f'{avg_r:+.2f}' if avg_r is not None else 'n/a'):>9}"
                f"{(f'{win*100:.0f}%' if win is not None else 'n/a'):>7}{flag}"
            )
    else:
        lines.append("(No closed study setups yet — populates as study ideas resolve.)")

    Path(path).parent.mkdir(parents=True, exist_ok=True)
    Path(path).write_text("\n".join(lines).rstrip() + "\n", encoding="utf-8")


def build_control_discovery_rows(tracker: dict | None = None) -> dict:
    """Compare promoted (favorite) setups against the control sample, and rank
    control setup families by realized edge to surface configurations the bot is
    rejecting that are actually working."""

    tracker = tracker if isinstance(tracker, dict) else load_setup_tracker_payload()
    promoted = _collect_control_episode_observations(tracker.get("setups", {}), default_reason="promoted")
    for obs in promoted:
        obs["reason"] = "promoted"
    control = _collect_control_episode_observations(tracker.get("control_setups", {}))

    cohorts = {
        "promoted": promoted,
        "near_miss": [obs for obs in control if obs["reason"] == "near_miss"],
        "random": [obs for obs in control if obs["reason"] == "random"],
    }
    cohort_rows = []
    for label in ("promoted", "near_miss", "random"):
        summary = _summarize_control_observation_group(cohorts[label])
        summary["cohort"] = label
        cohort_rows.append(summary)

    family_groups: dict[tuple[str, str], list[dict]] = {}
    for obs in control:
        family_groups.setdefault((obs["side"], obs["setup_family"]), []).append(obs)
    family_rows = []
    for (side, family), observations in family_groups.items():
        summary = _summarize_control_observation_group(observations)
        avg_r = summary["avg_closed_r"]
        summary.update(
            {
                "side": side,
                "setup_family": family,
                "outperforming": bool(
                    summary["closed_episodes"] >= CONTROL_DISCOVERY_MIN_CLOSED_EPISODES
                    and avg_r is not None
                    and avg_r >= CONTROL_DISCOVERY_MIN_AVG_R
                ),
            }
        )
        family_rows.append(summary)
    family_rows.sort(
        key=lambda row: (
            -(row["avg_closed_r"] if row["avg_closed_r"] is not None else -9999.0),
            -int(row["closed_episodes"]),
        )
    )
    return {"cohorts": cohort_rows, "families": family_rows}


def write_control_discovery_report(path: Path, tracker: dict | None = None) -> None:
    discovery = build_control_discovery_rows(tracker)
    lines = [
        "Master AVWAP control / holdout discovery",
        f"Generated at {datetime.now().strftime('%Y-%m-%d %H:%M:%S')}",
        "",
        "Gate edge: promoted (favorites) vs setups the bot saw but rejected.",
        "Episode-deduped, representative-stop, net-of-cost closed R.",
        "",
        f"{'cohort':<12}{'episodes':>10}{'avg R':>10}{'win rate':>10}",
        "-" * 42,
    ]
    for row in discovery["cohorts"]:
        avg_r = row["avg_closed_r"]
        win = row["win_rate"]
        lines.append(
            f"{row['cohort']:<12}{row['closed_episodes']:>10}"
            f"{(f'{avg_r:+.2f}' if avg_r is not None else 'n/a'):>10}"
            f"{(f'{win*100:.0f}%' if win is not None else 'n/a'):>10}"
        )

    lines.extend(
        [
            "",
            "Rejected configurations ranked by realized edge "
            f"(>= {CONTROL_DISCOVERY_MIN_CLOSED_EPISODES} closed, >= {CONTROL_DISCOVERY_MIN_AVG_R:+.2f}R flagged):",
            f"{'side':<6}{'family':<34}{'episodes':>10}{'avg R':>9}{'win':>7}  flag",
            "-" * 74,
        ]
    )
    if discovery["families"]:
        for row in discovery["families"]:
            avg_r = row["avg_closed_r"]
            win = row["win_rate"]
            flag = "  <-- DISCOVER" if row["outperforming"] else ""
            lines.append(
                f"{row['side']:<6}{row['setup_family'][:33]:<34}{row['closed_episodes']:>10}"
                f"{(f'{avg_r:+.2f}' if avg_r is not None else 'n/a'):>9}"
                f"{(f'{win*100:.0f}%' if win is not None else 'n/a'):>7}{flag}"
            )
    else:
        lines.append("(No closed control setups yet — discovery builds as the holdout sample resolves.)")

    Path(path).parent.mkdir(parents=True, exist_ok=True)
    Path(path).write_text("\n".join(lines).rstrip() + "\n", encoding="utf-8")


def get_last_daily_row_for_date(daily_rows, last_trade_date):
    target = last_trade_date.isoformat()
    for row in reversed(daily_rows):
        if row["date"] == target:
            return row
    return None


def get_previous_daily_row_for_date(daily_rows, last_trade_date):
    target = last_trade_date.isoformat()
    previous_row = None
    for row in daily_rows:
        row_date = str(row.get("date") or "")
        if not row_date:
            continue
        if row_date >= target:
            break
        previous_row = row
    return previous_row


def assess_previous_day_range_break(daily_rows, last_trade_date, last_close, side):
    previous_row = get_previous_daily_row_for_date(daily_rows, last_trade_date)
    previous_day_high = _coerce_float(previous_row.get("high")) if previous_row else None
    previous_day_low = _coerce_float(previous_row.get("low")) if previous_row else None
    result = {
        "previous_day_date": str(previous_row.get("date") or "") if previous_row else "",
        "previous_day_high": previous_day_high,
        "previous_day_low": previous_day_low,
        "previous_day_range_break": False,
        "previous_day_range_break_bonus": 0,
        "previous_day_range_note": "",
    }
    if last_close is None:
        return result

    side = normalize_side(side)
    if side == "LONG" and previous_day_high is not None and float(last_close) > float(previous_day_high):
        result["previous_day_range_break"] = True
        result["previous_day_range_break_bonus"] = PRIORITY_PREVIOUS_DAY_RANGE_BREAK_SCORE_BONUS
        result["previous_day_range_note"] = (
            f"Above previous day high {float(previous_day_high):.2f} "
            f"(+{PRIORITY_PREVIOUS_DAY_RANGE_BREAK_SCORE_BONUS})"
        )
    elif side == "SHORT" and previous_day_low is not None and float(last_close) < float(previous_day_low):
        result["previous_day_range_break"] = True
        result["previous_day_range_break_bonus"] = PRIORITY_PREVIOUS_DAY_RANGE_BREAK_SCORE_BONUS
        result["previous_day_range_note"] = (
            f"Below previous day low {float(previous_day_low):.2f} "
            f"(+{PRIORITY_PREVIOUS_DAY_RANGE_BREAK_SCORE_BONUS})"
        )
    return result


def sessions_since_date(df: pd.DataFrame, event_date: date) -> int | None:
    """
    Count trading-session candles from event_date (exclusive) through the latest
    available bar in df. Returns None if event_date is not present in df.
    """
    if df.empty or "datetime" not in df:
        return None

    session_dates = df["datetime"].dt.date
    if event_date not in set(session_dates.tolist()):
        return None

    return int((session_dates > event_date).sum())

# ============================================================================
# EARNINGS FETCH (NASDAQ + YFINANCE FALLBACK)
# ============================================================================

def _record_shared_nasdaq_rows_safely(rows: list[dict] | None, date_str: str) -> None:
    if not isinstance(rows, list) or not rows:
        return
    try:
        record_shared_nasdaq_rows(rows, date_str)
    except Exception as exc:
        logging.warning("Failed updating shared earnings history for %s: %s", date_str, exc)


def _record_shared_yfinance_dates_safely(symbol: str, dates: list[str] | None) -> None:
    if not dates:
        return
    rows = [
        {
            "ticker": symbol,
            "date": value,
            "source": "yfinance",
            "time": "TBD",
        }
        for value in dates
    ]
    try:
        record_shared_yfinance_rows(rows, symbol=symbol)
    except Exception as exc:
        logging.warning("%s: failed updating shared earnings history from yfinance: %s", symbol, exc)


def _earnings_calendar_cache_entry_has_rows(entry) -> bool:
    return isinstance(entry, list) or (isinstance(entry, dict) and isinstance(entry.get("rows"), list))


def _earnings_calendar_rows_from_cache_entry(entry) -> list:
    if isinstance(entry, dict):
        rows = entry.get("rows", [])
    else:
        rows = entry
    return rows if isinstance(rows, list) else []


def _earnings_calendar_cache_fetched_at(entry) -> str:
    return str(entry.get("fetched_at") or "unknown") if isinstance(entry, dict) else "unknown"


def _earnings_calendar_cache_entry_is_fresh(date_str: str, entry) -> bool:
    if not _earnings_calendar_cache_entry_has_rows(entry):
        return False
    event_date = _parse_iso_date_or_none(date_str)
    if event_date is None:
        return False
    today = datetime.now().date()
    if event_date < today:
        return True
    return _is_timestamp_within_minutes(
        _earnings_calendar_cache_fetched_at(entry),
        EARNINGS_CALENDAR_TODAY_CACHE_MAX_AGE_MINUTES,
    )


def _extract_nasdaq_earnings_rows(payload) -> list[dict]:
    data = payload.get("data") if isinstance(payload, dict) else {}
    rows = data.get("rows", []) if isinstance(data, dict) else []
    return [row for row in rows if isinstance(row, dict)] if isinstance(rows, list) else []


def _fetch_nasdaq_earnings_rows_with_retries(date_str: str) -> tuple[list[dict], Exception | None]:
    last_error = None
    attempts = max(1, int(EARNINGS_CALENDAR_REQUEST_RETRIES) + 1)
    for attempt in range(attempts):
        try:
            resp = requests.get(
                API_URL.format(date=date_str),
                headers=HEADERS,
                timeout=EARNINGS_CALENDAR_REQUEST_TIMEOUT_SECONDS,
            )
            resp.raise_for_status()
            return _extract_nasdaq_earnings_rows(resp.json()), None
        except Exception as exc:
            last_error = exc
            if attempt < attempts - 1 and EARNINGS_CALENDAR_RETRY_BACKOFF_SECONDS:
                time.sleep(float(EARNINGS_CALENDAR_RETRY_BACKOFF_SECONDS) * (2 ** attempt))
    return [], last_error


def fetch_earnings_for_date(date_str: str):
    cache = _load_earnings_calendar_rows_cache()
    cached_entry = cache.get(date_str) if isinstance(cache, dict) else None
    cached_rows = _earnings_calendar_rows_from_cache_entry(cached_entry)
    if _earnings_calendar_cache_entry_is_fresh(date_str, cached_entry):
        _record_shared_nasdaq_rows_safely(cached_rows, date_str)
        return cached_rows

    rows, error = _fetch_nasdaq_earnings_rows_with_retries(date_str)
    if error is None:
        fetched_at = datetime.now().isoformat(timespec="seconds")
        cache[date_str] = {
            "fetched_at": fetched_at,
            "row_count": len(rows),
            "rows": rows,
        }
        _save_earnings_calendar_rows_cache()
        _record_shared_nasdaq_rows_safely(rows, date_str)
        return rows

    logging.warning(f"Failed fetch earnings for {date_str}: {error}")
    if _earnings_calendar_cache_entry_has_rows(cached_entry):
        if cached_rows:
            logging.info(
                "Using cached earnings calendar rows for %s after fetch failure; fetched_at=%s row_count=%s.",
                date_str,
                _earnings_calendar_cache_fetched_at(cached_entry),
                len(cached_rows),
            )
            _record_shared_nasdaq_rows_safely(cached_rows, date_str)
        return cached_rows
    return []

def collect_earnings_dates(
    symbols,
    fetch_fn=fetch_earnings_for_date,
    base_sleep=0.5,
    lookback_days=MAX_LOOKBACK_DAYS,
    stop_when_complete=False,
    min_dates_per_symbol=1,
):
    """
    Return dict: sym -> sorted list of past earnings dates (YYYY-MM-DD), most recent first.

    Default behavior walks the entire lookback window so quarterly anchor history
    stays correct. Optional early-stop behavior is kept for targeted refreshes and
    dry-run validation.
    """
    normalized_symbols = sorted(
        {str(sym or "").strip().upper() for sym in symbols if str(sym or "").strip()}
    )
    symbol_dates = {sym: [] for sym in normalized_symbols}
    if not symbol_dates:
        return {}

    today = datetime.now().date()
    pending = set(normalized_symbols) if stop_when_complete else set()
    minimum_dates = max(1, int(min_dates_per_symbol))

    for delta in range(lookback_days):
        day = today - timedelta(days=delta)
        rows = fetch_fn(day.isoformat())
        if not isinstance(rows, list):
            rows = []
        for row in rows:
            sym = str(row.get("symbol", "")).strip().upper()
            if sym not in symbol_dates:
                continue
            ds = day.isoformat()
            if ds not in symbol_dates[sym]:
                symbol_dates[sym].append(ds)
            if stop_when_complete and len(symbol_dates[sym]) >= minimum_dates:
                pending.discard(sym)

        if stop_when_complete and not pending:
            logging.info("Collected required earnings history for all requested symbols; stopping early.")
            break

        if base_sleep:
            time.sleep(base_sleep)

    for sym, dates in symbol_dates.items():
        symbol_dates[sym] = _normalize_earnings_dates(dates, today=today)

    return symbol_dates


def collect_upcoming_earnings_dates(
    symbols,
    fetch_fn=fetch_earnings_for_date,
    lookahead_days=THETA_UPCOMING_EARNINGS_LOOKAHEAD_DAYS,
    base_sleep=0.05,
):
    normalized_symbols = sorted(
        {str(sym or "").strip().upper() for sym in symbols if str(sym or "").strip()}
    )
    symbol_dates = {sym: [] for sym in normalized_symbols}
    if not symbol_dates:
        return {}

    today = datetime.now().date()
    for delta in range(max(0, int(lookahead_days)) + 1):
        day = today + timedelta(days=delta)
        rows = fetch_fn(day.isoformat())
        if not isinstance(rows, list):
            rows = []
        for row in rows:
            sym = str(row.get("symbol", "")).strip().upper()
            if sym not in symbol_dates:
                continue
            ds = day.isoformat()
            if ds not in symbol_dates[sym]:
                symbol_dates[sym].append(ds)
        if base_sleep:
            time.sleep(base_sleep)

    for sym, dates in symbol_dates.items():
        symbol_dates[sym] = sorted(set(dates))

    try:
        shared_dates = get_shared_future_earnings_dates(
            normalized_symbols,
            start_date=today,
            lookahead_days=lookahead_days,
        )
        for sym in normalized_symbols:
            symbol_dates[sym] = sorted(set(symbol_dates.get(sym, []) + shared_dates.get(sym, [])))
    except Exception as exc:
        logging.warning("Failed reading shared upcoming earnings history: %s", exc)
    return symbol_dates


def dry_run_collect_earnings_dates_short_circuit():
    """
    Dry-run helper to validate optional short-circuit behavior.
    """
    symbols = ["AAA", "BBB", "CCC"]
    today = datetime.now().date()

    schedule = {
        today.isoformat(): [{"symbol": "AAA"}],
        (today - timedelta(days=1)).isoformat(): [{"symbol": "BBB"}],
        (today - timedelta(days=2)).isoformat(): [{"symbol": "CCC"}],
        (today - timedelta(days=3)).isoformat(): [{"symbol": "AAA"}],
    }

    calls = []

    def mock_fetch(date_str: str):
        calls.append(date_str)
        return schedule.get(date_str, [])

    results = collect_earnings_dates(
        symbols,
        fetch_fn=mock_fetch,
        base_sleep=0,
        lookback_days=10,
        stop_when_complete=True,
        min_dates_per_symbol=1,
    )

    assert len(calls) == 3, f"Expected 3 fetches before short-circuiting, got {len(calls)}"
    assert all(results[sym] for sym in symbols), f"Missing earnings data for: {results}"

    return {"calls": calls, "results": results}

def pick_current_earnings_anchor(dates):
    """
    dates: ISO strings desc (most recent first).
    Current anchor:
      - If most recent within RECENT_DAYS, use SECOND most recent as anchor
        (to avoid 'fresh earnings gap' ambiguity)
      - Else, use most recent.
    """
    if not dates:
        return None
    today = datetime.now().date()
    first_date = datetime.fromisoformat(dates[0]).date()
    if (today - first_date).days <= RECENT_DAYS and len(dates) > 1:
        return datetime.fromisoformat(dates[1]).date()
    return first_date

def pick_previous_earnings_anchor(dates):
    """
    dates: ISO strings desc (most recent first).
    Previous anchor: the quarter before the current AVWAPE anchor.
    """
    if len(dates) < 2:
        return None
    today = datetime.now().date()
    first_date = datetime.fromisoformat(dates[0]).date()
    if (today - first_date).days <= RECENT_DAYS:
        if len(dates) < 3:
            return None
        return datetime.fromisoformat(dates[2]).date()
    return datetime.fromisoformat(dates[1]).date()


def _earnings_dates_as_of(dates, reference_date: date) -> list[str]:
    filtered = []
    for value in dates or []:
        parsed = _parse_iso_date_or_none(value)
        if parsed is None or parsed > reference_date:
            continue
        filtered.append(parsed.isoformat())
    return _normalize_earnings_dates(filtered, today=reference_date, limit=EARNINGS_HISTORY_LIMIT)


def pick_current_earnings_anchor_for_reference_date(dates, reference_date: date):
    eligible_dates = _earnings_dates_as_of(dates, reference_date)
    if not eligible_dates:
        return None
    first_date = datetime.fromisoformat(eligible_dates[0]).date()
    if (reference_date - first_date).days <= RECENT_DAYS and len(eligible_dates) > 1:
        return datetime.fromisoformat(eligible_dates[1]).date()
    return first_date


def pick_previous_earnings_anchor_for_reference_date(dates, reference_date: date):
    eligible_dates = _earnings_dates_as_of(dates, reference_date)
    if len(eligible_dates) < 2:
        return None
    first_date = datetime.fromisoformat(eligible_dates[0]).date()
    if (reference_date - first_date).days <= RECENT_DAYS:
        if len(eligible_dates) < 3:
            return None
        return datetime.fromisoformat(eligible_dates[2]).date()
    return datetime.fromisoformat(eligible_dates[1]).date()

def yf_earnings_dates(symbol: str):
    """
    Fallback using yfinance earnings_dates.
    """
    if not _can_attempt_yf_earnings_lookup(log_once=True):
        return []

    logger_state = []
    for logger_name in YF_EARNINGS_LOGGER_NAMES:
        logger = logging.getLogger(logger_name)
        logger_state.append((logger, logger.level, logger.propagate))
        logger.setLevel(logging.CRITICAL)
        logger.propagate = False

    try:
        t = yf.Ticker(symbol)
        ed = t.get_earnings_dates(limit=8)
        if ed is None or getattr(ed, "empty", True):
            return []
        if not hasattr(ed, "index") or ed.index is None:
            return []
        if getattr(ed.index, "tz", None) is not None:
            ed.index = ed.index.tz_localize(None)
        past = ed[ed.index < pd.Timestamp.today().tz_localize(None)]
        sorted_past = sorted(past.index, reverse=True)
        return [d.date().isoformat() for d in sorted_past]
    except Exception as e:
        message = str(e)
        if "Import lxml" in message:
            global YF_EARNINGS_LOOKUP_DISABLED_REASON
            YF_EARNINGS_LOOKUP_DISABLED_REASON = "lxml is not installed"
            _can_attempt_yf_earnings_lookup(log_once=True)
            return []
        if any(marker in message for marker in YF_EARNINGS_NO_DATA_MARKERS):
            return []
        logging.warning(f"{symbol}: yfinance earnings lookup failed: {e}")
        return []
    finally:
        for logger, level, propagate in logger_state:
            logger.setLevel(level)
            logger.propagate = propagate


def load_or_refresh_earnings(symbols):
    """
    Maintain a rolling earnings cache that can discover new quarterly releases.

    The cache does a daily recent-window refresh across the universe to catch new
    earnings quickly, then forces a deeper rebuild for symbols whose latest known
    earnings is stale or whose history is incomplete.
    """
    cache = load_earnings_date_cache()
    symbol_cache = cache.setdefault("symbols", {})
    today = datetime.now().date()
    today_iso = today.isoformat()
    normalized_symbols = sorted(
        {str(sym or "").strip().upper() for sym in symbols if str(sym or "").strip()}
    )

    for sym in normalized_symbols:
        symbol_cache.setdefault(sym, _normalize_earnings_cache_entry({}))

    try:
        shared_past_dates = get_shared_past_earnings_dates(
            normalized_symbols,
            as_of=today,
            limit=EARNINGS_HISTORY_LIMIT,
        )
    except Exception as exc:
        logging.warning("Failed reading shared earnings history: %s", exc)
        shared_past_dates = {}
    for sym in normalized_symbols:
        dates = shared_past_dates.get(sym, [])
        if not dates:
            continue
        entry = symbol_cache.setdefault(sym, _normalize_earnings_cache_entry({}))
        entry["dates"] = _merge_earnings_dates(entry.get("dates", []), dates)

    cached_recent_updates = _collect_cached_calendar_earnings_dates(
        normalized_symbols,
        lookback_days=EARNINGS_RECENT_DISCOVERY_WINDOW_DAYS,
        today=today,
    )
    cached_merge_count = 0
    for sym in normalized_symbols:
        cached_dates = cached_recent_updates.get(sym, [])
        if not cached_dates:
            continue
        entry = symbol_cache.setdefault(sym, _normalize_earnings_cache_entry({}))
        before_dates = list(entry.get("dates", []))
        entry["dates"] = _merge_earnings_dates(before_dates, cached_dates)
        if entry["dates"] != before_dates:
            cached_merge_count += 1
    if cached_merge_count:
        logging.info(
            "Merged cached Nasdaq earnings calendar rows into %d symbol earnings history entries.",
            cached_merge_count,
        )

    recent_refresh_symbols = (
        normalized_symbols
        if cache.get("last_recent_refresh_on") != today_iso
        else [
            sym
            for sym in normalized_symbols
            if symbol_cache.get(sym, {}).get("last_recent_refresh_on") != today_iso
        ]
    )

    if recent_refresh_symbols:
        logging.info(
            f"Refreshing recent earnings window across {len(recent_refresh_symbols)} symbols "
            f"({EARNINGS_RECENT_DISCOVERY_WINDOW_DAYS} days)."
        )
        recent_updates = collect_earnings_dates(
            recent_refresh_symbols,
            lookback_days=EARNINGS_RECENT_DISCOVERY_WINDOW_DAYS,
            base_sleep=0.15,
        )
        for sym in recent_refresh_symbols:
            entry = symbol_cache.setdefault(sym, _normalize_earnings_cache_entry({}))
            entry["dates"] = _merge_earnings_dates(entry.get("dates", []), recent_updates.get(sym, []))
            entry["last_recent_refresh_on"] = today_iso
        cache["last_recent_refresh_on"] = today_iso

    sec_recent_symbols = [
        sym for sym in normalized_symbols
        if _earnings_symbol_needs_sec_recent_fallback(symbol_cache.get(sym, {}), today=today)
    ]
    if sec_recent_symbols:
        logging.info(
            "Checking SEC recent filings fallback for %d symbol(s) with stale latest earnings dates.",
            len(sec_recent_symbols),
        )
        sec_recent_updates = _collect_sec_recent_earnings_dates(
            sec_recent_symbols,
            today=today,
            lookback_days=SEC_RECENT_EARNINGS_LOOKBACK_DAYS,
        )
        sec_merge_count = 0
        for sym in sec_recent_symbols:
            sec_dates = sec_recent_updates.get(sym, [])
            if not sec_dates:
                continue
            entry = symbol_cache.setdefault(sym, _normalize_earnings_cache_entry({}))
            before_dates = list(entry.get("dates", []))
            entry["dates"] = _merge_earnings_dates(before_dates, sec_dates)
            if entry["dates"] != before_dates:
                sec_merge_count += 1
        if sec_merge_count:
            logging.info(
                "Merged SEC recent filing dates into %d symbol earnings history entries.",
                sec_merge_count,
            )

    deep_refresh_symbols = [
        sym for sym in normalized_symbols
        if _earnings_symbol_needs_deep_refresh(symbol_cache.get(sym, {}), today=today)
    ]
    if deep_refresh_symbols:
        logging.info(
            f"Refreshing deep earnings history for {len(deep_refresh_symbols)} symbol(s) "
            f"({EARNINGS_DEEP_LOOKBACK_DAYS} days)."
        )
        deep_updates = collect_earnings_dates(
            deep_refresh_symbols,
            lookback_days=EARNINGS_DEEP_LOOKBACK_DAYS,
            base_sleep=0.15,
        )
        for sym in deep_refresh_symbols:
            entry = symbol_cache.setdefault(sym, _normalize_earnings_cache_entry({}))
            entry["dates"] = _merge_earnings_dates(entry.get("dates", []), deep_updates.get(sym, []))
            entry["last_deep_refresh_on"] = today_iso

        yf_refresh_symbols = [
            sym for sym in deep_refresh_symbols
            if _earnings_symbol_needs_yf_refresh(symbol_cache.get(sym, {}), today=today)
        ]
        if yf_refresh_symbols and _can_attempt_yf_earnings_lookup(log_once=True):
            logging.info(
                f"Supplementing stale/incomplete earnings history with yfinance for {len(yf_refresh_symbols)} symbol(s)."
            )
            for sym in yf_refresh_symbols:
                entry = symbol_cache.setdefault(sym, _normalize_earnings_cache_entry({}))
                yf_dates = yf_earnings_dates(sym)
                if yf_dates:
                    entry["dates"] = _merge_earnings_dates(entry.get("dates", []), yf_dates)
                    _record_shared_yfinance_dates_safely(sym, yf_dates)
                entry["last_yf_refresh_on"] = today_iso

    try:
        refreshed_shared_dates = get_shared_past_earnings_dates(
            normalized_symbols,
            as_of=today,
            limit=EARNINGS_HISTORY_LIMIT,
        )
    except Exception as exc:
        logging.warning("Failed rereading shared earnings history after refresh: %s", exc)
        refreshed_shared_dates = {}
    for sym in normalized_symbols:
        dates = refreshed_shared_dates.get(sym, [])
        if not dates:
            continue
        entry = symbol_cache.setdefault(sym, _normalize_earnings_cache_entry({}))
        entry["dates"] = _merge_earnings_dates(entry.get("dates", []), dates)

    save_earnings_date_cache(cache)
    return {
        sym: _normalize_earnings_dates(symbol_cache.get(sym, {}).get("dates", []), today=today)
        for sym in normalized_symbols
    }

