def assess_adverse_entry_candle(
    daily_rows,
    last_trade_date,
    side: str,
    atr20: float | None,
) -> dict:
    result = {
        "adverse_entry_candle": False,
        "adverse_entry_candle_note": "",
        "adverse_entry_wick_ratio": None,
        "adverse_entry_close_position": None,
        "adverse_entry_range_atr": None,
    }
    if not daily_rows or not last_trade_date:
        return result

    target = last_trade_date.isoformat() if hasattr(last_trade_date, "isoformat") else str(last_trade_date)
    relevant = [row for row in daily_rows if str(row.get("date") or "") == target]
    if not relevant:
        return result
    candle = relevant[-1]
    open_value = _coerce_float(candle.get("open"))
    high_value = _coerce_float(candle.get("high"))
    low_value = _coerce_float(candle.get("low"))
    close_value = _coerce_float(candle.get("close"))
    if None in (open_value, high_value, low_value, close_value):
        return result

    range_size = float(high_value) - float(low_value)
    if range_size <= 0:
        return result
    body_size = abs(float(close_value) - float(open_value))
    upper_wick = max(0.0, float(high_value) - max(float(open_value), float(close_value)))
    lower_wick = max(0.0, min(float(open_value), float(close_value)) - float(low_value))
    close_position = (float(close_value) - float(low_value)) / range_size
    range_atr = (range_size / float(atr20)) if atr20 is not None and atr20 > 0 else None
    body_range_ratio = body_size / range_size
    normalized_side = normalize_side(side)

    if normalized_side == "SHORT":
        adverse_wick = lower_wick
        wick_ratio = lower_wick / range_size
        bad_close = close_position >= PRIORITY_ADVERSE_REJECTION_CLOSE_POSITION_MIN
        bad_body = float(close_value) > float(open_value)
        close_label = "high"
        wick_label = "lower tail"
    else:
        adverse_wick = upper_wick
        wick_ratio = upper_wick / range_size
        bad_close = close_position <= PRIORITY_ADVERSE_REJECTION_CLOSE_POSITION_MAX
        bad_body = float(close_value) < float(open_value)
        close_label = "low"
        wick_label = "upper wick"

    large_enough = range_atr is None or range_atr >= PRIORITY_ADVERSE_REJECTION_MIN_RANGE_ATR
    wick_rejection = (
        wick_ratio >= PRIORITY_ADVERSE_REJECTION_MIN_WICK_RANGE_RATIO
        and bad_close
        and large_enough
    )
    close_rejection = (
        bad_body
        and bad_close
        and body_range_ratio >= PRIORITY_ADVERSE_REJECTION_MIN_BODY_RANGE_RATIO
        and large_enough
    )

    result["adverse_entry_wick_ratio"] = round(float(wick_ratio), 3)
    result["adverse_entry_close_position"] = round(float(close_position), 3)
    result["adverse_entry_range_atr"] = None if range_atr is None else round(float(range_atr), 3)
    if not (wick_rejection or close_rejection):
        return result

    note_bits = []
    if wick_rejection:
        note_bits.append(f"big {wick_label} rejection ({wick_ratio:.0%} of range)")
    if close_rejection:
        note_bits.append(f"closed near {close_label} on adverse body")
    if range_atr is not None:
        note_bits.append(f"range={range_atr:.2f} ATR")
    result["adverse_entry_candle"] = True
    result["adverse_entry_candle_note"] = "; ".join(note_bits)
    return result

def compute_weekly_indicator_frame(df: pd.DataFrame) -> pd.DataFrame:
    if df is None or df.empty:
        return pd.DataFrame()

    work = df.copy()
    work["datetime"] = pd.to_datetime(work["datetime"], errors="coerce")
    work = work.dropna(subset=["datetime"]).sort_values("datetime")
    if work.empty:
        return pd.DataFrame()
    for column in ("open", "high", "low", "close", "volume"):
        work[column] = pd.to_numeric(work[column], errors="coerce")
    work = work.dropna(subset=["open", "high", "low", "close"])
    if work.empty:
        return pd.DataFrame()

    weekly = (
        work.set_index("datetime")
        .resample("W-FRI")
        .agg(
            {
                "open": "first",
                "high": "max",
                "low": "min",
                "close": "last",
                "volume": "sum",
            }
        )
        .dropna(subset=["open", "high", "low", "close"])
        .reset_index()
    )
    weekly["close_num"] = pd.to_numeric(weekly["close"], errors="coerce")
    weekly["high_num"] = pd.to_numeric(weekly["high"], errors="coerce")
    weekly["low_num"] = pd.to_numeric(weekly["low"], errors="coerce")
    for period in (20, 50, 100):
        weekly[f"sma_{period}"] = weekly["close_num"].rolling(period).mean()
        weekly[f"sma_{period}_prev"] = weekly[f"sma_{period}"].shift(1)
    weekly["ema_15"] = weekly["close_num"].ewm(span=15, adjust=False).mean()
    weekly["high_52w"] = weekly["high_num"].rolling(52, min_periods=1).max()
    weekly["trade_date"] = pd.to_datetime(weekly["datetime"]).dt.date.astype(str)
    return weekly

def _top_pattern_level_test(
    *,
    low_value: float | None,
    close_value: float | None,
    level_value: float | None,
    atr_value: float | None,
    tolerance_atr: float = TOP_PATTERN_DAILY_ENTRY_TOL_ATR,
) -> bool:
    low_value = _coerce_float(low_value)
    close_value = _coerce_float(close_value)
    level_value = _coerce_float(level_value)
    atr_value = _coerce_float(atr_value)
    if low_value is None or close_value is None or level_value is None:
        return False
    tolerance = max(0.0, float(atr_value or 0.0) * float(tolerance_atr))
    return float(low_value) <= float(level_value) + tolerance and float(close_value) >= float(level_value)

def analyze_top_pattern_setup(
    df: pd.DataFrame,
    *,
    side: str,
    current_anchor_meta: dict | None = None,
    indicator_frame: pd.DataFrame | None = None,
    atr20: float | None = None,
) -> dict:
    result = {
        "watch": False,
        "favorite_signal": False,
        "signal": "",
        "setup_family": "",
        "score_bonus": 0,
        "entry_trigger": "",
        "entry_triggers": [],
        "entry_level": None,
        "weekly_return_13w_pct": None,
        "weekly_return_26w_pct": None,
        "weekly_pullback_from_52w_high_pct": None,
        "weekly_ema15_hold": False,
        "weekly_ema15_hold_ratio": None,
        "weekly_above_sma100": False,
        "weekly_sma50_retest_recent": False,
        "daily_sma50_reclaim": False,
        "daily_sma50_bounce": False,
        "weekly_sma50_entry": False,
        "avwape_retest": False,
        "note": "",
    }
    if normalize_side(side) != "LONG" or df is None or df.empty:
        return result

    weekly = compute_weekly_indicator_frame(df)
    if weekly.empty or len(weekly) < TOP_PATTERN_WEEKLY_MIN_BARS:
        return result
    weekly = weekly.reset_index(drop=True)
    latest_week = weekly.iloc[-1]
    latest_week_close = _coerce_float(latest_week.get("close_num", latest_week.get("close")))
    latest_week_high52 = _coerce_float(latest_week.get("high_52w"))
    latest_week_ema15 = _coerce_float(latest_week.get("ema_15"))
    latest_week_sma50 = _coerce_float(latest_week.get("sma_50"))
    latest_week_sma100 = _coerce_float(latest_week.get("sma_100"))
    if latest_week_close is None or latest_week_ema15 is None:
        return result

    ema_window = weekly.dropna(subset=["close_num", "ema_15"]).tail(TOP_PATTERN_WEEKLY_EMA15_RATIO_LOOKBACK)
    if ema_window.empty:
        return result
    ema_hold_ratio = float((ema_window["close_num"] >= ema_window["ema_15"]).mean())
    recent_ema_window = ema_window.tail(TOP_PATTERN_WEEKLY_EMA15_HOLD_WEEKS)
    ema15_recent_hold = bool(
        len(recent_ema_window) >= TOP_PATTERN_WEEKLY_EMA15_HOLD_WEEKS
        and (recent_ema_window["close_num"] >= recent_ema_window["ema_15"]).all()
    )

    close_13 = _coerce_float(weekly.iloc[-14].get("close_num")) if len(weekly) >= 14 else None
    close_26 = _coerce_float(weekly.iloc[-27].get("close_num")) if len(weekly) >= 27 else None
    return_13 = (
        ((float(latest_week_close) - float(close_13)) / float(close_13)) * 100
        if close_13 not in (None, 0)
        else None
    )
    return_26 = (
        ((float(latest_week_close) - float(close_26)) / float(close_26)) * 100
        if close_26 not in (None, 0)
        else None
    )
    pullback_52w = (
        ((float(latest_week_high52) - float(latest_week_close)) / float(latest_week_high52)) * 100
        if latest_week_high52 not in (None, 0)
        else None
    )
    going_crazy = bool(
        (return_13 is not None and float(return_13) >= TOP_PATTERN_WEEKLY_MIN_13W_RETURN_PCT)
        or (return_26 is not None and float(return_26) >= TOP_PATTERN_WEEKLY_MIN_26W_RETURN_PCT)
    )
    near_high = bool(pullback_52w is not None and float(pullback_52w) <= TOP_PATTERN_MAX_PULLBACK_FROM_52W_HIGH_PCT)
    above_sma100 = bool(
        latest_week_sma100 is not None
        and float(latest_week_close) >= float(latest_week_sma100)
    )
    weekly_sma50_rising = bool(
        latest_week_sma50 is not None
        and _coerce_float(latest_week.get("sma_50_prev")) is not None
        and float(latest_week_sma50) >= float(_coerce_float(latest_week.get("sma_50_prev")))
    )
    weekly_sma50_retest_recent = False
    if latest_week_sma50 is not None:
        for _, week in weekly.tail(8).iterrows():
            week_low = _coerce_float(week.get("low_num", week.get("low")))
            week_close = _coerce_float(week.get("close_num", week.get("close")))
            week_sma50 = _coerce_float(week.get("sma_50"))
            if week_low is None or week_close is None or week_sma50 is None:
                continue
            if float(week_low) <= float(week_sma50) * 1.04 and float(week_close) >= float(week_sma50):
                weekly_sma50_retest_recent = True
                break

    top_structure = bool(
        ema15_recent_hold
        and ema_hold_ratio >= TOP_PATTERN_WEEKLY_EMA15_MIN_RATIO
        and going_crazy
        and near_high
    )
    if not top_structure:
        return result

    work = indicator_frame.copy() if isinstance(indicator_frame, pd.DataFrame) and not indicator_frame.empty else compute_indicator_frame(df)
    if work.empty:
        return result
    work = work.reset_index(drop=True)
    latest = work.iloc[-1]
    previous = work.iloc[-2] if len(work) >= 2 else pd.Series(dtype=object)
    latest_close = _coerce_float(latest.get("close_num", latest.get("close")))
    latest_low = _coerce_float(latest.get("low_num", latest.get("low")))
    daily_sma50 = _coerce_float(latest.get("sma_50"))
    prev_close = _coerce_float(previous.get("close_num", previous.get("close")))
    prev_sma50 = _coerce_float(previous.get("sma_50"))
    atr_value = _coerce_float(atr20) or _coerce_float(latest.get("atr_20"))
    current_vwap = _anchor_level_value(current_anchor_meta or {}, "AVWAPE")

    daily_sma50_bounce = _top_pattern_level_test(
        low_value=latest_low,
        close_value=latest_close,
        level_value=daily_sma50,
        atr_value=atr_value,
    )
    daily_sma50_reclaim = bool(
        latest_close is not None
        and daily_sma50 is not None
        and prev_close is not None
        and prev_sma50 is not None
        and float(prev_close) < float(prev_sma50)
        and float(latest_close) >= float(daily_sma50)
    )
    weekly_sma50_entry = _top_pattern_level_test(
        low_value=latest_low,
        close_value=latest_close,
        level_value=latest_week_sma50,
        atr_value=atr_value,
    )
    avwape_retest = _top_pattern_level_test(
        low_value=latest_low,
        close_value=latest_close,
        level_value=current_vwap,
        atr_value=atr_value,
    )

    entry_triggers = []
    entry_level = None
    score_bonus = TOP_PATTERN_SCORE_BONUS
    if daily_sma50_reclaim:
        entry_triggers.append("daily_50sma_reclaim")
        entry_level = daily_sma50
        score_bonus += TOP_PATTERN_SMA50_ENTRY_BONUS
    if daily_sma50_bounce:
        entry_triggers.append("daily_50sma_bounce")
        entry_level = entry_level if entry_level is not None else daily_sma50
        score_bonus += TOP_PATTERN_SMA50_ENTRY_BONUS
    if weekly_sma50_entry:
        entry_triggers.append("weekly_50sma_test")
        entry_level = entry_level if entry_level is not None else latest_week_sma50
        score_bonus += TOP_PATTERN_WEEKLY_SMA50_ENTRY_BONUS
    if avwape_retest:
        entry_triggers.append("avwape_test")
        entry_level = entry_level if entry_level is not None else current_vwap
        score_bonus += TOP_PATTERN_AVWAPE_ENTRY_BONUS
    if above_sma100:
        score_bonus += TOP_PATTERN_WEEKLY_SMA100_BONUS

    note_parts = [
        "TOP weekly trend",
        f"13w={return_13:+.1f}%" if return_13 is not None else "",
        f"26w={return_26:+.1f}%" if return_26 is not None else "",
        f"weekly EMA15 hold={ema_hold_ratio:.0%}",
    ]
    if above_sma100:
        note_parts.append("above weekly SMA100")
    if weekly_sma50_retest_recent:
        note_parts.append("recent weekly 50SMA support")
    if weekly_sma50_rising:
        note_parts.append("weekly 50SMA rising")
    if entry_triggers:
        note_parts.append("entry=" + ",".join(entry_triggers))
    else:
        note_parts.append("tracking for 50SMA/AVWAPE entry")

    result.update(
        {
            "watch": True,
            "favorite_signal": bool(entry_triggers),
            "signal": TOP_PATTERN_SIGNAL if entry_triggers else "",
            "setup_family": TOP_PATTERN_FAMILY if entry_triggers else TOP_PATTERN_TRACKING_FAMILY,
            "score_bonus": int(score_bonus if entry_triggers else max(0, score_bonus // 2)),
            "entry_trigger": entry_triggers[0] if entry_triggers else "",
            "entry_triggers": entry_triggers,
            "entry_level": _coerce_float(entry_level),
            "weekly_return_13w_pct": None if return_13 is None else round(float(return_13), 3),
            "weekly_return_26w_pct": None if return_26 is None else round(float(return_26), 3),
            "weekly_pullback_from_52w_high_pct": None if pullback_52w is None else round(float(pullback_52w), 3),
            "weekly_ema15_hold": bool(ema15_recent_hold),
            "weekly_ema15_hold_ratio": round(float(ema_hold_ratio), 3),
            "weekly_above_sma100": bool(above_sma100),
            "weekly_sma50_retest_recent": bool(weekly_sma50_retest_recent),
            "daily_sma50_reclaim": bool(daily_sma50_reclaim),
            "daily_sma50_bounce": bool(daily_sma50_bounce),
            "weekly_sma50_entry": bool(weekly_sma50_entry),
            "avwape_retest": bool(avwape_retest),
            "note": "; ".join(part for part in note_parts if part),
        }
    )
    return result

def assess_vwap_range_confirmation(last_close, intraday_vwap, side, previous_day_range_summary: dict | None):
    close_value = _coerce_float(last_close)
    vwap_value = _coerce_float(intraday_vwap)
    previous_summary = previous_day_range_summary if isinstance(previous_day_range_summary, dict) else {}
    previous_day_high = _coerce_float(previous_summary.get("previous_day_high"))
    previous_day_low = _coerce_float(previous_summary.get("previous_day_low"))
    result = {
        "vwap_range_confirmation": False,
        "vwap_range_confirmation_bonus": 0,
        "vwap_range_confirmation_note": "",
    }
    if close_value is None or vwap_value is None:
        return result

    side = normalize_side(side)
    if (
        side == "LONG"
        and previous_day_high is not None
        and float(close_value) > float(vwap_value)
        and float(close_value) > float(previous_day_high)
    ):
        result["vwap_range_confirmation"] = True
        result["vwap_range_confirmation_bonus"] = PRIORITY_VWAP_RANGE_CONFIRMATION_SCORE_BONUS
        result["vwap_range_confirmation_note"] = (
            f"Holding above intraday VWAP {float(vwap_value):.2f} "
            f"and previous day high {float(previous_day_high):.2f} "
            f"(+{PRIORITY_VWAP_RANGE_CONFIRMATION_SCORE_BONUS})"
        )
    elif (
        side == "SHORT"
        and previous_day_low is not None
        and float(close_value) < float(vwap_value)
        and float(close_value) < float(previous_day_low)
    ):
        result["vwap_range_confirmation"] = True
        result["vwap_range_confirmation_bonus"] = PRIORITY_VWAP_RANGE_CONFIRMATION_SCORE_BONUS
        result["vwap_range_confirmation_note"] = (
            f"Holding below intraday VWAP {float(vwap_value):.2f} "
            f"and previous day low {float(previous_day_low):.2f} "
            f"(+{PRIORITY_VWAP_RANGE_CONFIRMATION_SCORE_BONUS})"
        )
    return result

def assess_daily_relative_strength(
    daily_rows,
    last_trade_date,
    side,
    spy_benchmark: dict | None,
    lookback_days: int = DAILY_RELATIVE_STRENGTH_LOOKBACK_DAYS,
) -> dict:
    result = {
        "daily_relative_strength_score": None,
        "daily_relative_strength_bonus": 0,
        "daily_relative_strength_note": "",
        "symbol_one_day_return_pct": None,
        "symbol_five_day_return_pct": None,
        "spy_one_day_return_pct": _coerce_float((spy_benchmark or {}).get("one_day_return_pct")),
        "spy_five_day_return_pct": _coerce_float((spy_benchmark or {}).get("five_day_return_pct")),
    }
    if not daily_rows or not last_trade_date or not isinstance(spy_benchmark, dict):
        return result
    target = last_trade_date.isoformat() if isinstance(last_trade_date, date) else str(last_trade_date)
    relevant = [row for row in daily_rows if str(row.get("date") or "") <= target]
    if len(relevant) < max(2, int(lookback_days) + 1):
        return result
    latest = relevant[-1]
    previous = relevant[-2]
    lookback = relevant[-(int(lookback_days) + 1)]
    latest_close = _coerce_float(latest.get("close"))
    previous_close = _coerce_float(previous.get("close"))
    lookback_close = _coerce_float(lookback.get("close"))
    symbol_one_day = (
        ((float(latest_close) - float(previous_close)) / float(previous_close)) * 100
        if latest_close is not None and previous_close not in (None, 0)
        else None
    )
    symbol_five_day = (
        ((float(latest_close) - float(lookback_close)) / float(lookback_close)) * 100
        if latest_close is not None and lookback_close not in (None, 0)
        else None
    )
    spy_one_day = result["spy_one_day_return_pct"]
    spy_five_day = result["spy_five_day_return_pct"]
    result["symbol_one_day_return_pct"] = None if symbol_one_day is None else round(float(symbol_one_day), 3)
    result["symbol_five_day_return_pct"] = None if symbol_five_day is None else round(float(symbol_five_day), 3)
    if symbol_one_day is None or symbol_five_day is None or spy_one_day is None or spy_five_day is None:
        return result

    one_day_excess = float(symbol_one_day) - float(spy_one_day)
    five_day_excess = float(symbol_five_day) - float(spy_five_day)
    rs_score = (0.35 * one_day_excess) + (0.65 * five_day_excess)
    normalized_side = normalize_side(side)
    directional_bonus = 0
    if normalized_side == "LONG" and rs_score >= DAILY_RELATIVE_STRENGTH_THRESHOLD:
        directional_bonus = DAILY_RELATIVE_STRENGTH_BONUS
    elif normalized_side == "SHORT" and rs_score <= -DAILY_RELATIVE_STRENGTH_THRESHOLD:
        directional_bonus = DAILY_RELATIVE_STRENGTH_WEAKNESS_BONUS

    if directional_bonus:
        direction_text = "stronger than SPY" if normalized_side == "LONG" else "weaker than SPY"
        note = (
            f"D1 {direction_text}: rs={rs_score:+.2f}, "
            f"1d excess={one_day_excess:+.2f}%, 5d excess={five_day_excess:+.2f}% "
            f"(+{directional_bonus})"
        )
    else:
        note = (
            f"D1 vs SPY neutral: rs={rs_score:+.2f}, "
            f"1d excess={one_day_excess:+.2f}%, 5d excess={five_day_excess:+.2f}%"
        )

    result.update(
        {
            "daily_relative_strength_score": round(float(rs_score), 3),
            "daily_relative_strength_bonus": int(directional_bonus),
            "daily_relative_strength_note": note,
        }
    )
    return result


def _daily_frame_to_rows(df: "pd.DataFrame | None") -> list[dict]:
    """Convert a normalized daily-bar DataFrame (columns datetime/open/high/low/
    close/volume) into the list-of-dict shape the dict-based helpers expect
    (``assess_daily_relative_strength`` / ``compute_atr_from_ohlc`` key off
    ``date``/``close``/``high``/``low``)."""
    if df is None or getattr(df, "empty", True):
        return []
    work = df.copy()
    work["date"] = pd.to_datetime(work["datetime"], errors="coerce").dt.date
    work = work.dropna(subset=["date"])
    rows: list[dict] = []
    for record in work[["date", "open", "high", "low", "close", "volume"]].to_dict("records"):
        rows.append(
            {
                "date": record["date"].isoformat(),
                "open": _coerce_float(record.get("open")),
                "high": _coerce_float(record.get("high")),
                "low": _coerce_float(record.get("low")),
                "close": _coerce_float(record.get("close")),
                "volume": _coerce_float(record.get("volume")),
            }
        )
    return rows


def build_daily_rows_cache(daily_frames_by_symbol: "dict | None") -> dict[str, dict]:
    """Convert each symbol's daily frame to rows + ATR20 + last_trade_date once.

    The universe-strength, HV-level and phase-6 enrichers each used to re-run
    ``_daily_frame_to_rows`` and ``compute_atr_from_ohlc`` per symbol. Building
    this cache a single time lets them share the result, removing two redundant
    full-frame conversions per symbol on every scan.
    """
    cache: dict[str, dict] = {}
    if not isinstance(daily_frames_by_symbol, dict):
        return cache
    for symbol, df in daily_frames_by_symbol.items():
        sym = str(symbol or "").strip().upper()
        if not sym:
            continue
        rows = _daily_frame_to_rows(df)
        if not rows:
            continue
        try:
            last_trade_date = date.fromisoformat(rows[-1]["date"])
        except (KeyError, TypeError, ValueError):
            continue
        cache[sym] = {
            "rows": rows,
            "last_trade_date": last_trade_date,
            "atr20": _coerce_float(compute_atr_from_ohlc(rows, last_trade_date)),
        }
    return cache


def _trailing_return_pct(daily_rows: list[dict], sessions: int) -> float | None:
    """Percent change in close over the last ``sessions`` trading sessions."""
    if not daily_rows or sessions <= 0 or len(daily_rows) < sessions + 1:
        return None
    last_close = _coerce_float(daily_rows[-1].get("close"))
    past_close = _coerce_float(daily_rows[-(sessions + 1)].get("close"))
    if last_close is None or past_close in (None, 0):
        return None
    return round(((float(last_close) - float(past_close)) / float(past_close)) * 100.0, 3)


def _weighted_excess_strength_score(
    one_day_return: float | None,
    five_day_return: float | None,
    benchmark_one_day: float | None,
    benchmark_five_day: float | None,
) -> float | None:
    one_day = _coerce_float(one_day_return)
    five_day = _coerce_float(five_day_return)
    benchmark_one = _coerce_float(benchmark_one_day)
    benchmark_five = _coerce_float(benchmark_five_day)
    if one_day is None or five_day is None or benchmark_one is None or benchmark_five is None:
        return None
    return round((0.35 * (float(one_day) - float(benchmark_one))) + (0.65 * (float(five_day) - float(benchmark_five))), 3)


def resample_intraday_bars_to_4h(hourly_df: pd.DataFrame | None) -> pd.DataFrame:
    """Build synthetic 4h bars from sequential 1h bars.

    IBKR has no native 4h bar size here; grouping every four completed 1h bars is
    deterministic for scanner tests and avoids exchange-session gap assumptions.
    """

    work = _normalize_intraday_bar_frame(hourly_df)
    if work.empty:
        return _empty_intraday_bar_frame()
    work = work.reset_index(drop=True)
    work["_group"] = [idx // 4 for idx in range(len(work))]
    grouped = (
        work.groupby("_group", as_index=False)
        .agg(
            {
                "datetime": "last",
                "open": "first",
                "high": "max",
                "low": "min",
                "close": "last",
                "volume": "sum",
            }
        )
        .dropna(subset=["datetime", "open", "high", "low", "close"])
    )
    return grouped[["datetime", "open", "high", "low", "close", "volume"]].reset_index(drop=True)


def _htf_indicator_frame(df: pd.DataFrame | None) -> pd.DataFrame:
    normalized = _normalize_intraday_bar_frame(df)
    if normalized.empty:
        return pd.DataFrame()
    return compute_indicator_frame(normalized)


def _htf_trend_label(indicator_frame: pd.DataFrame | None) -> str:
    if indicator_frame is None or indicator_frame.empty:
        return "NEUTRAL"
    work = indicator_frame.dropna(subset=["close_num"]).reset_index(drop=True)
    if work.empty:
        return "NEUTRAL"
    latest = work.iloc[-1]
    close_value = _coerce_float(latest.get("close_num", latest.get("close")))
    sma20 = _coerce_float(latest.get("sma_20"))
    sma20_prev = _coerce_float(latest.get("sma_20_prev"))
    sma50 = _coerce_float(latest.get("sma_50"))
    if close_value is None or sma20 is None:
        return "NEUTRAL"
    sma20_rising = sma20_prev is None or float(sma20) >= float(sma20_prev)
    sma20_falling = sma20_prev is None or float(sma20) <= float(sma20_prev)
    long_stack = float(close_value) >= float(sma20) and sma20_rising
    short_stack = float(close_value) <= float(sma20) and sma20_falling
    if sma50 is not None:
        long_stack = long_stack and float(sma20) >= float(sma50)
        short_stack = short_stack and float(sma20) <= float(sma50)
    if long_stack:
        return "UP"
    if short_stack:
        return "DOWN"
    return "NEUTRAL"


def _htf_row_timestamp(row: pd.Series | dict | None) -> str:
    if row is None:
        return ""
    value = row.get("datetime") if isinstance(row, (pd.Series, dict)) else None
    if value is None:
        value = row.get("trade_date") if isinstance(row, (pd.Series, dict)) else None
    if value is None:
        return ""
    if hasattr(value, "isoformat"):
        return value.isoformat()
    return str(value)


def _htf_recent_sma_retest(
    indicator_frame: pd.DataFrame | None,
    *,
    side: str,
    timeframe: str,
    lookback_bars: int = HTF_TREND_RETEST_LOOKBACK_BARS,
) -> dict | None:
    if indicator_frame is None or indicator_frame.empty:
        return None
    work = indicator_frame.reset_index(drop=True)
    normalized_side = normalize_side(side)
    last_idx = len(work) - 1
    first_idx = max(0, last_idx - max(1, int(lookback_bars or 1)) + 1)
    for idx in range(last_idx, first_idx - 1, -1):
        row = work.iloc[idx]
        close_value = _coerce_float(row.get("close_num", row.get("close")))
        high_value = _coerce_float(row.get("high_num", row.get("high")))
        low_value = _coerce_float(row.get("low_num", row.get("low")))
        atr_value = _coerce_float(row.get("atr_20"))
        if close_value is None or high_value is None or low_value is None:
            continue
        for period in HTF_TREND_SMA_PERIODS:
            level = _coerce_float(row.get(f"sma_{period}"))
            if level is None:
                continue
            tolerance = max(
                abs(float(level)) * HTF_TREND_FALLBACK_TOL_PCT,
                float(atr_value or 0.0) * HTF_TREND_RETEST_TOL_ATR,
            )
            if normalized_side == "SHORT":
                touched = float(high_value) >= float(level) - tolerance
                reclaimed = float(close_value) <= float(level)
            else:
                touched = float(low_value) <= float(level) + tolerance
                reclaimed = float(close_value) >= float(level)
            if touched and reclaimed:
                return {
                    "timeframe": timeframe,
                    "sma_label": f"SMA_{period}",
                    "sma_period": int(period),
                    "sma_level": round(float(level), 4),
                    "age_bars": int(last_idx - idx),
                    "bar_time": _htf_row_timestamp(row),
                }
    return None


def assess_htf_trend_context(
    hourly_df: pd.DataFrame | None,
    side: str,
    *,
    scoring_enabled: bool = False,
) -> dict:
    hourly = _normalize_intraday_bar_frame(hourly_df)
    result = {
        "htf_trend_1h": "NEUTRAL",
        "htf_trend_4h": "NEUTRAL",
        "htf_trend_aligned": False,
        "htf_retest_confirmed": False,
        "htf_retest_sma": "",
        "htf_retest_timeframes": "",
        "htf_retest_age_bars": None,
        "htf_intraday_bar_count": int(len(hourly)),
        "htf_4h_bar_count": 0,
        "htf_trend_score_bonus": 0,
        "htf_trend_note": "",
    }
    if hourly.empty:
        result["htf_trend_note"] = "No 1h bars available"
        return result

    four_hour = resample_intraday_bars_to_4h(hourly)
    result["htf_4h_bar_count"] = int(len(four_hour))
    hourly_indicators = _htf_indicator_frame(hourly)
    four_hour_indicators = _htf_indicator_frame(four_hour)
    one_hour_label = _htf_trend_label(hourly_indicators)
    four_hour_label = _htf_trend_label(four_hour_indicators)
    result["htf_trend_1h"] = one_hour_label
    result["htf_trend_4h"] = four_hour_label

    normalized_side = normalize_side(side)
    required_label = "DOWN" if normalized_side == "SHORT" else "UP"
    aligned = one_hour_label == required_label and four_hour_label == required_label
    result["htf_trend_aligned"] = bool(aligned)

    retests = []
    if one_hour_label == required_label:
        retest_1h = _htf_recent_sma_retest(hourly_indicators, side=normalized_side, timeframe="1h")
        if retest_1h:
            retests.append(retest_1h)
    if four_hour_label == required_label:
        retest_4h = _htf_recent_sma_retest(four_hour_indicators, side=normalized_side, timeframe="4h")
        if retest_4h:
            retests.append(retest_4h)

    retest_confirmed = bool(aligned and retests)
    result["htf_retest_confirmed"] = retest_confirmed
    if retests:
        result["htf_retest_sma"] = ";".join(
            f"{item['timeframe']}:{item['sma_label']}" for item in retests
        )
        result["htf_retest_timeframes"] = ";".join(item["timeframe"] for item in retests)
        result["htf_retest_age_bars"] = min(int(item.get("age_bars", 0) or 0) for item in retests)

    note_bits = [f"1h={one_hour_label}", f"4h={four_hour_label}"]
    if retests:
        note_bits.append("recent SMA retest " + result["htf_retest_sma"])
    if aligned and retest_confirmed:
        if scoring_enabled:
            result["htf_trend_score_bonus"] = HTF_TREND_SCORE_BONUS
            note_bits.append(f"+{HTF_TREND_SCORE_BONUS}")
        else:
            note_bits.append("score flag off")
    elif aligned:
        note_bits.append("aligned; no recent SMA retest")
    else:
        note_bits.append("not aligned")
    result["htf_trend_note"] = "; ".join(note_bits)
    return result


def _priority_row_has_active_setup(row: dict | None) -> bool:
    if not isinstance(row, dict):
        return False
    setup_family = str(row.get("setup_family") or "").strip().lower()
    return bool(
        row.get("has_favorite_signal")
        or row.get("favorite_signals")
        or row.get("favorite_zone")
        or row.get("extreme_move_watch")
        or row.get("sma_breakout_watch")
        or row.get("sma_breakout_confirmed")
        or row.get("top_pattern_watch")
        or row.get("top_pattern_entry")
        or setup_family not in {"", "general"}
    )


def _build_htf_trend_study_row(priority_row: dict, context: dict) -> dict:
    study_row = dict(priority_row)
    existing_tags = list(study_row.get("setup_tags") or [])
    study_row.update(context)
    study_row["priority_bucket"] = HTF_TREND_STUDY_BUCKET
    study_row["is_favorite_setup"] = False
    study_row["is_near_favorite_zone"] = False
    study_row["setup_family"] = HTF_TREND_STUDY_FAMILY
    study_row["study_kind"] = HTF_TREND_STUDY_FAMILY
    study_row["setup_tags"] = list(dict.fromkeys([*existing_tags, "HTF_TREND_RETEST"]))
    study_row["favorite_signals"] = []
    study_row["context_signals"] = list(dict.fromkeys([*(study_row.get("context_signals") or []), "HTF_TREND_RETEST"]))
    study_row["has_favorite_signal"] = False
    htf_note = str(context.get("htf_trend_note") or "")
    study_row["score_bonus_note"] = htf_note
    if not str(study_row.get("retest_note") or "").strip():
        study_row["retest_note"] = htf_note
    return study_row


def enrich_priority_rows_with_htf_trend_context(
    priority_rows: list[dict] | None,
    *,
    ib: IBApi | None = None,
    intraday_frames_by_symbol: dict[str, pd.DataFrame] | None = None,
    scoring_enabled: bool | None = None,
    ai_state: dict | None = None,
    feature_rows_by_symbol: dict | None = None,
) -> list[dict]:
    if not priority_rows:
        return []
    if scoring_enabled is None:
        scoring_enabled = bool(get_priority_feature_flags().get(HTF_TREND_SCORING_FLAG))
    intraday_cache = dict(intraday_frames_by_symbol or {})
    ai_symbols = ai_state.get("symbols") if isinstance(ai_state, dict) else {}
    if not isinstance(ai_symbols, dict):
        ai_symbols = {}
    feature_rows_by_symbol = feature_rows_by_symbol if isinstance(feature_rows_by_symbol, dict) else {}
    htf_fields = (
        "htf_trend_1h",
        "htf_trend_4h",
        "htf_trend_aligned",
        "htf_retest_confirmed",
        "htf_retest_sma",
        "htf_retest_timeframes",
        "htf_retest_age_bars",
        "htf_intraday_bar_count",
        "htf_4h_bar_count",
        "htf_trend_score_bonus",
        "htf_trend_note",
    )
    study_rows: list[dict] = []
    for row in priority_rows:
        if not isinstance(row, dict) or not _priority_row_has_active_setup(row):
            continue
        symbol = str(row.get("symbol") or "").strip().upper()
        if not symbol:
            continue
        if symbol in intraday_cache:
            hourly_df = intraday_cache.get(symbol)
        else:
            try:
                hourly_df = fetch_intraday_bars(ib, symbol)
            except Exception as exc:
                logging.warning("%s: HTF trend intraday fetch failed (%s).", symbol, exc)
                hourly_df = _empty_intraday_bar_frame()
            intraday_cache[symbol] = hourly_df

        context = assess_htf_trend_context(
            hourly_df,
            row.get("side") or "",
            scoring_enabled=bool(scoring_enabled),
        )
        row.update(context)
        bonus = int(context.get("htf_trend_score_bonus", 0) or 0)
        if bonus:
            row["score"] = float(row.get("score", 0.0) or 0.0) + float(bonus)

        symbol_entry = ai_symbols.get(symbol)
        if isinstance(symbol_entry, dict):
            for field in htf_fields:
                symbol_entry[field] = row.get(field)
            symbol_entry["priority_score"] = row.get("score")
        feature_row = feature_rows_by_symbol.get(symbol)
        if isinstance(feature_row, dict):
            for field in htf_fields:
                feature_row[field] = row.get(field)
            feature_row["priority_score"] = row.get("score")

        if context.get("htf_retest_confirmed"):
            study_rows.append(_build_htf_trend_study_row(row, context))
    return study_rows


def _hv_level_last_trade_date(df: pd.DataFrame | None) -> str:
    work = df.copy() if isinstance(df, pd.DataFrame) and not df.empty else pd.DataFrame()
    if work.empty or "datetime" not in work.columns:
        return datetime.now().date().isoformat()
    dates = pd.to_datetime(work["datetime"], errors="coerce").dropna()
    if dates.empty:
        return datetime.now().date().isoformat()
    return dates.iloc[-1].date().isoformat()


def _hv_level_first_trade_date(df: pd.DataFrame | None) -> str:
    work = df if isinstance(df, pd.DataFrame) else pd.DataFrame()
    if work.empty or "datetime" not in work.columns:
        return ""
    dates = pd.to_datetime(work["datetime"], errors="coerce").dropna()
    if dates.empty:
        return ""
    return dates.iloc[0].date().isoformat()


def _hv_level_atr20_for_frame(df: pd.DataFrame | None) -> float | None:
    rows = _daily_frame_to_rows(df)
    if not rows:
        return None
    try:
        last_trade_date = date.fromisoformat(rows[-1]["date"])
    except (KeyError, TypeError, ValueError):
        return None
    return _coerce_float(compute_atr_from_ohlc(rows, last_trade_date))


def _fetch_deep_daily_bars_for_levels(
    ib: "IBApi | None", symbol: str, days: int
) -> "pd.DataFrame | None":
    """One-time long-history daily fetch for the level backfill.

    Uses the live fetch directly (not ``fetch_daily_bars``) so the multi-year pull
    is NOT written into the rolling daily-bar cache; otherwise every later scan
    would re-extract levels and indicators over years of bars and slow the whole
    pipeline. The deep frame is consumed once to seed the level store and dropped.
    """
    sym = str(symbol or "").strip().upper()
    if not sym:
        return None
    try:
        deep = _fetch_live_daily_bars(ib, sym, max(int(days), HV_LEVEL_DEEP_BACKFILL_DAYS))
    except Exception as exc:
        logging.warning("%s: deep level backfill fetch failed (%s).", sym, exc)
        return None
    if deep is None or getattr(deep, "empty", True):
        return None
    return deep


def _level_store_needs_deep_backfill(store: dict | None) -> bool:
    """True until a symbol has had its one-time multi-year backfill recorded."""
    if not isinstance(store, dict):
        return True
    marker = store.get("deep_backfill")
    return not (isinstance(marker, dict) and bool(marker.get("done")))


def build_hv_level_store_for_symbol(
    symbol: str,
    df: pd.DataFrame | None,
    *,
    atr20: float | None = None,
    earnings_dates: list[str] | None = None,
    levels_dir: Path | None = None,
    persist: bool = True,
    existing_store: dict | None = None,
    cumulative_stats: bool = True,
    mark_deep_backfill: bool = False,
    backfill_lookback_days: int | None = None,
) -> dict:
    sym = str(symbol or "").strip().upper()
    if not sym:
        return default_level_store("")
    # Normalize the daily frame once and reuse it across extract/span-B/touch-stats
    # instead of letting each helper re-run the copy/coerce/sort pipeline.
    work = normalize_levels_frame(df)
    atr_value = _coerce_float(atr20) or _hv_level_atr20_for_frame(work)
    levels_root = Path(levels_dir or MASTER_AVWAP_LEVELS_DIR)
    path = level_store_path(levels_root, sym)
    store_in = existing_store if isinstance(existing_store, dict) else load_level_store(path, sym)
    candidates = extract_hv_levels(
        work,
        atr_value,
        green=HV_RELVOL_GREEN,
        red=HV_RELVOL_RED,
        vol_sma=HV_VOL_SMA,
        earnings_dates=earnings_dates or [],
    )
    clusters = cluster_hv_levels(candidates, atr_value, tol_frac=LEVEL_TOL_ATR_FRACTION)
    cloud_flats = compute_span_b_flats(work, atr_value)
    last_trade_date = _hv_level_last_trade_date(work)
    store = merge_levels_into_store(
        store_in,
        [*clusters, *cloud_flats],
        symbol=sym,
        atr20=atr_value,
        updated=last_trade_date,
    )
    if cumulative_stats:
        # Add only the unseen bars to the stored running totals; a deep backfill
        # resets and counts the full multi-year window once.
        store["levels"] = accumulate_level_touch_stats(
            store.get("levels", []),
            work,
            atr_value,
            tol_frac=LEVEL_TOL_ATR_FRACTION,
            break_atr=LEVEL_BREAK_ATR,
            reset=bool(mark_deep_backfill),
        )
    else:
        store["levels"] = recompute_level_touch_stats(
            store.get("levels", []),
            work,
            atr_value,
            tol_frac=LEVEL_TOL_ATR_FRACTION,
            break_atr=LEVEL_BREAK_ATR,
        )
    if mark_deep_backfill:
        first_seen = ""
        if not work.empty and "datetime" in work.columns:
            first_seen = _hv_level_first_trade_date(work)
        store["deep_backfill"] = {
            "done": True,
            "completed_on": datetime.now().date().isoformat(),
            "from_date": first_seen,
            "through_date": last_trade_date,
            "lookback_days": int(backfill_lookback_days or HV_LEVEL_DEEP_BACKFILL_DAYS),
            "bar_count": int(len(work)),
        }
    if persist:
        save_level_store(path, store)
    return store


def _hv_level_summary(levels: list[dict], limit: int = 3) -> str:
    parts = []
    for level in levels[: max(1, int(limit or 1))]:
        price = _coerce_float(level.get("price"))
        bucket = str(level.get("bucket") or "").strip()
        distance_atr = _coerce_float(level.get("distance_atr"))
        if price is None:
            continue
        distance_text = "" if distance_atr is None else f" {distance_atr:+.2f}ATR"
        parts.append(f"{bucket}@{price:.2f}{distance_text}".strip())
    return ", ".join(parts)


def _hv_level_block_score_delta(blocking: list[dict]) -> tuple[float, dict | None]:
    """Negative score delta for the strongest respected level in the entry path.

    Picks the blocking level with the highest cumulative-respect conviction and
    scales the penalty by that conviction and how point-blank the entry is (the
    closer to the level, the larger the penalty). Returns ``(delta, level)``.
    """
    if not blocking:
        return 0.0, None
    top = max(blocking, key=lambda level: level_conviction(level))
    conviction = level_conviction(top)
    if conviction <= 0:
        return 0.0, None
    tol_atr = float(LEVEL_TOL_ATR_FRACTION) or 0.0
    abs_dist_atr = abs(_coerce_float(top.get("distance_atr")) or 0.0)
    proximity = 1.0 - (abs_dist_atr / tol_atr) if tol_atr > 0 else 1.0
    proximity = max(0.0, min(1.0, proximity))
    proximity_factor = HV_LEVEL_BLOCK_PROXIMITY_FLOOR + (1.0 - HV_LEVEL_BLOCK_PROXIMITY_FLOOR) * proximity
    conviction_factor = min(1.0, conviction / float(HV_LEVEL_BLOCK_CONVICTION_FULL or 1.0))
    delta = -round(HV_LEVEL_BLOCK_PENALTY_MAX * conviction_factor * proximity_factor, 1)
    return delta, top


def _hv_level_context_for_entry(
    store: dict,
    *,
    side: str,
    entry_price: float | None,
    atr20: float | None,
    last_trade_date: str = "",
    scoring_enabled: bool = False,
) -> dict:
    nearby = levels_near(
        store,
        entry_price,
        atr20,
        tol_frac=LEVEL_TOL_ATR_FRACTION,
        min_strength=HV_LEVEL_MIN_STUDY_STRENGTH,
        kinds={"hv_horizontal"},
    )
    blocking = levels_blocking_entry(
        store,
        side,
        entry_price,
        atr20,
        tol_frac=LEVEL_TOL_ATR_FRACTION,
        min_strength=1.0,
        kinds={"hv_horizontal"},
    )
    nearest = nearby[0] if nearby else {}
    last_trade_text = str(last_trade_date or "")
    break_today = bool(last_trade_text) and any(
        str(level.get("last_break") or "") == last_trade_text for level in nearby
    )
    score_delta, penalized = (0.0, None)
    if scoring_enabled and not break_today:
        # A level being broken on the latest bar is a different (breakout) setup,
        # so only penalize entries into an intact respected wall.
        score_delta, penalized = _hv_level_block_score_delta(blocking)
    note = ""
    if nearby:
        label = "blocking" if blocking else "nearby"
        note = f"HV level {label}: {_hv_level_summary(blocking or nearby)}"
        if break_today:
            note += "; latest bar broke a stored level"
    if score_delta and penalized is not None:
        respect = int(penalized.get("respect_count", 0) or 0)
        note += (
            f"; entering at respected level @{_coerce_float(penalized.get('price')):.2f} "
            f"(respected {respect}x, conviction {level_conviction(penalized):.2f}) {score_delta:+.1f}"
        )
    return {
        "hv_level_nearby_count": int(len(nearby)),
        "hv_level_blocking_count": int(len(blocking)),
        "hv_level_break_today": bool(break_today),
        "hv_level_nearest_price": _coerce_float(nearest.get("price")),
        "hv_level_nearest_bucket": nearest.get("bucket", "") if nearest else "",
        "hv_level_nearest_distance_atr": _coerce_float(nearest.get("distance_atr")),
        "hv_level_nearby_summary": _hv_level_summary(nearby),
        "hv_level_blocking_summary": _hv_level_summary(blocking),
        "hv_level_score_delta": float(score_delta),
        "hv_level_score_note": note if score_delta else "",
        "hv_level_note": note,
    }


def _build_hv_level_study_row(priority_row: dict, context: dict) -> dict:
    study_row = dict(priority_row)
    study_row.update(context)
    break_today = bool(context.get("hv_level_break_today"))
    family = HV_LEVEL_BREAK_STUDY_FAMILY if break_today else HV_LEVEL_STUDY_FAMILY
    tag = "HV_LEVEL_BREAK" if break_today else "HV_LEVEL_PROXIMITY"
    existing_tags = list(study_row.get("setup_tags") or [])
    study_row["priority_bucket"] = HV_LEVEL_STUDY_BUCKET
    study_row["is_favorite_setup"] = False
    study_row["is_near_favorite_zone"] = False
    study_row["setup_family"] = family
    study_row["study_kind"] = family
    study_row["setup_tags"] = list(dict.fromkeys([*existing_tags, tag]))
    study_row["favorite_signals"] = []
    study_row["context_signals"] = list(dict.fromkeys([*(study_row.get("context_signals") or []), tag]))
    study_row["has_favorite_signal"] = False
    note = str(context.get("hv_level_note") or "")
    study_row["score_bonus_note"] = note
    if not str(study_row.get("retest_note") or "").strip():
        study_row["retest_note"] = note
    return study_row


def enrich_priority_rows_with_hv_levels(
    priority_rows: list[dict] | None,
    daily_frames_by_symbol: dict[str, pd.DataFrame] | None,
    *,
    earnings_dates_by_symbol: dict[str, list[str]] | None = None,
    ai_state: dict | None = None,
    feature_rows_by_symbol: dict | None = None,
    levels_dir: Path | None = None,
    persist: bool = True,
    stores_out: dict[str, dict] | None = None,
    daily_rows_cache: dict | None = None,
    ib: "IBApi | None" = None,
    deep_backfill_enabled: bool | None = None,
    cumulative_stats: bool | None = None,
    deep_backfill_days: int | None = None,
    max_backfills_per_run: int | None = None,
    scoring_enabled: bool | None = None,
) -> list[dict]:
    frames = daily_frames_by_symbol if isinstance(daily_frames_by_symbol, dict) else {}
    stores_by_symbol: dict[str, dict] = stores_out if isinstance(stores_out, dict) else {}
    earnings_dates_by_symbol = earnings_dates_by_symbol if isinstance(earnings_dates_by_symbol, dict) else {}
    daily_rows_cache = daily_rows_cache if isinstance(daily_rows_cache, dict) else {}

    flags = get_priority_feature_flags()
    if cumulative_stats is None:
        cumulative_stats = bool(flags.get(HV_LEVEL_CUMULATIVE_STATS_FLAG, True))
    if deep_backfill_enabled is None:
        deep_backfill_enabled = bool(flags.get(HV_LEVEL_DEEP_BACKFILL_FLAG, True))
    if scoring_enabled is None:
        scoring_enabled = bool(flags.get(HV_LEVEL_SCORING_FLAG))
    backfill_days = int(deep_backfill_days or HV_LEVEL_DEEP_BACKFILL_DAYS)
    backfill_budget = (
        int(max_backfills_per_run) if max_backfills_per_run is not None else HV_LEVEL_DEEP_BACKFILL_MAX_PER_RUN
    )
    levels_root = Path(levels_dir or MASTER_AVWAP_LEVELS_DIR)

    for symbol, df in frames.items():
        sym = str(symbol or "").strip().upper()
        if not sym:
            continue
        cached = daily_rows_cache.get(sym) if daily_rows_cache else None
        cached_atr = cached.get("atr20") if isinstance(cached, dict) else None
        try:
            existing_store = load_level_store(level_store_path(levels_root, sym), sym)
            build_df = df
            mark_backfill = False
            build_atr = cached_atr
            if (
                deep_backfill_enabled
                and ib is not None
                and backfill_budget > 0
                and _level_store_needs_deep_backfill(existing_store)
            ):
                deep_df = _fetch_deep_daily_bars_for_levels(ib, sym, backfill_days)
                if deep_df is not None and len(deep_df) >= HV_LEVEL_DEEP_BACKFILL_MIN_BARS:
                    build_df = deep_df
                    mark_backfill = True
                    build_atr = None  # recompute ATR from the deep frame's own tail
                    backfill_budget -= 1
                    logging.info(
                        "%s: seeding multi-year level history from %d daily bars.", sym, len(deep_df)
                    )
            stores_by_symbol[sym] = build_hv_level_store_for_symbol(
                sym,
                build_df,
                atr20=build_atr,
                earnings_dates=earnings_dates_by_symbol.get(sym, []),
                levels_dir=levels_dir,
                persist=persist,
                existing_store=existing_store,
                cumulative_stats=bool(cumulative_stats),
                mark_deep_backfill=mark_backfill,
                backfill_lookback_days=backfill_days,
            )
        except Exception as exc:
            logging.warning("%s: failed updating HV level store (%s).", sym, exc)

    ai_symbols = ai_state.get("symbols") if isinstance(ai_state, dict) else {}
    if not isinstance(ai_symbols, dict):
        ai_symbols = {}
    feature_rows_by_symbol = feature_rows_by_symbol if isinstance(feature_rows_by_symbol, dict) else {}
    hv_fields = (
        "hv_level_nearby_count",
        "hv_level_blocking_count",
        "hv_level_break_today",
        "hv_level_nearest_price",
        "hv_level_nearest_bucket",
        "hv_level_nearest_distance_atr",
        "hv_level_nearby_summary",
        "hv_level_blocking_summary",
        "hv_level_score_delta",
        "hv_level_score_note",
        "hv_level_note",
    )
    study_rows: list[dict] = []
    for row in priority_rows or []:
        if not isinstance(row, dict):
            continue
        symbol = str(row.get("symbol") or "").strip().upper()
        store = stores_by_symbol.get(symbol)
        if not store:
            continue
        symbol_entry = ai_symbols.get(symbol) if isinstance(ai_symbols, dict) else {}
        symbol_entry = symbol_entry if isinstance(symbol_entry, dict) else {}
        feature_row = feature_rows_by_symbol.get(symbol)
        feature_row = feature_row if isinstance(feature_row, dict) else {}
        entry_price = _coerce_float(row.get("last_close") or symbol_entry.get("last_close") or feature_row.get("last_close"))
        atr_value = _coerce_float(row.get("atr20") or symbol_entry.get("atr20") or feature_row.get("atr20"))
        last_trade_date = str(symbol_entry.get("last_trade_date") or feature_row.get("last_trade_date") or "")
        context = _hv_level_context_for_entry(
            store,
            side=row.get("side") or symbol_entry.get("side") or "",
            entry_price=entry_price,
            atr20=atr_value,
            last_trade_date=last_trade_date,
            scoring_enabled=bool(scoring_enabled),
        )
        row.update(context)
        score_delta = _coerce_float(context.get("hv_level_score_delta")) or 0.0
        if score_delta:
            row["score"] = float(row.get("score", 0.0) or 0.0) + float(score_delta)
            if isinstance(symbol_entry, dict):
                symbol_entry["priority_score"] = row.get("score")
            if isinstance(feature_row, dict):
                feature_row["priority_score"] = row.get("score")
        if isinstance(symbol_entry, dict):
            for field in hv_fields:
                symbol_entry[field] = context.get(field)
        if isinstance(feature_row, dict):
            for field in hv_fields:
                feature_row[field] = context.get(field)
        if context.get("hv_level_nearby_count") or context.get("hv_level_break_today"):
            study_rows.append(_build_hv_level_study_row(row, context))
    return study_rows


def _phase6_level_summary(levels: list[dict], limit: int = 3) -> str:
    parts = []
    for level in levels[: max(1, int(limit or 1))]:
        price = _coerce_float(level.get("price"))
        distance_atr = _coerce_float(level.get("distance_atr"))
        if price is None:
            continue
        effective_range = level.get("effective_range")
        range_text = ""
        if isinstance(effective_range, list) and len(effective_range) == 2:
            range_text = f" eff={effective_range[0]}..{effective_range[1]}"
        distance_text = "" if distance_atr is None else f" {distance_atr:+.2f}ATR"
        parts.append(f"cloud@{price:.2f}{distance_text}{range_text}".strip())
    return ", ".join(parts)


def _cloud_level_context_for_entry(
    store: dict,
    *,
    entry_price: float | None,
    atr20: float | None,
    last_trade_date: str = "",
) -> dict:
    nearby = levels_near(
        store,
        entry_price,
        atr20,
        tol_frac=CLOUD_TOL_ATR_FRACTION,
        min_strength=0.0,
        kinds={"cloud_flat"},
        as_of_date=last_trade_date,
    )
    nearest = nearby[0] if nearby else {}
    note = f"Cloud flat nearby: {_phase6_level_summary(nearby)}" if nearby else ""
    effective_range = nearest.get("effective_range") if nearest else []
    return {
        "cloud_level_nearby_count": int(len(nearby)),
        "cloud_level_nearest_price": _coerce_float(nearest.get("price")),
        "cloud_level_nearest_distance_atr": _coerce_float(nearest.get("distance_atr")),
        "cloud_level_effective_range": (
            " -> ".join(str(value) for value in effective_range)
            if isinstance(effective_range, list) and len(effective_range) == 2
            else ""
        ),
        "cloud_level_nearby_summary": _phase6_level_summary(nearby),
        "cloud_level_note": note,
    }


def assess_compression_break_context(
    df: pd.DataFrame | None,
    *,
    anchor_date_iso: str | None,
    anchor_stdev: float | None,
    atr20: float | None,
    side: str = "",
    last_trade_date: str | date | None = None,
) -> dict:
    result = {
        "compression_break_today": False,
        "compression_break_direction": "",
        "compression_break_level": None,
        "compression_break_distance_atr": None,
        "compression_break_prior_bars": 0,
        "compression_break_note": "",
    }
    atr_value = _coerce_float(atr20)
    stdev_value = _coerce_float(anchor_stdev)
    if df is None or df.empty or atr_value is None or atr_value <= 0 or stdev_value is None:
        return result
    try:
        anchor_date = date.fromisoformat(str(anchor_date_iso or "")[:10])
    except ValueError:
        return result

    work = df.copy()
    if "datetime" not in work.columns:
        return result
    work["datetime"] = pd.to_datetime(work["datetime"], errors="coerce")
    work = work.dropna(subset=["datetime"]).sort_values("datetime")
    if work.empty:
        return result
    for column in ("high", "low", "close"):
        if column not in work.columns:
            return result
        work[column] = pd.to_numeric(work[column], errors="coerce")
    work = work.dropna(subset=["high", "low", "close"])
    if work.empty:
        return result

    if last_trade_date:
        try:
            last_date = date.fromisoformat(str(last_trade_date)[:10])
        except ValueError:
            last_date = work["datetime"].iloc[-1].date()
    else:
        last_date = work["datetime"].iloc[-1].date()

    prior = work[(work["datetime"].dt.date >= anchor_date) & (work["datetime"].dt.date < last_date)].copy()
    if len(prior) < PHASE6_COMPRESSION_MIN_PRIOR_BARS:
        return result
    prior_summary = summarize_anchor_compression(prior, stdev_value, atr_value)
    if not prior_summary.get("is_compressed"):
        return result

    latest_rows = work[work["datetime"].dt.date == last_date]
    latest = latest_rows.iloc[-1] if not latest_rows.empty else work.iloc[-1]
    prior_high = _coerce_float(prior["high"].max())
    prior_low = _coerce_float(prior["low"].min())
    close_value = _coerce_float(latest.get("close"))
    if prior_high is None or prior_low is None or close_value is None:
        return result
    buffer = float(PHASE6_COMPRESSION_BREAK_BUFFER_ATR) * float(atr_value)
    normalized_side = normalize_side(side)
    broke_up = float(close_value) > float(prior_high) + buffer
    broke_down = float(close_value) < float(prior_low) - buffer
    if normalized_side == "SHORT":
        broke_up = False
    elif normalized_side == "LONG":
        broke_down = False
    if not (broke_up or broke_down):
        return result

    direction = "up" if broke_up else "down"
    level = float(prior_high if broke_up else prior_low)
    distance = abs(float(close_value) - level) / float(atr_value)
    result.update(
        {
            "compression_break_today": True,
            "compression_break_direction": direction,
            "compression_break_level": round(level, 4),
            "compression_break_distance_atr": round(distance, 4),
            "compression_break_prior_bars": int(len(prior)),
            "compression_break_note": (
                f"Compression break {direction}: close {close_value:.2f} beyond prior box "
                f"{prior_low:.2f}-{prior_high:.2f} by {distance:.2f} ATR"
            ),
        }
    )
    return result


def _build_phase6_study_row(priority_row: dict, *, family: str, bucket: str, tag: str, note: str, extra: dict | None = None) -> dict:
    study_row = dict(priority_row)
    if isinstance(extra, dict):
        study_row.update(extra)
    existing_tags = list(study_row.get("setup_tags") or [])
    study_row["priority_bucket"] = bucket
    study_row["is_favorite_setup"] = False
    study_row["is_near_favorite_zone"] = False
    study_row["setup_family"] = family
    study_row["study_kind"] = family
    study_row["setup_tags"] = list(dict.fromkeys([*existing_tags, tag]))
    study_row["favorite_signals"] = []
    study_row["context_signals"] = list(dict.fromkeys([*(study_row.get("context_signals") or []), tag]))
    study_row["has_favorite_signal"] = False
    study_row["score_bonus_note"] = note
    if not str(study_row.get("retest_note") or "").strip():
        study_row["retest_note"] = note
    return study_row


def enrich_priority_rows_with_phase6_studies(
    priority_rows: list[dict] | None,
    daily_frames_by_symbol: dict[str, pd.DataFrame] | None,
    *,
    earnings_dates_by_symbol: dict[str, list[str]] | None = None,
    ai_state: dict | None = None,
    feature_rows_by_symbol: dict | None = None,
    levels_dir: Path | None = None,
    persist: bool = True,
    level_stores_by_symbol: dict[str, dict] | None = None,
) -> list[dict]:
    frames = daily_frames_by_symbol if isinstance(daily_frames_by_symbol, dict) else {}
    stores_by_symbol = level_stores_by_symbol if isinstance(level_stores_by_symbol, dict) else {}
    earnings_dates_by_symbol = earnings_dates_by_symbol if isinstance(earnings_dates_by_symbol, dict) else {}
    if not stores_by_symbol:
        stores_by_symbol = {}
        for symbol, df in frames.items():
            sym = str(symbol or "").strip().upper()
            if not sym:
                continue
            try:
                stores_by_symbol[sym] = build_hv_level_store_for_symbol(
                    sym,
                    df,
                    earnings_dates=earnings_dates_by_symbol.get(sym, []),
                    levels_dir=levels_dir,
                    persist=persist,
                )
            except Exception as exc:
                logging.warning("%s: failed updating Phase 6 level store (%s).", sym, exc)

    ai_symbols = ai_state.get("symbols") if isinstance(ai_state, dict) else {}
    if not isinstance(ai_symbols, dict):
        ai_symbols = {}
    feature_rows_by_symbol = feature_rows_by_symbol if isinstance(feature_rows_by_symbol, dict) else {}
    fields = (
        "cloud_level_nearby_count",
        "cloud_level_nearest_price",
        "cloud_level_nearest_distance_atr",
        "cloud_level_effective_range",
        "cloud_level_nearby_summary",
        "cloud_level_note",
        "compression_break_today",
        "compression_break_direction",
        "compression_break_level",
        "compression_break_distance_atr",
        "compression_break_prior_bars",
        "compression_break_note",
    )
    study_rows: list[dict] = []
    for row in priority_rows or []:
        if not isinstance(row, dict):
            continue
        symbol = str(row.get("symbol") or "").strip().upper()
        symbol_entry = ai_symbols.get(symbol) if isinstance(ai_symbols, dict) else {}
        symbol_entry = symbol_entry if isinstance(symbol_entry, dict) else {}
        feature_row = feature_rows_by_symbol.get(symbol)
        feature_row = feature_row if isinstance(feature_row, dict) else {}
        entry_price = _coerce_float(row.get("last_close") or symbol_entry.get("last_close") or feature_row.get("last_close"))
        atr_value = _coerce_float(row.get("atr20") or symbol_entry.get("atr20") or feature_row.get("atr20"))
        last_trade_date = str(
            row.get("last_trade_date")
            or symbol_entry.get("last_trade_date")
            or feature_row.get("last_trade_date")
            or ""
        )
        cloud_context = _cloud_level_context_for_entry(
            stores_by_symbol.get(symbol, {}),
            entry_price=entry_price,
            atr20=atr_value,
            last_trade_date=last_trade_date,
        )
        compression_context = assess_compression_break_context(
            frames.get(symbol),
            anchor_date_iso=(
                (symbol_entry.get("current_anchor") or {}).get("date")
                if isinstance(symbol_entry.get("current_anchor"), dict)
                else ""
            ),
            anchor_stdev=(
                (symbol_entry.get("current_anchor") or {}).get("stdev")
                if isinstance(symbol_entry.get("current_anchor"), dict)
                else None
            ),
            atr20=atr_value,
            side=row.get("side") or symbol_entry.get("side") or "",
            last_trade_date=last_trade_date,
        )
        context = {**cloud_context, **compression_context}
        row.update(context)
        for target in (symbol_entry, feature_row):
            if isinstance(target, dict):
                for field in fields:
                    target[field] = context.get(field)

        if cloud_context.get("cloud_level_nearby_count"):
            study_rows.append(
                _build_phase6_study_row(
                    row,
                    family=PHASE6_CLOUD_STUDY_FAMILY,
                    bucket=PHASE6_CLOUD_STUDY_BUCKET,
                    tag="CLOUD_FLAT_PROXIMITY",
                    note=cloud_context.get("cloud_level_note") or "",
                    extra=cloud_context,
                )
            )
        if compression_context.get("compression_break_today"):
            study_rows.append(
                _build_phase6_study_row(
                    row,
                    family=PHASE6_COMPRESSION_BREAK_STUDY_FAMILY,
                    bucket=PHASE6_STRUCTURE_STUDY_BUCKET,
                    tag="COMPRESSION_BREAK",
                    note=compression_context.get("compression_break_note") or "",
                    extra=compression_context,
                )
            )
        if row.get("trendline_break_recent"):
            note = row.get("trendline_break_note") or symbol_entry.get("priority_trendline_break_note") or ""
            study_rows.append(
                _build_phase6_study_row(
                    row,
                    family=PHASE6_TRENDLINE_BREAK_STUDY_FAMILY,
                    bucket=PHASE6_STRUCTURE_STUDY_BUCKET,
                    tag="TRENDLINE_BREAK",
                    note=note,
                    extra={
                        "trendline_break_recent": True,
                        "trendline_break_note": note,
                        "trendline_break_candidate": row.get("trendline_break_candidate")
                        or symbol_entry.get("priority_trendline_break_candidate"),
                    },
                )
            )
    return study_rows


def build_symbol_industry_contexts(
    symbols,
    *,
    symbol_classification_cache: dict | None = None,
    sector_map: dict | None = None,
    industry_map_data: dict | None = None,
) -> dict[str, dict]:
    """Resolve scanned symbols to their sector and industry ETF references.

    The master scan reads the shared cache that BounceBot already maintains. It
    intentionally does not fetch missing Yahoo classifications here; missing cache
    rows simply produce no industry context for that symbol.
    """
    if symbol_classification_cache is None and callable(load_rrs_symbol_classification_cache):
        symbol_classification_cache = load_rrs_symbol_classification_cache()
    if sector_map is None and callable(load_rrs_sector_etf_map):
        sector_map = load_rrs_sector_etf_map()
    if industry_map_data is None and callable(load_rrs_industry_etf_map):
        industry_map_data = load_rrs_industry_etf_map()
    symbol_classification_cache = symbol_classification_cache if isinstance(symbol_classification_cache, dict) else {}
    sector_map = sector_map if isinstance(sector_map, dict) else {}
    industry_map_data = industry_map_data if isinstance(industry_map_data, dict) else {}

    contexts: dict[str, dict] = {}
    for symbol in symbols or []:
        sym = str(symbol or "").strip().upper()
        if not sym:
            continue
        classification = symbol_classification_cache.get(sym)
        if not isinstance(classification, dict):
            continue
        sector_key = str(classification.get("sectorKey") or "").strip()
        industry_key = str(classification.get("industryKey") or "").strip()
        if not sector_key and not industry_key:
            continue
        if callable(resolve_rrs_sector_etf):
            sector_etf = resolve_rrs_sector_etf(sector_key, sector_map)
        else:
            sector_etf = "SPY"
        if callable(resolve_rrs_industry_ref_etf):
            industry_etf = resolve_rrs_industry_ref_etf(industry_key, sector_key, industry_map_data, sector_map)
        else:
            industry_etf = sector_etf
        contexts[sym] = {
            "symbol": sym,
            "sector_key": sector_key,
            "industry_key": industry_key,
            "sector": classification.get("sector", ""),
            "industry": classification.get("industry", ""),
            "sector_etf": str(sector_etf or "").strip().upper(),
            "industry_etf": str(industry_etf or "").strip().upper(),
        }
    return contexts


def build_industry_strength_rows(
    industry_daily_frames_by_etf: dict | None,
    spy_benchmark: dict | None,
    *,
    industry_context_by_symbol: dict | None = None,
) -> list[dict]:
    rows: list[dict] = []
    if not isinstance(industry_daily_frames_by_etf, dict) or not industry_daily_frames_by_etf:
        return rows

    labels_by_etf: dict[str, set[str]] = {}
    symbols_by_etf: dict[str, set[str]] = {}
    for symbol, context in (industry_context_by_symbol or {}).items():
        if not isinstance(context, dict):
            continue
        etf = str(context.get("industry_etf") or context.get("sector_etf") or "").strip().upper()
        if not etf:
            continue
        label = str(context.get("industry") or context.get("sector") or "").strip()
        if label:
            labels_by_etf.setdefault(etf, set()).add(label)
        sym = str(symbol or context.get("symbol") or "").strip().upper()
        if sym:
            symbols_by_etf.setdefault(etf, set()).add(sym)

    for etf, df in industry_daily_frames_by_etf.items():
        ref = str(etf or "").strip().upper()
        if not ref:
            continue
        daily_rows = _daily_frame_to_rows(df)
        if not daily_rows:
            continue
        try:
            last_trade_date = date.fromisoformat(daily_rows[-1]["date"])
        except (ValueError, KeyError, TypeError):
            continue
        rs = assess_daily_relative_strength(daily_rows, last_trade_date, "LONG", spy_benchmark)
        rs_score = _coerce_float(rs.get("daily_relative_strength_score"))
        if rs_score is None:
            continue
        label_candidates = sorted(labels_by_etf.get(ref, set()))
        rows.append(
            {
                "symbol": ref,
                "industry_etf": ref,
                "industry": ", ".join(label_candidates[:3]),
                "constituent_symbols": sorted(symbols_by_etf.get(ref, set())),
                "daily_relative_strength_score": rs_score,
                "symbol_one_day_return_pct": rs.get("symbol_one_day_return_pct"),
                "symbol_five_day_return_pct": rs.get("symbol_five_day_return_pct"),
                "spy_one_day_return_pct": rs.get("spy_one_day_return_pct"),
                "spy_five_day_return_pct": rs.get("spy_five_day_return_pct"),
                "return_13w_pct": _trailing_return_pct(daily_rows, MARKET_PREP_RETURN_13W_SESSIONS),
                "return_26w_pct": _trailing_return_pct(daily_rows, MARKET_PREP_RETURN_26W_SESSIONS),
            }
        )
    rows.sort(
        key=lambda row: (
            -float(row.get("daily_relative_strength_score") or 0.0),
            str(row.get("industry_etf") or row.get("symbol") or ""),
        )
    )
    return rows


def build_universe_strength_rows(
    daily_frames_by_symbol: dict | None,
    spy_benchmark: dict | None,
    *,
    sides_by_symbol: dict | None = None,
    industry_context_by_symbol: dict | None = None,
    industry_daily_frames_by_etf: dict | None = None,
    daily_rows_cache: dict | None = None,
    industry_rows_by_etf: dict | None = None,
) -> list[dict]:
    """One strength row per *scanned* symbol — the whole universe, not just the
    symbols that produced a flagged setup. Feeds the market-prep strongest/weakest
    decile and the "recently strong, now pulling back" list (Feat 1).

    Reuses the existing ``assess_daily_relative_strength`` (0.35/0.65 excess-vs-SPY
    math) so universe RS matches per-symbol RS shown elsewhere. The RS *score* is
    side-independent, so this is computed once per symbol regardless of watchlist
    side; ``sides_by_symbol`` only labels the row.
    """
    rows: list[dict] = []
    if not isinstance(daily_frames_by_symbol, dict) or not daily_frames_by_symbol:
        return rows
    sides_by_symbol = sides_by_symbol if isinstance(sides_by_symbol, dict) else {}
    industry_context_by_symbol = industry_context_by_symbol if isinstance(industry_context_by_symbol, dict) else {}
    industry_daily_frames_by_etf = industry_daily_frames_by_etf if isinstance(industry_daily_frames_by_etf, dict) else {}
    daily_rows_cache = daily_rows_cache if isinstance(daily_rows_cache, dict) else {}
    if isinstance(industry_rows_by_etf, dict):
        industry_rows_by_etf = {
            str(etf or "").strip().upper(): rows
            for etf, rows in industry_rows_by_etf.items()
            if str(etf or "").strip()
        }
    else:
        industry_rows_by_etf = {}
        for etf, df in industry_daily_frames_by_etf.items():
            ref = str(etf or "").strip().upper()
            if ref:
                industry_rows_by_etf[ref] = _daily_frame_to_rows(df)
    for symbol, df in daily_frames_by_symbol.items():
        sym = str(symbol or "").strip().upper()
        if not sym:
            continue
        cached = daily_rows_cache.get(sym) if daily_rows_cache else None
        if isinstance(cached, dict) and cached.get("rows"):
            daily_rows = cached["rows"]
            last_trade_date = cached.get("last_trade_date")
            cached_atr = cached.get("atr20")
        else:
            daily_rows = _daily_frame_to_rows(df)
            last_trade_date = None
            cached_atr = None
        if not daily_rows:
            continue
        if last_trade_date is None:
            try:
                last_trade_date = date.fromisoformat(daily_rows[-1]["date"])
            except (ValueError, KeyError, TypeError):
                continue
        side = normalize_side(sides_by_symbol.get(sym) or "")
        rs = assess_daily_relative_strength(daily_rows, last_trade_date, side, spy_benchmark)
        row = {
            "symbol": sym,
            "side": side,
            "daily_relative_strength_score": rs.get("daily_relative_strength_score"),
            "daily_relative_strength_bonus": rs.get("daily_relative_strength_bonus"),
            "daily_relative_strength_note": rs.get("daily_relative_strength_note"),
            "symbol_one_day_return_pct": rs.get("symbol_one_day_return_pct"),
            "symbol_five_day_return_pct": rs.get("symbol_five_day_return_pct"),
            "spy_one_day_return_pct": rs.get("spy_one_day_return_pct"),
            "spy_five_day_return_pct": rs.get("spy_five_day_return_pct"),
            "return_13w_pct": _trailing_return_pct(daily_rows, MARKET_PREP_RETURN_13W_SESSIONS),
            "return_26w_pct": _trailing_return_pct(daily_rows, MARKET_PREP_RETURN_26W_SESSIONS),
            "atr20": cached_atr if cached_atr is not None else compute_atr_from_ohlc(daily_rows, last_trade_date),
            "universe_strength_row": True,
        }
        context = industry_context_by_symbol.get(sym)
        if isinstance(context, dict):
            row.update(
                {
                    "sector": context.get("sector", ""),
                    "industry": context.get("industry", ""),
                    "sector_key": context.get("sector_key", ""),
                    "industry_key": context.get("industry_key", ""),
                    "sector_etf": context.get("sector_etf", ""),
                    "industry_etf": context.get("industry_etf", ""),
                }
            )
            industry_etf = str(context.get("industry_etf") or "").strip().upper()
            industry_rows = industry_rows_by_etf.get(industry_etf)
            if industry_rows:
                industry_one_day = _trailing_return_pct(industry_rows, 1)
                industry_five_day = _trailing_return_pct(industry_rows, DAILY_RELATIVE_STRENGTH_LOOKBACK_DAYS)
                industry_13w = _trailing_return_pct(industry_rows, MARKET_PREP_RETURN_13W_SESSIONS)
                row.update(
                    {
                        "industry_one_day_return_pct": industry_one_day,
                        "industry_five_day_return_pct": industry_five_day,
                        "industry_13w_return_pct": industry_13w,
                        "rs_vs_industry": _weighted_excess_strength_score(
                            row.get("symbol_one_day_return_pct"),
                            row.get("symbol_five_day_return_pct"),
                            industry_one_day,
                            industry_five_day,
                        ),
                        "return_13w_vs_industry_pct": (
                            None
                            if row.get("return_13w_pct") is None or industry_13w is None
                            else round(float(row.get("return_13w_pct")) - float(industry_13w), 3)
                        ),
                    }
                )
        rows.append(row)
    return rows


def assess_industry_relative_strength(
    universe_row: dict | None,
    side: str,
    industry_strength_row: dict | None = None,
    *,
    scoring_enabled: bool = False,
) -> dict:
    row = universe_row if isinstance(universe_row, dict) else {}
    industry_row = industry_strength_row if isinstance(industry_strength_row, dict) else {}
    industry_etf = str(row.get("industry_etf") or industry_row.get("industry_etf") or "").strip().upper()
    rs_vs_industry = _coerce_float(row.get("rs_vs_industry"))
    industry_rs = _coerce_float(industry_row.get("daily_relative_strength_score"))
    result = {
        "industry_etf": industry_etf,
        "industry_relative_strength_score": rs_vs_industry,
        "industry_daily_relative_strength_score": industry_rs,
        "industry_relative_strength_bonus": 0,
        "industry_relative_strength_note": "",
    }
    if not industry_etf or rs_vs_industry is None:
        return result

    normalized_side = normalize_side(side)
    if normalized_side == "SHORT":
        stock_leads = rs_vs_industry <= -INDUSTRY_RELATIVE_STRENGTH_THRESHOLD
        industry_aligned = industry_rs is None or industry_rs <= -INDUSTRY_RELATIVE_STRENGTH_INDUSTRY_THRESHOLD
        stock_text = "weaker than"
        industry_text = "industry weak vs SPY"
    else:
        stock_leads = rs_vs_industry >= INDUSTRY_RELATIVE_STRENGTH_THRESHOLD
        industry_aligned = industry_rs is None or industry_rs >= INDUSTRY_RELATIVE_STRENGTH_INDUSTRY_THRESHOLD
        stock_text = "stronger than"
        industry_text = "industry strong vs SPY"

    note_bits = [
        f"D1 {stock_text} {industry_etf}: rs_ind={rs_vs_industry:+.2f}",
    ]
    if industry_rs is not None:
        note_bits.append(f"{industry_text} rs={industry_rs:+.2f}")

    if stock_leads and industry_aligned:
        if scoring_enabled:
            result["industry_relative_strength_bonus"] = INDUSTRY_RELATIVE_STRENGTH_BONUS
            note_bits.append(f"+{INDUSTRY_RELATIVE_STRENGTH_BONUS}")
        else:
            note_bits.append("score flag off")
    elif (
        normalized_side == "LONG"
        and industry_rs is not None
        and industry_rs >= INDUSTRY_RELATIVE_STRENGTH_ROTATION_RELAX_THRESHOLD
        and rs_vs_industry > -INDUSTRY_RELATIVE_STRENGTH_THRESHOLD
    ):
        note_bits.append("super-strong industry; mild lag kept as rotation context")

    result["industry_relative_strength_note"] = "; ".join(note_bits)
    return result


def enrich_priority_rows_with_industry_relative_strength(
    priority_rows: list[dict] | None,
    universe_strength_rows: list[dict] | None,
    industry_strength_rows: list[dict] | None,
    *,
    scoring_enabled: bool | None = None,
    ai_state: dict | None = None,
    feature_rows_by_symbol: dict | None = None,
) -> None:
    if not priority_rows or not universe_strength_rows:
        return
    if scoring_enabled is None:
        scoring_enabled = bool(get_priority_feature_flags().get(INDUSTRY_RELATIVE_STRENGTH_SCORING_FLAG))
    universe_by_symbol = {
        str(row.get("symbol") or "").strip().upper(): row
        for row in universe_strength_rows or []
        if isinstance(row, dict) and str(row.get("symbol") or "").strip()
    }
    industry_by_etf = {
        str(row.get("industry_etf") or row.get("symbol") or "").strip().upper(): row
        for row in industry_strength_rows or []
        if isinstance(row, dict) and str(row.get("industry_etf") or row.get("symbol") or "").strip()
    }
    ai_symbols = ai_state.get("symbols") if isinstance(ai_state, dict) else {}
    if not isinstance(ai_symbols, dict):
        ai_symbols = {}
    feature_rows_by_symbol = feature_rows_by_symbol if isinstance(feature_rows_by_symbol, dict) else {}

    copy_fields = (
        "daily_relative_strength_score",
        "symbol_one_day_return_pct",
        "symbol_five_day_return_pct",
        "spy_one_day_return_pct",
        "spy_five_day_return_pct",
        "return_13w_pct",
        "return_26w_pct",
        "sector",
        "industry",
        "sector_key",
        "industry_key",
        "sector_etf",
        "industry_etf",
        "industry_one_day_return_pct",
        "industry_five_day_return_pct",
        "industry_13w_return_pct",
        "rs_vs_industry",
        "return_13w_vs_industry_pct",
    )
    for priority_row in priority_rows:
        if not isinstance(priority_row, dict):
            continue
        symbol = str(priority_row.get("symbol") or "").strip().upper()
        universe_row = universe_by_symbol.get(symbol)
        if not universe_row:
            continue
        for field in copy_fields:
            if field in universe_row:
                priority_row[field] = universe_row.get(field)
        industry_etf = str(universe_row.get("industry_etf") or "").strip().upper()
        bonus_result = assess_industry_relative_strength(
            universe_row,
            priority_row.get("side") or universe_row.get("side") or "",
            industry_by_etf.get(industry_etf),
            scoring_enabled=bool(scoring_enabled),
        )
        setup_family = str(priority_row.get("setup_family") or "").strip().lower()
        setup_active = (
            bool(priority_row.get("has_favorite_signal"))
            or bool(priority_row.get("favorite_signals"))
            or bool(priority_row.get("favorite_zone"))
            or bool(priority_row.get("extreme_move_watch"))
            or bool(priority_row.get("sma_breakout_watch"))
            or bool(priority_row.get("sma_breakout_confirmed"))
            or setup_family not in {"", "general"}
        )
        if not setup_active and int(bonus_result.get("industry_relative_strength_bonus", 0) or 0):
            bonus_result["industry_relative_strength_bonus"] = 0
            note = str(bonus_result.get("industry_relative_strength_note") or "")
            bonus_result["industry_relative_strength_note"] = (
                f"{note}; setup inactive" if note else "Industry RS boost skipped; setup inactive"
            )
        priority_row.update(bonus_result)
        bonus = int(bonus_result.get("industry_relative_strength_bonus", 0) or 0)
        if bonus:
            priority_row["score"] = float(priority_row.get("score", 0.0) or 0.0) + float(bonus)

        symbol_entry = ai_symbols.get(symbol)
        if isinstance(symbol_entry, dict):
            for field in (*copy_fields, *bonus_result.keys()):
                if field in priority_row:
                    symbol_entry[field] = priority_row.get(field)
            symbol_entry["priority_score"] = priority_row.get("score")
        feature_row = feature_rows_by_symbol.get(symbol)
        if isinstance(feature_row, dict):
            for field in (*copy_fields, *bonus_result.keys()):
                if field in priority_row:
                    feature_row[field] = priority_row.get(field)
            feature_row["priority_score"] = priority_row.get("score")


def _previous_anchor_sr_output_label(level_label: str) -> str:
    normalized = str(level_label or "").strip().upper()
    if normalized in {"AVWAPE", "VWAP"}:
        return "PREV_AVWAPE"
    return f"PREV_{normalized}" if normalized else ""

def _previous_anchor_sr_event_level(event_name: str) -> str:
    normalized_event = str(event_name or "").strip().upper()
    if not normalized_event.startswith("PREV_BOUNCE_"):
        return ""
    level = normalized_event[len("PREV_BOUNCE_"):]
    if level in {"VWAP", "AVWAPE"}:
        return "AVWAPE"
    return level if level in PREVIOUS_ANCHOR_SR_LEVEL_LABELS else ""

def _previous_anchor_sr_level_values(previous_anchor_meta: dict | None) -> dict[str, float]:
    levels = {}
    if not isinstance(previous_anchor_meta, dict) or not previous_anchor_meta:
        return levels
    for label in PREVIOUS_ANCHOR_SR_LEVEL_LABELS:
        level_value = _anchor_level_value(previous_anchor_meta, label)
        if level_value is not None:
            levels[label] = float(level_value)
    return levels

def _daily_row_matches_trade_date(row: dict | pd.Series, last_trade_date) -> bool:
    if last_trade_date is None:
        return True
    target = str(last_trade_date)
    if hasattr(last_trade_date, "isoformat"):
        target = last_trade_date.isoformat()
    row_date = None
    if isinstance(row, pd.Series):
        row_date = row.get("date", row.get("trade_date", row.get("datetime")))
    elif isinstance(row, dict):
        row_date = row.get("date", row.get("trade_date", row.get("datetime")))
    if row_date is None:
        return False
    if hasattr(row_date, "date"):
        row_date = row_date.date()
    if hasattr(row_date, "isoformat"):
        row_date = row_date.isoformat()
    return str(row_date)[:10] == target[:10]

def _latest_daily_row_for_sr(daily_rows, last_trade_date) -> dict:
    if isinstance(daily_rows, pd.DataFrame):
        rows = [daily_rows.iloc[idx] for idx in range(len(daily_rows))]
    else:
        rows = list(daily_rows or [])
    if not rows:
        return {}
    for row in reversed(rows):
        if _daily_row_matches_trade_date(row, last_trade_date):
            return dict(row)
    return dict(rows[-1])

def analyze_previous_anchor_sr_context(
    daily_rows,
    last_trade_date,
    last_close: float | None,
    side: str,
    previous_anchor_meta: dict | None,
    atr20: float | None,
    events_today: list[str] | None = None,
) -> dict:
    close_value = _coerce_float(last_close)
    atr_value = _coerce_float(atr20)
    level_values = _previous_anchor_sr_level_values(previous_anchor_meta)
    event_levels = sorted(
        set(
            level
            for level in (_previous_anchor_sr_event_level(event_name) for event_name in events_today or [])
            if level
        )
    )
    empty_summary = {
        "levels": [],
        "nearest_level": "",
        "nearest_distance_atr": None,
        "near_levels": [],
        "touched_levels": [],
        "bounce_levels": [],
        "obstacle_levels": [],
        "critical_near_levels": [],
        "critical_touched_levels": [],
        "critical_bounce_levels": [],
        "critical_obstacle_levels": [],
        "previous_avwape_bounce": "AVWAPE" in event_levels,
        "previous_avwape_near": False,
        "previous_avwape_distance_atr": None,
        "note": "",
    }
    if close_value is None or not atr_value or atr_value <= 0 or not level_values:
        if event_levels:
            empty_summary["bounce_levels"] = [_previous_anchor_sr_output_label(level) for level in event_levels]
            empty_summary["critical_bounce_levels"] = [
                _previous_anchor_sr_output_label(level)
                for level in event_levels
                if level in PREVIOUS_ANCHOR_CRITICAL_SR_LABELS
            ]
        return empty_summary

    latest_row = _latest_daily_row_for_sr(daily_rows, last_trade_date)
    high_value = _coerce_float(latest_row.get("high"))
    low_value = _coerce_float(latest_row.get("low"))
    if high_value is None:
        high_value = close_value
    if low_value is None:
        low_value = close_value

    levels = []
    near_levels = []
    touched_levels = []
    bounce_levels = []
    obstacle_levels = []
    critical_near_levels = []
    critical_touched_levels = []
    critical_bounce_levels = []
    critical_obstacle_levels = []
    nearest_record = None
    normalized_side = normalize_side(side)

    for level_label, level in level_values.items():
        output_label = _previous_anchor_sr_output_label(level_label)
        signed_distance_atr = (close_value - float(level)) / float(atr_value)
        abs_distance_atr = abs(signed_distance_atr)
        directional_distance_atr = _directional_atr_distance(close_value, float(level), atr_value, normalized_side)
        touched = (
            (low_value - (PREVIOUS_ANCHOR_SR_TOUCH_ATR * atr_value)) <= float(level)
            <= (high_value + (PREVIOUS_ANCHOR_SR_TOUCH_ATR * atr_value))
        )
        event_bounce = level_label in event_levels
        bounce = bool(event_bounce)
        if not bounce and touched:
            if normalized_side == "SHORT":
                bounce = close_value <= float(level)
            else:
                bounce = close_value >= float(level)
        near = abs_distance_atr <= PREVIOUS_ANCHOR_SR_NEAR_ATR
        obstacle = (
            directional_distance_atr is not None
            and directional_distance_atr <= PRIORITY_PREV_AVWAP_WARN_ATR
        )
        critical = level_label in PREVIOUS_ANCHOR_CRITICAL_SR_LABELS
        record = {
            "label": output_label,
            "level_label": level_label,
            "level": float(level),
            "signed_distance_atr": float(signed_distance_atr),
            "abs_distance_atr": float(abs_distance_atr),
            "directional_distance_atr": None if directional_distance_atr is None else float(directional_distance_atr),
            "near": bool(near),
            "touched": bool(touched),
            "bounce": bool(bounce),
            "obstacle": bool(obstacle),
            "critical": bool(critical),
        }
        levels.append(record)
        if nearest_record is None or abs_distance_atr < nearest_record["abs_distance_atr"]:
            nearest_record = record
        if near:
            near_levels.append(output_label)
            if critical:
                critical_near_levels.append(output_label)
        if touched:
            touched_levels.append(output_label)
            if critical:
                critical_touched_levels.append(output_label)
        if bounce:
            bounce_levels.append(output_label)
            if critical:
                critical_bounce_levels.append(output_label)
        if obstacle:
            obstacle_entry = {
                "label": output_label,
                "level": float(level),
                "atr_distance": float(directional_distance_atr),
                "critical": bool(critical),
            }
            obstacle_levels.append(obstacle_entry)
            if critical:
                critical_obstacle_levels.append(obstacle_entry)

    levels.sort(key=lambda item: item["abs_distance_atr"])
    obstacle_levels.sort(key=lambda item: item["atr_distance"])
    critical_obstacle_levels.sort(key=lambda item: item["atr_distance"])
    note_parts = []
    if "PREV_AVWAPE" in bounce_levels:
        note_parts.append(f"Previous AVWAPE bounce +{PRIORITY_PREVIOUS_AVWAPE_BOUNCE_SCORE_BONUS}")
    if critical_obstacle_levels:
        note_parts.append(f"Critical previous S/R ahead: {_format_obstacle_labels(critical_obstacle_levels)}")
    elif obstacle_levels:
        note_parts.append(f"Previous S/R ahead: {_format_obstacle_labels(obstacle_levels)}")
    if critical_near_levels:
        note_parts.append(f"Near critical previous S/R: {', '.join(critical_near_levels[:4])}")

    return {
        "levels": levels,
        "nearest_level": nearest_record.get("label", "") if nearest_record else "",
        "nearest_distance_atr": nearest_record.get("abs_distance_atr") if nearest_record else None,
        "near_levels": sorted(set(near_levels)),
        "touched_levels": sorted(set(touched_levels)),
        "bounce_levels": sorted(set(bounce_levels)),
        "obstacle_levels": obstacle_levels,
        "critical_near_levels": sorted(set(critical_near_levels)),
        "critical_touched_levels": sorted(set(critical_touched_levels)),
        "critical_bounce_levels": sorted(set(critical_bounce_levels)),
        "critical_obstacle_levels": critical_obstacle_levels,
        "previous_avwape_bounce": "PREV_AVWAPE" in bounce_levels,
        "previous_avwape_near": any(item.get("label") == "PREV_AVWAPE" and item.get("near") for item in levels),
        "previous_avwape_distance_atr": next(
            (item.get("signed_distance_atr") for item in levels if item.get("label") == "PREV_AVWAPE"),
            None,
        ),
        "note": " | ".join(note_parts),
    }

def _priority_is_sma_breakout_trigger_confirmed(row: dict) -> bool:
    if str(row.get("setup_family") or "") != SMA_BREAKOUT_FAMILY:
        return False
    if not row.get("sma_breakout_confirmed"):
        return False
    if (
        "sma_breakout_higher_high_confirmed" not in row
        and "sma_breakout_previous_day_high_break" not in row
    ):
        return True
    return bool(
        row.get("sma_breakout_higher_high_confirmed")
        or row.get("sma_breakout_previous_day_high_break")
    )

def _priority_has_range_break_confirmation(row: dict) -> bool:
    return bool(
        row.get("previous_day_range_break")
        or row.get("sma_breakout_previous_day_high_break")
        or row.get("sma_breakout_higher_high_confirmed")
    )

def _priority_is_swing_entry_band_zone(row: dict) -> bool:
    side = normalize_side(row.get("side", ""))
    band_zone = _priority_current_band_zone(row)
    if side == "LONG":
        return band_zone in {"VWAP to UPPER_1", "UPPER_1 to UPPER_2"}
    if side == "SHORT":
        return band_zone in {"VWAP to LOWER_1", "LOWER_1 to LOWER_2"}
    return False

def _priority_is_mid_earnings_swing_retest_ready(row: dict) -> bool:
    setup_family = str(row.get("setup_family") or "")
    if setup_family not in {
        MID_EARNINGS_EMA15_RETEST_FAMILY,
        MID_EARNINGS_EMA21_RETEST_FAMILY,
        MID_EARNINGS_FIRST_DEV_RETEST_FAMILY,
    }:
        return False
    if not _priority_is_swing_entry_band_zone(row):
        return False
    if not _priority_has_strength_confirmation(row):
        return False
    return bool(
        row.get("mid_earnings_ema15_trigger")
        or row.get("mid_earnings_first_dev_trigger")
    )

def _priority_is_sma_breakout_swing_ready(row: dict) -> bool:
    if not _priority_is_sma_breakout_trigger_confirmed(row):
        return False
    if not _priority_has_range_break_confirmation(row):
        return False
    if not _priority_is_swing_entry_band_zone(row):
        return False
    return str(row.get("sma_breakout_retest_level") or "").strip().upper() == "EMA_15"

def _priority_is_preferred_swing_focus(row: dict) -> bool:
    setup_family = str(row.get("setup_family") or "")
    if setup_family in {
        MID_EARNINGS_EMA15_RETEST_FAMILY,
        MID_EARNINGS_FIRST_DEV_RETEST_FAMILY,
    }:
        return _priority_is_mid_earnings_swing_retest_ready(row)
    if setup_family == "extreme_move_retest":
        return str(row.get("extreme_move_retest_level") or "").strip().upper() in PREFERRED_SWING_STDEV_RETEST_LEVELS
    if setup_family == "post_earnings_avwap_bounce":
        return _is_post_earnings_play_ready(row)
    if setup_family == "previous_avwape_bounce":
        return bool(row.get("previous_avwape_bounce"))
    if setup_family == "post_earnings_52w_break":
        return _is_post_earnings_play_ready(row) and bool(row.get("post_earnings_break_close"))
    if setup_family == SMA_BREAKOUT_FAMILY:
        return _priority_is_sma_breakout_swing_ready(row)
    if setup_family == TOP_PATTERN_FAMILY:
        return bool(row.get("top_pattern_entry"))
    if setup_family == "avwap_retest_followthrough":
        return bool(
            row.get("retest_followthrough")
            and str(row.get("retest_reference_level") or "").strip().upper() in {"AVWAPE", "VWAP"}
        )
    if setup_family == "avwap_breakout":
        levels = _priority_signal_levels(row)
        return bool(
            _priority_is_actionable_avwap_breakout(row)
            and (
                row.get("retest_followthrough")
                or bool(levels & {"VWAP"})
            )
        )
    return False

def _priority_is_preferred_custom_setup(row: dict) -> bool:
    setup_family = str(row.get("setup_family") or "")
    if _priority_is_preferred_swing_focus(row):
        return True
    if setup_family in {
        MID_EARNINGS_EMA21_RETEST_FAMILY,
    }:
        return True
    # TOP entries stay "preferred" even when demoted to a secondary tag (Feat 2):
    # key off the flag, not the family, so a TOP+real-pattern setup keeps its status.
    if row.get("top_pattern_entry"):
        return True
    return False

def _priority_should_track_top_pattern(row: dict) -> bool:
    if not isinstance(row, dict):
        return False
    # A watch-only TOP candidate should appear in the TOP tracking list regardless of
    # whatever primary family it also matched (Feat 2: TOP is now secondary, so it no
    # longer owns the family). Gate on the flags, not the family.
    return bool(
        row.get("top_pattern_watch")
        and not row.get("top_pattern_entry")
    )

def _priority_is_top_strength_watchlist(row: dict) -> bool:
    if not isinstance(row, dict):
        return False
    if normalize_side(row.get("side") or "") != "LONG":
        return False
    setup_family = str(row.get("setup_family") or "").strip()
    return bool(
        setup_family in {TOP_PATTERN_FAMILY, TOP_PATTERN_TRACKING_FAMILY}
        or row.get("top_pattern_watch")
        or row.get("top_pattern_entry")
    )

def _priority_top_pattern_tracking_rows(rows: list[dict]) -> list[dict]:
    tracking_rows = _priority_unique_rows_by_symbol(
        [row for row in rows or [] if _priority_should_track_top_pattern(row)]
    )

    def sort_key(row: dict) -> tuple[float, float, str]:
        score = _coerce_float(row.get("score"))
        return_26w = _coerce_float(row.get("top_pattern_weekly_return_26w_pct"))
        return (
            -(score if score is not None else -10**9),
            -(return_26w if return_26w is not None else -10**9),
            str(row.get("symbol") or ""),
        )

    return sorted(tracking_rows, key=sort_key)

def _priority_top_strength_watchlist_rows(
    rows: list[dict],
    *,
    limit: int = TOP_STRENGTH_WATCHLIST_LIMIT,
) -> list[dict]:
    top_rows = _priority_unique_rows_by_symbol(
        [row for row in rows or [] if _priority_is_top_strength_watchlist(row)]
    )

    def sort_key(row: dict) -> tuple[int, float, float, float, float, str]:
        score = _coerce_float(row.get("score"))
        return_26w = _coerce_float(row.get("top_pattern_weekly_return_26w_pct"))
        return_13w = _coerce_float(row.get("top_pattern_weekly_return_13w_pct"))
        rs_score = _coerce_float(row.get("daily_relative_strength_score"))
        return (
            0 if row.get("top_pattern_entry") else 1,
            -(score if score is not None else -10**9),
            -(return_26w if return_26w is not None else -10**9),
            -(return_13w if return_13w is not None else -10**9),
            -(rs_score if rs_score is not None else -10**9),
            str(row.get("symbol") or ""),
        )

    sorted_rows = sorted(top_rows, key=sort_key)
    if limit <= 0:
        return sorted_rows
    return sorted_rows[: int(limit)]

def _priority_has_buying_interest_confirmation(row: dict) -> bool:
    return bool(
        row.get("previous_day_range_break")
        or row.get("previous_day_range_intraday_break")
        or row.get("vwap_range_confirmation")
        or row.get("breakout_5d")
        or row.get("trendline_break_recent")
        or row.get("post_earnings_break_intraday")
        or row.get("post_earnings_break_close")
        or row.get("sma_breakout_previous_day_high_break")
        or row.get("sma_breakout_higher_high_confirmed")
        or row.get("top_pattern_entry")
    )

def _priority_has_high_conviction_entry(row: dict) -> bool:
    setup_family = str(row.get("setup_family") or "")
    if _is_post_earnings_play_ready(row):
        return bool(
            row.get("post_earnings_break_intraday")
            or row.get("post_earnings_break_close")
            or row.get("previous_day_range_intraday_break")
            or row.get("previous_day_range_break")
        )
    if setup_family == TOP_PATTERN_FAMILY:
        return bool(row.get("top_pattern_entry"))
    if setup_family == SMA_BREAKOUT_FAMILY:
        return _priority_is_sma_breakout_swing_ready(row)
    if setup_family in {
        MID_EARNINGS_EMA15_RETEST_FAMILY,
        MID_EARNINGS_EMA21_RETEST_FAMILY,
        MID_EARNINGS_FIRST_DEV_RETEST_FAMILY,
    }:
        return bool(
            _priority_is_mid_earnings_swing_retest_ready(row)
            and _priority_has_buying_interest_confirmation(row)
        )
    if setup_family == "avwap_retest_followthrough":
        return bool(row.get("retest_followthrough") and _priority_is_swing_entry_band_zone(row))
    if setup_family == "previous_avwape_bounce":
        return bool(row.get("previous_avwape_bounce") and _priority_has_buying_interest_confirmation(row))
    if setup_family == "extreme_move_retest":
        return bool(_priority_is_preferred_swing_focus(row) and _priority_has_buying_interest_confirmation(row))
    if setup_family == "avwap_breakout":
        return bool(_priority_is_actionable_avwap_breakout(row) and _priority_has_buying_interest_confirmation(row))
    return bool(_priority_has_specific_trigger(row) and _priority_has_buying_interest_confirmation(row))

def _priority_is_best_swing_trade_candidate(row: dict) -> bool:
    setup_family = str(row.get("setup_family") or "")
    if _is_post_earnings_play_ready(row):
        signals = set(row.get("favorite_signals") or []) | set(row.get("context_signals") or [])
        return bool(
            row.get("post_earnings_break_close")
            or row.get("post_earnings_break_intraday")
            or POST_EARNINGS_BOUNCE_SIGNAL in signals
        )
    if setup_family in {
        MID_EARNINGS_EMA15_RETEST_FAMILY,
        MID_EARNINGS_EMA21_RETEST_FAMILY,
        MID_EARNINGS_FIRST_DEV_RETEST_FAMILY,
    }:
        return _priority_is_mid_earnings_swing_retest_ready(row)
    if setup_family == SMA_BREAKOUT_FAMILY:
        return _priority_is_sma_breakout_swing_ready(row)
    if setup_family == TOP_PATTERN_FAMILY:
        return bool(
            row.get("top_pattern_entry")
            and (
                row.get("top_pattern_daily_sma50_reclaim")
                or row.get("top_pattern_daily_sma50_bounce")
                or row.get("top_pattern_weekly_sma50_entry")
                or row.get("top_pattern_avwape_retest")
            )
        )
    if setup_family == "avwap_retest_followthrough":
        return bool(
            row.get("retest_followthrough")
            and _priority_is_swing_entry_band_zone(row)
        )
    if setup_family == "previous_avwape_bounce":
        return bool(
            row.get("previous_avwape_bounce")
            and _priority_is_swing_entry_band_zone(row)
            and _priority_has_range_break_confirmation(row)
        )
    if setup_family == "extreme_move_retest":
        return bool(_priority_is_preferred_swing_focus(row) and _priority_has_range_break_confirmation(row))
    if setup_family == "avwap_breakout":
        return bool(_priority_is_actionable_avwap_breakout(row) and _priority_has_range_break_confirmation(row))
    return False

def _priority_tier_sort_key(row: dict) -> tuple[float, int, int, str]:
    score = _coerce_float(row.get("score"))
    tracker_delta = (
        int(row.get("setup_type_score_delta", 0) or 0)
        + int(row.get("recent_tracker_score_delta", 0) or 0)
        + int(row.get("adaptive_score_delta", 0) or 0)
    )
    clean_bonus = int(row.get("clean_first_zone_score_bonus", 0) or 0)
    return (
        -(score if score is not None else -10**9),
        -tracker_delta,
        -clean_bonus,
        str(row.get("symbol") or ""),
    )

def _priority_partition_tier_rows(
    *,
    actionable_rows: list[dict],
    report_rows: list[dict],
    high_conviction_rows: list[dict],
    best_swing_rows: list[dict],
) -> list[dict]:
    assigned_symbols: set[str] = set()

    def symbol_for(row: dict) -> str:
        return str(row.get("symbol") or "").strip().upper()

    def sorted_unique(rows: list[dict]) -> list[dict]:
        return sorted(_priority_unique_rows_by_symbol(rows), key=_priority_tier_sort_key)

    def take_rows(rows: list[dict]) -> list[dict]:
        selected = []
        for row in sorted_unique(rows):
            symbol = symbol_for(row)
            if not symbol or symbol in assigned_symbols:
                continue
            assigned_symbols.add(symbol)
            selected.append(row)
        return selected

    s_rows = take_rows(best_swing_rows + high_conviction_rows)
    a_rows = take_rows(
        [
            row for row in actionable_rows
            if (
                row.get("priority_bucket") == "favorite_setup"
                or row.get("preferred_swing_focus")
                or _is_post_earnings_play_ready(row)
            )
        ]
    )
    b_rows = take_rows(report_rows)

    return [
        {
            "label": "S Tier",
            "title": "S Tier - act first",
            "note": "Cleanest actionable setups now; this is the cream-of-the-crop shortlist.",
            "rows": s_rows,
        },
        {
            "label": "A Tier",
            "title": "A Tier - next best",
            "note": "Strong setups or favorites that are close, but need a little more confirmation or have a small flaw.",
            "rows": a_rows,
        },
        {
            "label": "B Tier",
            "title": "B Tier - stalk list",
            "note": "Useful watchlist tier: strength/tracking names that can upgrade after the entry actually starts.",
            "rows": b_rows,
        },
    ]

def _write_priority_tier_copy_lists(handle, tiers: list[dict]) -> None:
    handle.write("Cream of the crop copy/paste\n")
    handle.write("============================\n")
    for tier in tiers:
        rows = list(tier.get("rows") or [])
        handle.write(f"{tier.get('title') or tier.get('label')}\n")
        handle.write(f"  LONG: {_priority_symbols(rows, 'LONG')}\n")
        handle.write(f"  SHORT: {_priority_symbols(rows, 'SHORT')}\n")
        note = str(tier.get("note") or "").strip()
        if note:
            handle.write(f"  note: {note}\n")
    handle.write("\n")

def _write_priority_tier_details(handle, tiers: list[dict]) -> None:
    handle.write("Cream of the crop details\n")
    handle.write("=========================\n")
    for tier in tiers:
        _write_best_swing_trade_rows(
            handle,
            str(tier.get("title") or tier.get("label") or "Tier"),
            list(tier.get("rows") or []),
        )

def write_top_strength_watchlist_report(path: Path, rows: list[dict]) -> None:
    top_rows = _priority_top_strength_watchlist_rows(rows, limit=TOP_STRENGTH_WATCHLIST_LIMIT)
    buffer = io.StringIO()
    handle = buffer
    handle.write("Master AVWAP TOP strength watchlist\n")
    handle.write(f"Generated at {datetime.now().strftime('%Y-%m-%d %H:%M:%S')}\n\n")
    handle.write(
        "Long-only leader list. Use this as the TOP/strongest-stock stalking list; "
        "intraday entry preference is an H1 15EMA touch/reclaim confirmation, plus any D1 50SMA/AVWAPE entry already flagged by Master AVWAP.\n\n"
    )
    handle.write("Copy/paste TOP leaders\n")
    handle.write("======================\n")
    handle.write(f"LONG: {_priority_symbols(top_rows, 'LONG')}\n")
    handle.write("SHORT: None\n\n")
    handle.write("Entry plan\n")
    handle.write("==========\n")
    handle.write(
        "H1 15EMA long entry: prior H1 candle tags/touches H1 EMA15, then the next H1 candle closes back above EMA15. "
        "Prefer names that are also above VWAP and above the previous day's high.\n\n"
    )
    handle.write("TOP leaders\n")
    handle.write("===========\n")
    if not top_rows:
        handle.write("None\n")
    for rank, row in enumerate(top_rows, start=1):
        symbol = str(row.get("symbol") or "").strip().upper()
        status = "ENTRY" if row.get("top_pattern_entry") else "WATCH"
        entry_trigger = str(row.get("top_pattern_entry_trigger") or "").replace("_", " ") or "waiting for H1 15EMA / D1 50SMA / AVWAPE entry"
        return_26w = _coerce_float(row.get("top_pattern_weekly_return_26w_pct"))
        return_13w = _coerce_float(row.get("top_pattern_weekly_return_13w_pct"))
        rs_score = _coerce_float(row.get("daily_relative_strength_score"))
        return_text = []
        if return_26w is not None:
            return_text.append(f"26w={return_26w:+.1f}%")
        if return_13w is not None:
            return_text.append(f"13w={return_13w:+.1f}%")
        if rs_score is not None:
            return_text.append(f"D1vsSPY={rs_score:+.2f}")
        details = " | ".join(return_text) or "strength metrics n/a"
        note = str(row.get("top_pattern_note") or "").strip()
        handle.write(
            f"{rank:>2}. {symbol:<6} {status:<5} score={_priority_score_text(row):<5} "
            f"{details} | trigger={entry_trigger}\n"
        )
        if note:
            handle.write(f"    note: {note}\n")
    _write_text_atomic(path, buffer.getvalue().rstrip() + "\n")

def _market_prep_strength_score(row: dict) -> float | None:
    if not isinstance(row, dict):
        return None
    return _coerce_float(row.get("daily_relative_strength_score"))

def _market_prep_unique_strength_rows(priority_rows: list[dict] | None) -> list[dict]:
    best_by_symbol: dict[str, dict] = {}
    for row in priority_rows or []:
        if not isinstance(row, dict):
            continue
        symbol = str(row.get("symbol") or "").strip().upper()
        rs_score = _market_prep_strength_score(row)
        if not symbol or rs_score is None:
            continue
        existing = best_by_symbol.get(symbol)
        if existing is None:
            best_by_symbol[symbol] = row
            continue
        existing_score = _market_prep_strength_score(existing)
        if existing_score is None or abs(float(rs_score)) > abs(float(existing_score)):
            best_by_symbol[symbol] = row
    return list(best_by_symbol.values())

def _market_prep_strength_decile_rows(
    priority_rows: list[dict] | None,
    *,
    strongest: bool,
    fraction: float = MARKET_PREP_STRENGTH_DECILE_FRACTION,
) -> tuple[list[dict], int]:
    strength_rows = _market_prep_unique_strength_rows(priority_rows)
    if not strength_rows:
        return [], 0
    fraction = max(0.01, min(1.0, float(fraction or MARKET_PREP_STRENGTH_DECILE_FRACTION)))
    decile_count = max(1, int(math.ceil(len(strength_rows) * fraction)))
    ranked = sorted(
        strength_rows,
        key=lambda row: (
            -float(_market_prep_strength_score(row) or 0.0) if strongest else float(_market_prep_strength_score(row) or 0.0),
            str(row.get("symbol") or ""),
        ),
    )
    return ranked[:decile_count], len(strength_rows)

def _market_prep_pullback_rows(
    universe_rows: list[dict] | None,
    *,
    limit: int = MARKET_PREP_PULLBACK_MAX_ROWS,
) -> list[dict]:
    """Symbols that were strong over the longer term (26w, or 13w if 26w is
    unavailable) but are pulling back recently (5d return negative). Serves Aaron's
    stated buy preference: "stocks that were super strong 1-2 weeks ago then went on
    pullbacks." Ranked by longer-term strength, then by how deep the pullback is."""
    candidates: list[dict] = []
    for row in universe_rows or []:
        if not isinstance(row, dict):
            continue
        long_term = _coerce_float(row.get("return_26w_pct"))
        if long_term is None:
            long_term = _coerce_float(row.get("return_13w_pct"))
        recent = _coerce_float(row.get("symbol_five_day_return_pct"))
        if long_term is None or recent is None:
            continue
        if long_term > 0 and recent < 0:
            candidates.append(row)
    candidates.sort(
        key=lambda r: (
            -(_coerce_float(r.get("return_26w_pct")) if _coerce_float(r.get("return_26w_pct")) is not None
              else (_coerce_float(r.get("return_13w_pct")) or 0.0)),
            _coerce_float(r.get("symbol_five_day_return_pct")) or 0.0,
            str(r.get("symbol") or ""),
        )
    )
    return candidates[: max(0, int(limit))]


def _market_prep_pullback_details(rows: list[dict]) -> list[str]:
    details = []
    for row in rows or []:
        symbol = str(row.get("symbol") or "").strip().upper()
        ret_26w = _coerce_float(row.get("return_26w_pct"))
        ret_13w = _coerce_float(row.get("return_13w_pct"))
        five_day = _coerce_float(row.get("symbol_five_day_return_pct"))
        one_day = _coerce_float(row.get("symbol_one_day_return_pct"))
        ret_26w_text = "n/a" if ret_26w is None else f"{ret_26w:+.1f}%"
        ret_13w_text = "n/a" if ret_13w is None else f"{ret_13w:+.1f}%"
        five_day_text = "n/a" if five_day is None else f"{five_day:+.1f}%"
        one_day_text = "n/a" if one_day is None else f"{one_day:+.1f}%"
        details.append(
            f"{symbol:<6} 26w={ret_26w_text:<8} 13w={ret_13w_text:<8} "
            f"5d={five_day_text:<7} 1d={one_day_text}"
        )
    return details


def _market_prep_strength_details(rows: list[dict]) -> list[str]:
    details = []
    for row in rows or []:
        symbol = str(row.get("symbol") or "").strip().upper()
        side = normalize_side(row.get("side") or "")
        rs_score = _market_prep_strength_score(row)
        industry_etf = str(row.get("industry_etf") or "").strip().upper()
        rs_vs_industry = _coerce_float(row.get("rs_vs_industry"))
        one_day = _coerce_float(row.get("symbol_one_day_return_pct"))
        five_day = _coerce_float(row.get("symbol_five_day_return_pct"))
        score = _coerce_float(row.get("score"))
        family = _priority_setup_family_label(str(row.get("setup_family") or "general"))
        rs_text = "n/a" if rs_score is None else f"{float(rs_score):+.2f}"
        industry_text = ""
        if industry_etf or rs_vs_industry is not None:
            ind_rs_text = "n/a" if rs_vs_industry is None else f"{float(rs_vs_industry):+.2f}"
            industry_text = f" ind={industry_etf or 'n/a'} ind_rs={ind_rs_text:<7}"
        one_day_text = "n/a" if one_day is None else f"{float(one_day):+.1f}%"
        five_day_text = "n/a" if five_day is None else f"{float(five_day):+.1f}%"
        score_text = "n/a" if score is None else _priority_score_text(row)
        details.append(
            f"{symbol:<6} {side:<5} rs={rs_text:<7} 1d={one_day_text:<7} "
            f"5d={five_day_text:<7}{industry_text} score={score_text:<5} family={family}"
        )
    return details


def _market_prep_industry_strength_rows(
    industry_strength_rows: list[dict] | None,
    *,
    limit: int = MARKET_PREP_INDUSTRY_STRENGTH_MAX_ROWS,
) -> list[dict]:
    rows = [
        row for row in (industry_strength_rows or [])
        if isinstance(row, dict) and _market_prep_strength_score(row) is not None
    ]
    rows.sort(
        key=lambda row: (
            -float(_market_prep_strength_score(row) or 0.0),
            str(row.get("industry_etf") or row.get("symbol") or ""),
        )
    )
    return rows[: max(0, int(limit))]


def _market_prep_industry_strength_details(rows: list[dict]) -> list[str]:
    details = []
    for row in rows or []:
        etf = str(row.get("industry_etf") or row.get("symbol") or "").strip().upper()
        label = str(row.get("industry") or "").strip()
        rs_score = _market_prep_strength_score(row)
        one_day = _coerce_float(row.get("symbol_one_day_return_pct"))
        five_day = _coerce_float(row.get("symbol_five_day_return_pct"))
        ret_13w = _coerce_float(row.get("return_13w_pct"))
        constituents = [
            str(sym or "").strip().upper()
            for sym in (row.get("constituent_symbols") or [])
            if str(sym or "").strip()
        ]
        rs_text = "n/a" if rs_score is None else f"{float(rs_score):+.2f}"
        one_day_text = "n/a" if one_day is None else f"{float(one_day):+.1f}%"
        five_day_text = "n/a" if five_day is None else f"{float(five_day):+.1f}%"
        ret_13w_text = "n/a" if ret_13w is None else f"{float(ret_13w):+.1f}%"
        sample_text = ", ".join(constituents[:5])
        details.append(
            f"{etf:<6} rs={rs_text:<7} 1d={one_day_text:<7} 5d={five_day_text:<7} "
            f"13w={ret_13w_text:<8} {label or 'Industry ETF'}"
            + (f" | symbols={sample_text}" if sample_text else "")
        )
    return details


